  1Ôćĺ// sidecar/index.ts
  2Ôćĺ// Entry point for the OpenDevs agent-server process.
  3Ôćĺ//
  4Ôćĺ// Supports two transport modes (selected via --listen flag):
  5Ôćĺ//   --listen ws://    Ôćĺ WebSocket server on 127.0.0.1 (default, dynamic port)
  6Ôćĺ//   --listen unix://  Ôćĺ Unix domain socket (legacy, for backward compat)
  7Ôćĺ//
  8Ôćĺ// Both transports use JSON-RPC 2.0 over text frames/lines.
  9Ôćĺ
 10Ôćĺimport * as Sentry from "@sentry/node";
 11Ôćĺ
 12Ôćĺ// Initialize Sentry before anything else.
 13Ôćĺ// DSN passed as env var from Rust process manager (not hardcoded ÔÇö open source repo).
 14Ôćĺif (process.env.SENTRY_DSN) {
 15Ôćĺ  Sentry.init({
 16Ôćĺ    dsn: process.env.SENTRY_DSN,
 17Ôćĺ    environment: process.env.NODE_ENV === "production" ? "production" : "development",
 18Ôćĺ    sendDefaultPii: true,
 19Ôćĺ    initialScope: { tags: { process: "sidecar" } },
 20Ôćĺ  });
 21Ôćĺ}
 22Ôćĺ
 23Ôćĺimport * as net from "net";
 24Ôćĺimport * as fs from "fs";
 25Ôćĺimport * as path from "path";
 26Ôćĺimport * as os from "os";
 27Ôćĺimport * as util from "util";
 28Ôćĺimport { exec } from "child_process";
 29Ôćĺimport { StringDecoder } from "string_decoder";
 30Ôćĺimport { createServer as createHttpServer } from "http";
 31Ôćĺimport { WebSocketServer, WebSocket } from "ws";
 32Ôćĺ
 33Ôćĺimport { getErrorMessage } from "../shared/lib/errors";
 34Ôćĺimport { RpcConnection, wsTransport } from "./rpc-connection";
 35Ôćĺimport { EventBroadcaster } from "./event-broadcaster";
 36Ôćĺimport { classifyError } from "./agents/lifecycle";
 37Ôćĺimport { registerAgent, getAgent, initializeAllAgents } from "./agents/registry";
 38Ôćĺimport { ClaudeAgentHandler } from "./agents/claude/claude-handler";
 39Ôćĺimport { CodexAgentHandler } from "./agents/codex/codex-handler";
 40Ôćĺimport {
 41Ôćĺ  handleHttpRequest,
 42Ôćĺ  isShuttingDown,
 43Ôćĺ  setShuttingDown,
 44Ôćĺ  setAgentsInitialized,
 45Ôćĺ  trackSession,
 46Ôćĺ  untrackSession,
 47Ôćĺ  waitForDrain,
 48Ôćĺ  cancelRemainingSessions,
 49Ôćĺ} from "./health";
 50Ôćĺ
 51Ôćĺ// ============================================================================
 52Ôćĺ// Logging
 53Ôćĺ// ============================================================================
 54Ôćĺ
 55Ôćĺexport const logFilePath = `/tmp/opendevs-${process.pid}.log`;
 56Ôćĺconst originalLog = console.log;
 57Ôćĺ
 58Ôćĺconst LOG_LEVEL = (process.env.LOG_LEVEL || "info") as "debug" | "info" | "error";
 59Ôćĺconst LOG_LEVELS = { debug: 0, info: 1, error: 2 };
 60Ôćĺ
 61Ôćĺfunction shouldLog(level: "debug" | "info" | "error"): boolean {
 62Ôćĺ  return LOG_LEVELS[level] >= LOG_LEVELS[LOG_LEVEL];
 63Ôćĺ}
 64Ôćĺ
 65Ôćĺfunction formatLogArgs(args: any[]): string {
 66Ôćĺ  return args
 67Ôćĺ    .map((arg) => {
 68Ôćĺ      if (typeof arg === "string") return arg;
 69Ôćĺ      if (arg instanceof Error) return `${arg.message}\n${arg.stack || ""}`;
 70Ôćĺ      return util.inspect(arg, { depth: 4, breakLength: Infinity });
 71Ôćĺ    })
 72Ôćĺ    .join(" ");
 73Ôćĺ}
 74Ôćĺ
 75Ôćĺ// Buffered log writer -- avoids synchronous appendFileSync on every log call
 76Ôćĺlet logBuffer = "";
 77Ôćĺlet flushTimer: NodeJS.Timeout | null = null;
 78Ôćĺ
 79Ôćĺfunction flushLogs(): void {
 80Ôćĺ  if (logBuffer) {
 81Ôćĺ    fs.appendFileSync(logFilePath, logBuffer);
 82Ôćĺ    logBuffer = "";
 83Ôćĺ  }
 84Ôćĺ  flushTimer = null;
 85Ôćĺ}
 86Ôćĺ
 87Ôćĺfunction writeLog(line: string): void {
 88Ôćĺ  logBuffer += line;
 89Ôćĺ  if (!flushTimer) {
 90Ôćĺ    flushTimer = setTimeout(flushLogs, 100);
 91Ôćĺ  }
 92Ôćĺ  if (logBuffer.length > 8192) {
 93Ôćĺ    flushLogs();
 94Ôćĺ  }
 95Ôćĺ}
 96Ôćĺ
 97Ôćĺ// Ensure logs are flushed on shutdown
 98Ôćĺprocess.on("exit", flushLogs);
 99Ôćĺ
100Ôćĺconsole.log = (...args: any[]) => {
101Ôćĺ  if (!shouldLog("info")) return;
102Ôćĺ  const timestamp = new Date().toISOString();
103Ôćĺ  writeLog(`[${timestamp}] ${formatLogArgs(args)}\n`);
104Ôćĺ};
105Ôćĺ
106Ôćĺconsole.error = (...args: any[]) => {
107Ôćĺ  const timestamp = new Date().toISOString();
108Ôćĺ  writeLog(`[${timestamp}] ERROR: ${formatLogArgs(args)}\n`);
109Ôćĺ};
110Ôćĺ
111Ôćĺconsole.debug = (...args: any[]) => {
112Ôćĺ  if (!shouldLog("debug")) return;
113Ôćĺ  const timestamp = new Date().toISOString();
114Ôćĺ  writeLog(`[${timestamp}] DEBUG: ${formatLogArgs(args)}\n`);
115Ôćĺ};
116Ôćĺ
117Ôćĺ// ============================================================================
118Ôćĺ// CLI flag parsing
119Ôćĺ// ============================================================================
120Ôćĺ
121Ôćĺtype TransportMode = "ws" | "unix";
122Ôćĺ
123Ôćĺfunction parseTransportMode(): TransportMode {
124Ôćĺ  const listenIdx = process.argv.indexOf("--listen");
125Ôćĺ  if (listenIdx === -1) return "ws"; // Default: WebSocket
126Ôćĺ  const value = process.argv[listenIdx + 1] || "";
127Ôćĺ  if (value.startsWith("unix://")) return "unix";
128Ôćĺ  if (value.startsWith("ws://") || value === "") return "ws";
129Ôćĺ  // Unknown scheme ÔÇö default to ws
130Ôćĺ  console.error(`[CLI] Unknown --listen scheme "${value}", defaulting to ws://`);
131Ôćĺ  return "ws";
132Ôćĺ}
133Ôćĺ
134Ôćĺ// ============================================================================
135Ôćĺ// UnifiedSidecar
136Ôćĺ// ============================================================================
137Ôćĺ
138Ôćĺclass UnifiedSidecar {
139Ôćĺ  private transportMode: TransportMode;
140Ôćĺ  private initializedAgents = new Set<string>();
141Ôćĺ
142Ôćĺ  // Unix socket transport
143Ôćĺ  private socketPath: string;
144Ôćĺ  private unixServer: net.Server | null = null;
145Ôćĺ
146Ôćĺ  // WebSocket transport
147Ôćĺ  private httpServer: ReturnType<typeof createHttpServer> | null = null;
148Ôćĺ  private wss: WebSocketServer | null = null;
149Ôćĺ
150Ôćĺ  constructor(mode: TransportMode) {
151Ôćĺ    this.transportMode = mode;
152Ôćĺ    this.socketPath = path.join(os.tmpdir(), `opendevs-sidecar-${process.pid}.sock`);
153Ôćĺ
154Ôćĺ    console.log(`UnifiedSidecar: Initializing (transport=${mode})...`);
155Ôćĺ
156Ôćĺ    // Graceful shutdown handlers ÔÇö drain in-flight turns before exiting
157Ôćĺ    const gracefulShutdown = async (signal: string) => {
158Ôćĺ      console.log(`\n[SIGNAL] Received ${signal}, shutting down gracefully...`);
159Ôćĺ
160Ôćĺ      // 1. Stop accepting new turn/start requests
161Ôćĺ      setShuttingDown(true);
162Ôćĺ
163Ôćĺ      // 2. Stop accepting new WS connections (close the HTTP listener)
164Ôćĺ      if (this.httpServer) {
165Ôćĺ        this.httpServer.close();
166Ôćĺ        console.log("[SHUTDOWN] HTTP server closed to new connections");
167Ôćĺ      }
168Ôćĺ      if (this.unixServer) {
169Ôćĺ        this.unixServer.close();
170Ôćĺ        console.log("[SHUTDOWN] Unix server closed to new connections");
171Ôćĺ      }
172Ôćĺ
173Ôćĺ      // 3. Wait for in-flight turns to drain (default 30s timeout)
174Ôćĺ      console.log("[SHUTDOWN] Waiting for in-flight turns to drain...");
175Ôćĺ      const drained = await waitForDrain();
176Ôćĺ      if (drained) {
177Ôćĺ        console.log("[SHUTDOWN] All turns drained successfully");
178Ôćĺ      } else {
179Ôćĺ        console.log("[SHUTDOWN] Drain timeout reached, cancelling remaining sessions");
180Ôćĺ        await cancelRemainingSessions();
181Ôćĺ      }
182Ôćĺ
183Ôćĺ      // 4. Full cleanup (kill child processes, close WS clients)
184Ôćĺ      try {
185Ôćĺ        await this.cleanup();
186Ôćĺ        console.log("[SIGNAL] Cleanup complete, exiting process");
187Ôćĺ      } catch (error) {
188Ôćĺ        console.error("[SIGNAL] Cleanup failed:", error);
189Ôćĺ      } finally {
190Ôćĺ        process.exit(0);
191Ôćĺ      }
192Ôćĺ    };
193Ôćĺ    process.on("SIGINT", () => gracefulShutdown("SIGINT"));
194Ôćĺ    process.on("SIGTERM", () => gracefulShutdown("SIGTERM"));
195Ôćĺ  }
196Ôćĺ
197Ôćĺ  /**
198Ôćĺ   * Wires up all JSON-RPC methods and notifications on a new connection.
199Ôćĺ   * Transport-agnostic ÔÇö works with both Unix socket and WebSocket tunnels.
200Ôćĺ   */
201Ôćĺ  private setupJsonRpc(rpcTunnel: RpcConnection): void {
202Ôćĺ    EventBroadcaster.attachTunnel(rpcTunnel);
203Ôćĺ
204Ôćĺ    // --- Initialize handshake (backend agent-client sends this) ---
205Ôćĺ    rpcTunnel.addMethod("initialize", () => {
206Ôćĺ      const agents = [];
207Ôćĺ      for (const [agentType, handler] of [
208Ôćĺ        ["claude", getAgent("claude")],
209Ôćĺ        ["codex", getAgent("codex")],
210Ôćĺ      ] as const) {
211Ôćĺ        if (handler && this.initializedAgents.has(agentType)) {
212Ôćĺ          agents.push({
213Ôćĺ            type: agentType,
214Ôćĺ            capabilities: handler.capabilities,
215Ôćĺ            initialized: true,
216Ôćĺ          });
217Ôćĺ        }
218Ôćĺ      }
219Ôćĺ      return { version: "1.0", agents };
220Ôćĺ    });
221Ôćĺ
222Ôćĺ    // --- Initialized notification (backend confirms handshake) ---
223Ôćĺ    rpcTunnel.addMethod("initialized", () => {
224Ôćĺ      console.log("[RPC] Backend handshake complete (initialized)");
225Ôćĺ      return undefined;
226Ôćĺ    });
227Ôćĺ
228Ôćĺ    // --- turn/start (new wire protocol method, maps to query dispatch) ---
229Ôćĺ    rpcTunnel.addMethod("turn/start", async (params: any) => {
230Ôćĺ      const sessionId = params?.sessionId;
231Ôćĺ      const agentType = params?.agentType || "claude";
232Ôćĺ      const prompt = params?.prompt;
233Ôćĺ      const options = params?.options || {};
234Ôćĺ
235Ôćĺ      // Reject new turns during shutdown
236Ôćĺ      if (isShuttingDown()) {
237Ôćĺ        return { accepted: false, reason: "shutting down" };
238Ôćĺ      }
239Ôćĺ
240Ôćĺ      if (!sessionId || !prompt) {
241Ôćĺ        return { accepted: false, reason: "turn/start requires sessionId and prompt" };
242Ôćĺ      }
243Ôćĺ
244Ôćĺ      const agent = getAgent(agentType);
245Ôćĺ      if (!agent) {
246Ôćĺ        return { accepted: false, reason: `No agent registered for type: ${agentType}` };
247Ôćĺ      }
248Ôćĺ
249Ôćĺ      // Track this session for graceful shutdown draining
250Ôćĺ      trackSession(sessionId, agentType);
251Ôćĺ
252Ôćĺ      agent
253Ôćĺ        .query(sessionId, prompt, options)
254Ôćĺ        .catch((err) => {
255Ôćĺ          console.error(`[turn/start] Unhandled error in ${agentType} query:`, err);
256Ôćĺ          const classified = classifyError(err);
257Ôćĺ          EventBroadcaster.sendError({
258Ôćĺ            id: sessionId,
259Ôćĺ            type: "error",
260Ôćĺ            error: classified.message,
261Ôćĺ            agentType,
262Ôćĺ            category: classified.category,
263Ôćĺ          });
264Ôćĺ          EventBroadcaster.emitSessionError(
265Ôćĺ            sessionId,
266Ôćĺ            agentType,
267Ôćĺ            classified.message,
268Ôćĺ            classified.category
269Ôćĺ          );
270Ôćĺ        })
271Ôćĺ        .finally(() => {
272Ôćĺ          // Untrack when the turn completes (success, error, or cancel)
273Ôćĺ          untrackSession(sessionId);
274Ôćĺ        });
275Ôćĺ
276Ôćĺ      EventBroadcaster.emitSessionStarted(sessionId, agentType);
277Ôćĺ
278Ôćĺ      console.log(`[TIMING][turn/start] DISPATCHED session=${sessionId}`);
279Ôćĺ      return { accepted: true };
280Ôćĺ    });
281Ôćĺ
282Ôćĺ    // --- turn/cancel (new wire protocol method, maps to cancel dispatch) ---
283Ôćĺ    rpcTunnel.addMethod("turn/cancel", async (params: any) => {
284Ôćĺ      const sessionId = params?.sessionId;
285Ôćĺ      if (!sessionId) return;
286Ôćĺ
287Ôćĺ      // Try all registered agents ÔÇö the backend may not send agentType for cancel
288Ôćĺ      for (const agentType of ["claude", "codex"] as const) {
289Ôćĺ        const agent = getAgent(agentType);
290Ôćĺ        if (agent) void agent.cancel(sessionId);
291Ôćĺ      }
292Ôćĺ    });
293Ôćĺ
294Ôćĺ    // --- session/reset (new wire protocol method) ---
295Ôćĺ    rpcTunnel.addMethod("session/reset", (params: any) => {
296Ôćĺ      const sessionId = params?.sessionId;
297Ôćĺ      if (!sessionId) return;
298Ôćĺ
299Ôćĺ      for (const agentType of ["claude", "codex"] as const) {
300Ôćĺ        const agent = getAgent(agentType);
301Ôćĺ        if (agent) agent.reset(sessionId);
302Ôćĺ      }
303Ôćĺ    });
304Ôćĺ
305Ôćĺ    // --- Query (dispatch to agent by agentType) ---
306Ôćĺ    // Returns synchronous ACK/reject before async streaming begins.
307Ôćĺ    // query() is NOT awaited ÔÇö the ACK returns immediately after validation.
308Ôćĺ    EventBroadcaster.onQuery(rpcTunnel, async (request) => {
309Ôćĺ      // Reject new queries during shutdown
310Ôćĺ      if (isShuttingDown()) {
311Ôćĺ        return { accepted: false, reason: "shutting down" };
312Ôćĺ      }
313Ôćĺ
314Ôćĺ      const tQueryReceived = Date.now();
315Ôćĺ      console.log(
316Ôćĺ        `[TIMING][QUERY] RECEIVED session=${request.id} agent=${request.agentType} promptLength=${request.prompt?.length ?? 0}`
317Ôćĺ      );
318Ôćĺ      const agent = getAgent(request.agentType);
319Ôćĺ      if (!agent) {
320Ôćĺ        return { accepted: false, reason: `No agent registered for type: ${request.agentType}` };
321Ôćĺ      }
322Ôćĺ
323Ôćĺ      // Track this session for graceful shutdown draining
324Ôćĺ      trackSession(request.id, request.agentType);
325Ôćĺ
326Ôćĺ      // The backend saves the user message BEFORE forwarding turn/start to the
327Ôćĺ      // agent-server. The agent-server just receives the query and starts the SDK.
328Ôćĺ      agent
329Ôćĺ        .query(request.id, request.prompt, request.options)
330Ôćĺ        .catch((err) => {
331Ôćĺ          console.error(`[QUERY] Unhandled error in ${request.agentType} query:`, err);
332Ôćĺ          // Recover: notify frontend of the error. The backend handles DB status updates
333Ôćĺ          // via canonical events (session.error).
334Ôćĺ          const classified = classifyError(err);
335Ôćĺ          EventBroadcaster.sendError({
336Ôćĺ            id: request.id,
337Ôćĺ            type: "error",
338Ôćĺ            error: classified.message,
339Ôćĺ            agentType: request.agentType,
340Ôćĺ            category: classified.category,
341Ôćĺ          });
342Ôćĺ          EventBroadcaster.emitSessionError(
343Ôćĺ            request.id,
344Ôćĺ            request.agentType,
345Ôćĺ            classified.message,
346Ôćĺ            classified.category
347Ôćĺ          );
348Ôćĺ        })
349Ôćĺ        .finally(() => {
350Ôćĺ          // Untrack when the turn completes (success, error, or cancel)
351Ôćĺ          untrackSession(request.id);
352Ôćĺ        });
353Ôćĺ
354Ôćĺ      // Dual-write: emit canonical session.started event after dispatch
355Ôćĺ      EventBroadcaster.emitSessionStarted(request.id, request.agentType);
356Ôćĺ
357Ôćĺ      console.log(
358Ôćĺ        `[TIMING][QUERY] DISPATCHED session=${request.id} dispatchTime=${Date.now() - tQueryReceived}ms`
359Ôćĺ      );
360Ôćĺ      return { accepted: true };
361Ôćĺ    });
362Ôćĺ
363Ôćĺ    // --- Cancel (dispatch to agent by agentType) ---
364Ôćĺ    EventBroadcaster.onCancel(rpcTunnel, (request) => {
365Ôćĺ      const agent = getAgent(request.agentType);
366Ôćĺ      if (agent) void agent.cancel(request.id);
367Ôćĺ    });
368Ôćĺ
369Ôćĺ    // --- Auth check (dispatched by agentType) ---
370Ôćĺ    EventBroadcaster.onClaudeAuth(rpcTunnel, (request) => {
371Ôćĺ      const agent = getAgent(request.agentType);
372Ôćĺ      if (!agent?.auth) {
373Ôćĺ        return Promise.reject(new Error(`Agent "${request.agentType}" does not support auth`));
374Ôćĺ      }
375Ôćĺ      return agent.auth({ id: request.id, cwd: request.options.cwd });
376Ôćĺ    });
377Ôćĺ
378Ôćĺ    // --- Workspace init (dispatched by agentType) ---
379Ôćĺ    EventBroadcaster.onWorkspaceInit(rpcTunnel, (request) => {
380Ôćĺ      const agent = getAgent(request.agentType);
381Ôćĺ      if (!agent?.initWorkspace) {
382Ôćĺ        return Promise.reject(
383Ôćĺ          new Error(`Agent "${request.agentType}" does not support workspace init`)
384Ôćĺ        );
385Ôćĺ      }
386Ôćĺ      return agent.initWorkspace({
387Ôćĺ        id: request.id,
388Ôćĺ        cwd: request.options.cwd,
389Ôćĺ        ghToken: request.options.ghToken,
390Ôćĺ        claudeEnvVars: request.options.claudeEnvVars,
391Ôćĺ      });
392Ôćĺ    });
393Ôćĺ
394Ôćĺ    // --- Context usage (dispatched by agentType) ---
395Ôćĺ    EventBroadcaster.onContextUsage(rpcTunnel, (request) => {
396Ôćĺ      const agent = getAgent(request.agentType);
397Ôćĺ      if (!agent?.getContextUsage) {
398Ôćĺ        return Promise.reject(
399Ôćĺ          new Error(`Agent "${request.agentType}" does not support context usage`)
400Ôćĺ        );
401Ôćĺ      }
402Ôćĺ      return agent.getContextUsage(request);
403Ôćĺ    });
404Ôćĺ
405Ôćĺ    // --- Permission mode updates (dispatched by agentType) ---
406Ôćĺ    // Fire-and-forget notification ÔÇö no error if the agent doesn't support it
407Ôćĺ    EventBroadcaster.onUpdatePermissionMode(rpcTunnel, (request) => {
408Ôćĺ      const agent = getAgent(request.agentType);
409Ôćĺ      if (agent?.updatePermissionMode) {
410Ôćĺ        void agent.updatePermissionMode(request.id, request.permissionMode);
411Ôćĺ      }
412Ôćĺ    });
413Ôćĺ
414Ôćĺ    // --- Reset generator (dispatch to agent by agentType) ---
415Ôćĺ    EventBroadcaster.onResetGenerator(rpcTunnel, (request) => {
416Ôćĺ      const agent = getAgent(request.agentType);
417Ôćĺ      if (agent) agent.reset(request.id);
418Ôćĺ    });
419Ôćĺ  }
420Ôćĺ
421Ôćĺ  // ==========================================================================
422Ôćĺ  // Unix socket transport
423Ôćĺ  // ==========================================================================
424Ôćĺ
425Ôćĺ  /**
426Ôćĺ   * Handles a new TCP/Unix socket connection.
427Ôćĺ   * Sets up line-based JSON-RPC message framing.
428Ôćĺ   */
429Ôćĺ  private handleUnixConnection(socket: net.Socket): void {
430Ôćĺ    console.log("Client connected (unix)");
431Ôćĺ    const rpcTunnel = new RpcConnection(socket);
432Ôćĺ    this.setupJsonRpc(rpcTunnel);
433Ôćĺ
434Ôćĺ    let buffer = "";
435Ôćĺ    const decoder = new StringDecoder("utf8");
436Ôćĺ
437Ôćĺ    socket.on("data", (data) => {
438Ôćĺ      buffer += decoder.write(data);
439Ôćĺ      console.debug("Received data with length", data.length);
440Ôćĺ
441Ôćĺ      const lines = buffer.split("\n");
442Ôćĺ      buffer = lines.pop() || "";
443Ôćĺ
444Ôćĺ      for (const line of lines) {
445Ôćĺ        if (line.trim()) {
446Ôćĺ          rpcTunnel.handleLine(line);
447Ôćĺ        }
448Ôćĺ      }
449Ôćĺ    });
450Ôćĺ
451Ôćĺ    socket.on("error", (error: any) => {
452Ôćĺ      console.error("Socket error:", error);
453Ôćĺ    });
454Ôćĺ
455Ôćĺ    socket.on("close", (hadError) => {
456Ôćĺ      console.log(`Client disconnected (unix), hadError: ${hadError}`);
457Ôćĺ      rpcTunnel.stop();
458Ôćĺ      EventBroadcaster.detachTunnel(rpcTunnel);
459Ôćĺ    });
460Ôćĺ  }
461Ôćĺ
462Ôćĺ  // ==========================================================================
463Ôćĺ  // WebSocket transport
464Ôćĺ  // ==========================================================================
465Ôćĺ
466Ôćĺ  /**
467Ôćĺ   * Handles a new WebSocket connection.
468Ôćĺ   * Each WS text frame is a complete JSON-RPC message (no line splitting needed).
469Ôćĺ   */
470Ôćĺ  private handleWsConnection(ws: WebSocket): void {
471Ôćĺ    console.log("Client connected (ws)");
472Ôćĺ    const transport = wsTransport(ws);
473Ôćĺ    const rpcTunnel = new RpcConnection(transport);
474Ôćĺ    this.setupJsonRpc(rpcTunnel);
475Ôćĺ
476Ôćĺ    ws.on("message", (data: Buffer | string) => {
477Ôćĺ      const message = typeof data === "string" ? data : data.toString("utf8");
478Ôćĺ      console.debug("Received WS message with length", message.length);
479Ôćĺ      rpcTunnel.handleMessage(message);
480Ôćĺ    });
481Ôćĺ
482Ôćĺ    ws.on("error", (error: Error) => {
483Ôćĺ      console.error("WebSocket error:", error);
484Ôćĺ    });
485Ôćĺ
486Ôćĺ    ws.on("close", (code: number, reason: Buffer) => {
487Ôćĺ      console.log(`Client disconnected (ws), code=${code} reason=${reason.toString()}`);
488Ôćĺ      rpcTunnel.stop();
489Ôćĺ      EventBroadcaster.detachTunnel(rpcTunnel);
490Ôćĺ    });
491Ôćĺ  }
492Ôćĺ
493Ôćĺ  // ==========================================================================
494Ôćĺ  // Lifecycle
495Ôćĺ  // ==========================================================================
496Ôćĺ
497Ôćĺ  /**
498Ôćĺ   * Kills any remaining Claude child processes spawned by this sidecar.
499Ôćĺ   */
500Ôćĺ  private async killRemainingChildProcesses(): Promise<void> {
501Ôćĺ    return new Promise((resolve) => {
502Ôćĺ      const command = `/usr/bin/pgrep -P ${process.pid}`;
503Ôćĺ      exec(command, (error, stdout) => {
504Ôćĺ        if (error) {
505Ôćĺ          console.log("[CLEANUP] No child processes found");
506Ôćĺ          resolve();
507Ôćĺ          return;
508Ôćĺ        }
509Ôćĺ        const childPids = stdout
510Ôćĺ          .trim()
511Ôćĺ          .split("\n")
512Ôćĺ          .filter((pid) => pid);
513Ôćĺ        if (childPids.length === 0) {
514Ôćĺ          console.log("[CLEANUP] No child processes to kill");
515Ôćĺ          resolve();
516Ôćĺ          return;
517Ôćĺ        }
518Ôćĺ        console.log(`[CLEANUP] Found ${childPids.length} child processes: ${childPids.join(", ")}`);
519Ôćĺ        childPids.forEach((pid) => {
520Ôćĺ          try {
521Ôćĺ            process.kill(Number(pid), "SIGTERM");
522Ôćĺ            console.log(`[CLEANUP] Sent SIGTERM to child PID ${pid}`);
523Ôćĺ          } catch (e) {
524Ôćĺ            const errorMsg = getErrorMessage(e);
525Ôćĺ            console.log(`[CLEANUP] Failed to kill child PID ${pid}: ${errorMsg}`);
526Ôćĺ          }
527Ôćĺ        });
528Ôćĺ        resolve();
529Ôćĺ      });
530Ôćĺ    });
531Ôćĺ  }
532Ôćĺ
533Ôćĺ  private async cleanup(): Promise<void> {
534Ôćĺ    await this.killRemainingChildProcesses();
535Ôćĺ
536Ôćĺ    // Clean up Unix socket
537Ôćĺ    if (fs.existsSync(this.socketPath)) {
538Ôćĺ      fs.unlinkSync(this.socketPath);
539Ôćĺ      console.log("[CLEANUP] Removed socket file");
540Ôćĺ    }
541Ôćĺ    if (this.unixServer) {
542Ôćĺ      this.unixServer.close();
543Ôćĺ    }
544Ôćĺ
545Ôćĺ    // Clean up WebSocket server
546Ôćĺ    if (this.wss) {
547Ôćĺ      // Close all connected clients
548Ôćĺ      for (const client of this.wss.clients) {
549Ôćĺ        client.close(1001, "Server shutting down");
550Ôćĺ      }
551Ôćĺ      this.wss.close();
552Ôćĺ    }
553Ôćĺ    if (this.httpServer) {
554Ôćĺ      this.httpServer.close();
555Ôćĺ    }
556Ôćĺ  }
557Ôćĺ
558Ôćĺ  /**
559Ôćĺ   * Starts the agent-server:
560Ôćĺ   * 1. Clean up stale resources
561Ôćĺ   * 2. Initialize agent handlers
562Ôćĺ   * 3. Listen on the selected transport
563Ôćĺ   * 4. Print connection info to stdout (consumed by the Rust process manager)
564Ôćĺ   */
565Ôćĺ  async start(): Promise<void> {
566Ôćĺ    await this.cleanup();
567Ôćĺ
568Ôćĺ    // Register all agent handlers
569Ôćĺ    registerAgent(new ClaudeAgentHandler());
570Ôćĺ    registerAgent(new CodexAgentHandler());
571Ôćĺ
572Ôćĺ    // Initialize all registered agents
573Ôćĺ    console.log("Initializing agent handlers...");
574Ôćĺ    this.initializedAgents.clear();
575Ôćĺ    const initResults = initializeAllAgents();
576Ôćĺ    for (const [agentType, result] of initResults) {
577Ôćĺ      if (!result.success) {
578Ôćĺ        console.error(`${agentType} initialization failed:`, result.error);
579Ôćĺ      } else {
580Ôćĺ        console.log(`${agentType} handler initialized successfully`);
581Ôćĺ        this.initializedAgents.add(agentType);
582Ôćĺ      }
583Ôćĺ    }
584Ôćĺ
585Ôćĺ    // Mark agents as initialized for the /readyz endpoint only if at least one succeeded
586Ôćĺ    setAgentsInitialized(this.initializedAgents.size > 0);
587Ôćĺ
588Ôćĺ    if (this.transportMode === "ws") {
589Ôćĺ      return this.startWebSocket();
590Ôćĺ    } else {
591Ôćĺ      return this.startUnixSocket();
592Ôćĺ    }
593Ôćĺ  }
594Ôćĺ
595Ôćĺ  private startWebSocket(): Promise<void> {
596Ôćĺ    return new Promise((resolve, reject) => {
597Ôćĺ      // Create an HTTP server for health endpoints + WS upgrade.
598Ôćĺ      // Binding to 127.0.0.1 ÔÇö agent-server only accepts local connections.
599Ôćĺ      this.httpServer = createHttpServer((req, res) => {
600Ôćĺ        handleHttpRequest(req, res, this.wss);
601Ôćĺ      });
602Ôćĺ
603Ôćĺ      this.wss = new WebSocketServer({ server: this.httpServer });
604Ôćĺ
605Ôćĺ      this.wss.on("connection", (ws) => {
606Ôćĺ        console.log("Server: New WebSocket connection accepted");
607Ôćĺ        this.handleWsConnection(ws);
608Ôćĺ      });
609Ôćĺ
610Ôćĺ      this.wss.on("error", (error: Error) => {
611Ôćĺ        console.error("WebSocketServer error:", error);
612Ôćĺ      });
613Ôćĺ
614Ôćĺ      // Port 0 = OS-assigned dynamic port
615Ôćĺ      this.httpServer.listen(0, "127.0.0.1", () => {
616Ôćĺ        const addr = this.httpServer!.address();
617Ôćĺ        const port = typeof addr === "object" && addr ? addr.port : 0;
618Ôćĺ
619Ôćĺ        console.log(`Agent-server listening on ws://127.0.0.1:${port}`);
620Ôćĺ        console.log(`Sidecar PID: ${process.pid}`);
621Ôćĺ
622Ôćĺ        // Machine-readable output for the Rust process manager.
623Ôćĺ        // LISTEN_URL is the new canonical output; SOCKET_PATH kept for transition.
624Ôćĺ        originalLog(`LISTEN_URL=ws://127.0.0.1:${port}`);
625Ôćĺ        resolve();
626Ôćĺ      });
627Ôćĺ
628Ôćĺ      this.httpServer.on("error", (error: Error) => {
629Ôćĺ        console.error("HTTP server error:", error);
630Ôćĺ        reject(error);
631Ôćĺ      });
632Ôćĺ    });
633Ôćĺ  }
634Ôćĺ
635Ôćĺ  private startUnixSocket(): Promise<void> {
636Ôćĺ    return new Promise((resolve, reject) => {
637Ôćĺ      this.unixServer = net.createServer((socket) => {
638Ôćĺ        console.log("Server: New connection accepted");
639Ôćĺ        this.handleUnixConnection(socket);
