  1Ôćĺ// sidecar/rpc-connection.ts
  2Ôćĺ// Bidirectional JSON-RPC 2.0 connection over a pluggable transport.
  3Ôćĺ//
  4Ôćĺ// Supports two transports:
  5Ôćĺ// - TCP/Unix socket (net.Socket): newline-delimited JSON lines (NDJSON)
  6Ôćĺ// - WebSocket (ws): each JSON-RPC message is a single WS text frame
  7Ôćĺ//
  8Ôćĺ// The caller is responsible for message framing:
  9Ôćĺ// - For net.Socket: split on newlines, call handleLine() per line
 10Ôćĺ// - For WebSocket: call handleMessage() per WS "message" event
 11Ôćĺ
 12Ôćĺimport {
 13Ôćĺ  JSONRPCServer,
 14Ôćĺ  JSONRPCClient,
 15Ôćĺ  JSONRPCServerAndClient,
 16Ôćĺ  isJSONRPCRequest,
 17Ôćĺ  isJSONRPCRequests,
 18Ôćĺ  isJSONRPCResponse,
 19Ôćĺ  isJSONRPCResponses,
 20Ôćĺ} from "json-rpc-2.0";
 21Ôćĺimport type { Socket } from "net";
 22Ôćĺimport type { WebSocket } from "ws";
 23Ôćĺ
 24Ôćĺ// ============================================================================
 25Ôćĺ// Transport abstraction
 26Ôćĺ// ============================================================================
 27Ôćĺ
 28Ôćĺ/**
 29Ôćĺ * Minimal interface for sending data over a connection.
 30Ôćĺ * Implemented by both net.Socket and ws.WebSocket adapters.
 31Ôćĺ */
 32Ôćĺexport interface RpcTransport {
 33Ôćĺ  /** Send a string payload. For sockets, appends \n. For WS, sends as text frame. */
 34Ôćĺ  send(data: string): void;
 35Ôćĺ  /** Returns true if the underlying connection is no longer usable. */
 36Ôćĺ  isClosed(): boolean;
 37Ôćĺ}
 38Ôćĺ
 39Ôćĺ/** Wraps a net.Socket as an RpcTransport (newline-delimited JSON). */
 40Ôćĺexport function socketTransport(socket: Socket): RpcTransport {
 41Ôćĺ  return {
 42Ôćĺ    send(data: string) {
 43Ôćĺ      socket.write(data + "\n");
 44Ôćĺ    },
 45Ôćĺ    isClosed() {
 46Ôćĺ      return socket.destroyed;
 47Ôćĺ    },
 48Ôćĺ  };
 49Ôćĺ}
 50Ôćĺ
 51Ôćĺ/** Wraps a ws.WebSocket as an RpcTransport (text frames). */
 52Ôćĺexport function wsTransport(ws: WebSocket): RpcTransport {
 53Ôćĺ  return {
 54Ôćĺ    send(data: string) {
 55Ôćĺ      ws.send(data);
 56Ôćĺ    },
 57Ôćĺ    isClosed() {
 58Ôćĺ      // ws.readyState: 0=CONNECTING, 1=OPEN, 2=CLOSING, 3=CLOSED
 59Ôćĺ      return ws.readyState !== 1;
 60Ôćĺ    },
 61Ôćĺ  };
 62Ôćĺ}
 63Ôćĺ
 64Ôćĺ// ============================================================================
 65Ôćĺ// JSON parsing / validation helpers
 66Ôćĺ// ============================================================================
 67Ôćĺ
 68Ôćĺfunction safeJsonParse(text: string): unknown | undefined {
 69Ôćĺ  try {
 70Ôćĺ    return JSON.parse(text);
 71Ôćĺ  } catch {
 72Ôćĺ    return undefined;
 73Ôćĺ  }
 74Ôćĺ}
 75Ôćĺ
 76Ôćĺfunction isJsonRpcPayload(payload: unknown): boolean {
 77Ôćĺ  return (
 78Ôćĺ    isJSONRPCRequest(payload) ||
 79Ôćĺ    isJSONRPCRequests(payload) ||
 80Ôćĺ    isJSONRPCResponse(payload) ||
 81Ôćĺ    isJSONRPCResponses(payload)
 82Ôćĺ  );
 83Ôćĺ}
 84Ôćĺ
 85Ôćĺ// ============================================================================
 86Ôćĺ// RpcConnection
 87Ôćĺ// ============================================================================
 88Ôćĺ
 89Ôćĺexport class RpcConnection {
 90Ôćĺ  private transport: RpcTransport;
 91Ôćĺ  private peer: JSONRPCServerAndClient;
 92Ôćĺ
 93Ôćĺ  /**
 94Ôćĺ   * Create an RPC connection over any transport.
 95Ôćĺ   *
 96Ôćĺ   * Accepts either:
 97Ôćĺ   * - A net.Socket (legacy Unix socket path) ÔÇö auto-wrapped in socketTransport
 98Ôćĺ   * - An RpcTransport (WebSocket or custom) ÔÇö used directly
 99Ôćĺ   */
100Ôćĺ  constructor(transportOrSocket: RpcTransport | Socket) {
101Ôćĺ    // Duck-type: if it has send() and isClosed(), treat as RpcTransport.
102Ôćĺ    // Otherwise, wrap as a net.Socket via socketTransport().
103Ôćĺ    this.transport = isRpcTransport(transportOrSocket)
104Ôćĺ      ? transportOrSocket
105Ôćĺ      : socketTransport(transportOrSocket as Socket);
106Ôćĺ
107Ôćĺ    const server = new JSONRPCServer({
108Ôćĺ      errorListener: (message, data) => {
109Ôćĺ        console.error("[RpcConnection] Server error:", message, data);
110Ôćĺ      },
111Ôćĺ    });
112Ôćĺ
113Ôćĺ    const client = new JSONRPCClient((payload) => {
114Ôćĺ      if (this.transport.isClosed()) {
115Ôćĺ        return Promise.reject(new Error("Transport is closed"));
116Ôćĺ      }
117Ôćĺ      try {
118Ôćĺ        this.transport.send(JSON.stringify(payload));
119Ôćĺ        return Promise.resolve();
120Ôćĺ      } catch (error) {
121Ôćĺ        const err = error instanceof Error ? error : new Error(String(error));
122Ôćĺ        return Promise.reject(err);
123Ôćĺ      }
124Ôćĺ    });
125Ôćĺ
126Ôćĺ    this.peer = new JSONRPCServerAndClient(server, client, {
127Ôćĺ      errorListener: (message, data) => {
128Ôćĺ        console.error("[RpcConnection] Client error:", message, data);
129Ôćĺ      },
130Ôćĺ    });
131Ôćĺ  }
132Ôćĺ
133Ôćĺ  /** Register a method handler that the remote side can call */
134Ôćĺ  addMethod(name: string, method: (params: unknown) => Promise<unknown>): void {
135Ôćĺ    this.peer.addMethod(name, (params) => method(params));
136Ôćĺ  }
137Ôćĺ
138Ôćĺ  /** Send a one-way notification to the remote side */
139Ôćĺ  notify(method: string, params: unknown): void {
140Ôćĺ    this.peer.notify(method, params, undefined);
141Ôćĺ  }
142Ôćĺ
143Ôćĺ  /** Send a request to the remote side and wait for a response */
144Ôćĺ  request(method: string, params: unknown): Promise<unknown> {
145Ôćĺ    return Promise.resolve(this.peer.request(method, params, undefined));
146Ôćĺ  }
147Ôćĺ
148Ôćĺ  /**
149Ôćĺ   * Process a single line/message received from the transport.
150Ôćĺ   * Works for both NDJSON lines (net.Socket) and WS text frames.
151Ôćĺ   * Returns true if the line was a valid JSON-RPC payload.
152Ôćĺ   */
153Ôćĺ  handleLine(line: string): boolean {
154Ôćĺ    const t0 = Date.now();
155Ôćĺ    const payload = safeJsonParse(line);
156Ôćĺ    if (payload === undefined) {
157Ôćĺ      console.error("[RpcConnection] Failed to parse JSON:", line);
158Ôćĺ      return false;
159Ôćĺ    }
160Ôćĺ    if (!isJsonRpcPayload(payload)) {
161Ôćĺ      console.error("[RpcConnection] Received non-JSON-RPC payload:", payload);
162Ôćĺ      return false;
163Ôćĺ    }
164Ôćĺ
165Ôćĺ    const method = (payload as any)?.method;
166Ôćĺ    if (method) {
167Ôćĺ      console.log(
168Ôćĺ        `[TIMING][RpcConnection] handleLine method=${method} parseTime=${Date.now() - t0}ms lineLen=${line.length}`
169Ôćĺ      );
170Ôćĺ    }
171Ôćĺ
172Ôćĺ    void this.peer.receiveAndSend(payload, undefined, undefined).catch((e) => {
173Ôćĺ      console.error("[RpcConnection] Failed to handle message:", e);
174Ôćĺ    });
175Ôćĺ    return true;
176Ôćĺ  }
177Ôćĺ
178Ôćĺ  /** Alias for handleLine ÔÇö clearer name when used with WebSocket messages. */
179Ôćĺ  handleMessage(message: string): boolean {
180Ôćĺ    return this.handleLine(message);
181Ôćĺ  }
182Ôćĺ
183Ôćĺ  /** Reject all pending outbound requests and tear down the connection */
184Ôćĺ  stop(): void {
185Ôćĺ    this.peer.rejectAllPendingRequests("RPC connection stopped");
186Ôćĺ  }
187Ôćĺ}
188Ôćĺ
189Ôćĺ// ============================================================================
190Ôćĺ// Type guard
191Ôćĺ// ============================================================================
192Ôćĺ
193Ôćĺ/**
194Ôćĺ * Duck-type check: RpcTransport has `send` (function) and `isClosed` (function).
195Ôćĺ * Anything that doesn't match is treated as a net.Socket (which has `write`).
196Ôćĺ */
197Ôćĺfunction isRpcTransport(obj: unknown): obj is RpcTransport {
198Ôćĺ  return (
199Ôćĺ    typeof obj === "object" &&
200Ôćĺ    obj !== null &&
201Ôćĺ    typeof (obj as any).send === "function" &&
202Ôćĺ    typeof (obj as any).isClosed === "function"
203Ôćĺ  );
204Ôćĺ}
205Ôćĺ

