111Ôćĺ/** Timeout for browser navigate ÔÇö allows extra time for auto-creating a tab,
112Ôćĺ *  waiting for the webview to initialize, loading the page, and taking a snapshot. */
113Ôćĺconst BROWSER_NAVIGATE_TIMEOUT_MS = 30_000;
114Ôćĺ
115Ôćĺ/** Timeout for browser navigate-back ÔÇö page load (15s) + snapshot (12s) + buffer. */
116Ôćĺconst BROWSER_NAVIGATE_BACK_TIMEOUT_MS = 30_000;
117Ôćĺ
118Ôćĺ/** Timeout for BrowserWaitFor ÔÇö polls for up to 30s inside the webview,
119Ôćĺ *  plus 5s buffer for eval overhead and title-channel round-trip. */
120Ôćĺconst BROWSER_WAIT_FOR_TIMEOUT_MS = 35_000;
121Ôćĺ
122Ôćĺ/** Timeout for BrowserEvaluate ÔÇö user code can run expensive operations,
123Ôćĺ *  frontend allows 15s for eval, plus IPC overhead. */
124Ôćĺconst BROWSER_EVALUATE_TIMEOUT_MS = 20_000;
125Ôćĺ
126Ôćĺ/** Timeout for BrowserScreenshot ÔÇö native WKWebView.takeSnapshot() has a
127Ôćĺ *  10s internal timeout, plus 5s buffer for IPC and base64 encoding. */
128Ôćĺconst BROWSER_SCREENSHOT_TIMEOUT_MS = 15_000;
129Ôćĺ
130Ôćĺ/** Timeout for browser interactions (click, type, hover, etc.) that include
131Ôćĺ *  visual effects + eval. Visual cursor animation up to 3s + eval up to 8s. */
132Ôćĺconst BROWSER_INTERACTION_TIMEOUT_MS = 15_000;
133Ôćĺ
134Ôćĺ/** Timeout for simulator screenshot ÔÇö Rust ObjC bridge capture + JPEG
135Ôćĺ *  encoding + base64 transfer. Typically <2s but allow headroom. */
136Ôćĺconst SIMULATOR_SCREENSHOT_TIMEOUT_MS = 10_000;
137Ôćĺ
138Ôćĺ/** Timeout for simulator interactions (tap, swipe, type, key press) ÔÇö HID
139Ôćĺ *  injection through the ObjC bridge is fast but include IPC buffer. */
140Ôćĺconst SIMULATOR_INTERACTION_TIMEOUT_MS = 10_000;
141Ôćĺ
142Ôćĺ/** Timeout for simulator boot ÔÇö booting a simulator and starting the MJPEG
143Ôćĺ *  stream + ObjC bridge can take 15-20s on cold boot. */
144Ôćĺconst SIMULATOR_BOOT_TIMEOUT_MS = 30_000;
145Ôćĺ
146Ôćĺ/** Timeout for build-and-run ÔÇö xcodebuild can take minutes for large projects.
147Ôćĺ *  10 minutes matches the existing builder.ts timeout. */
148Ôćĺconst SIMULATOR_BUILD_TIMEOUT_MS = 600_000;
