154Ôćĺclass EventBroadcasterClass {
155Ôćĺ  // Multi-tunnel: all connected clients receive notifications.
156Ôćĺ  // The relay and desktop app can be connected simultaneously.
157Ôćĺ  private tunnels = new Set<RpcConnection>();
158Ôćĺ
159Ôćĺ  attachTunnel(tunnel: RpcConnection): void {
160Ôćĺ    this.tunnels.add(tunnel);
161Ôćĺ    console.log(`[EventBroadcaster] Tunnel attached (${this.tunnels.size} active)`);
162Ôćĺ  }
163Ôćĺ
164Ôćĺ  /**
165Ôćĺ   * Detach a specific tunnel. If tunnel is provided, removes only that one.
166Ôćĺ   * If no tunnel is provided, clears all tunnels.
167Ôćĺ   */
168Ôćĺ  detachTunnel(tunnel?: RpcConnection): void {
169Ôćĺ    if (tunnel) {
170Ôćĺ      this.tunnels.delete(tunnel);
171Ôćĺ      console.log(`[EventBroadcaster] Tunnel detached (${this.tunnels.size} remaining)`);
172Ôćĺ    } else {
173Ôćĺ      this.tunnels.clear();
174Ôćĺ      console.log("[EventBroadcaster] All tunnels cleared");
175Ôćĺ    }
176Ôćĺ  }
