574Ôćĺ  onQuery(
575Ôćĺ    tunnel: RpcConnection,
576Ôćĺ    handler: (request: Omit<QueryRequest, "type">) => Promise<QueryAckResponse>
577Ôćĺ  ): void {
578Ôćĺ    tunnel.addMethod(SIDECAR_METHODS.QUERY, async (params) => {
579Ôćĺ      const parsed = QueryRequestSchema.safeParse(params);
580Ôćĺ      if (!parsed.success) return { accepted: false, reason: "Invalid query request" };
581Ôćĺ      const { type: _, ...input } = parsed.data;
582Ôćĺ      return handler(input);
583Ôćĺ    });
584Ôćĺ  }
585Ôćĺ
586Ôćĺ  onCancel(tunnel: RpcConnection, handler: (request: Omit<CancelRequest, "type">) => void): void {
587Ôćĺ    tunnel.addMethod(SIDECAR_METHODS.CANCEL, (params) => {
588Ôćĺ      const parsed = CancelRequestSchema.safeParse(params);
589Ôćĺ      if (!parsed.success) return Promise.resolve(undefined);
590Ôćĺ      const { type: _, ...input } = parsed.data;
591Ôćĺ      handler(input);
592Ôćĺ      return Promise.resolve(undefined);
593Ôćĺ    });
594Ôćĺ  }
