657Ôćĺ
658Ôćĺ  // ==========================================================================
659Ôćĺ  // Internal helpers
660Ôćĺ  // ==========================================================================
661Ôćĺ
662Ôćĺ  /** Generic typed RPC: send a request to the frontend with a timeout. */
663Ôćĺ  private async rpc<TRes>(method: string, params: unknown, timeoutMs: number): Promise<TRes> {
664Ôćĺ    return this.withTimeout<TRes>(
665Ôćĺ      this.requireTunnel().request(method, params) as Promise<TRes>,
666Ôćĺ      timeoutMs,
667Ôćĺ      method
668Ôćĺ    );
669Ôćĺ  }
670Ôćĺ
671Ôćĺ  /** Returns the first available tunnel, or throws if none are connected. */
672Ôćĺ  private requireTunnel(): RpcConnection {
673Ôćĺ    const first = this.tunnels.values().next().value;
674Ôćĺ    if (!first) {
675Ôćĺ      throw new Error("EventBroadcaster tunnel not attached.");
676Ôćĺ    }
677Ôćĺ    return first;
678Ôćĺ  }
679Ôćĺ
680Ôćĺ  /**
681Ôćĺ   * Broadcast a notification to all connected tunnels.
682Ôćĺ   * Dead tunnels (those that throw on notify) are automatically removed.
683Ôćĺ   */
684Ôćĺ  private broadcastNotification(method: string, params: unknown, label: string): void {
685Ôćĺ    const t0 = Date.now();
686Ôćĺ    for (const tunnel of this.tunnels) {
687Ôćĺ      try {
688Ôćĺ        tunnel.notify(method, params);
689Ôćĺ      } catch (err) {
690Ôćĺ        console.error(`[EventBroadcaster] ${label} failed, removing dead tunnel:`, err);
691Ôćĺ        this.tunnels.delete(tunnel);
692Ôćĺ      }
693Ôćĺ    }
694Ôćĺ    const elapsed = Date.now() - t0;
695Ôćĺ    if (elapsed > 5) {
696Ôćĺ      console.log(
697Ôćĺ        `[TIMING][EventBroadcaster] ${label} broadcast took ${elapsed}ms (${this.tunnels.size} tunnels)`
698Ôćĺ      );
699Ôćĺ    }
700Ôćĺ  }
701Ôćĺ
702Ôćĺ  /**
703Ôćĺ   * Race a tunnel request against a timeout. Rejects with a descriptive
704Ôćĺ   * error if the frontend does not respond within `ms` milliseconds.
705Ôćĺ   */
706Ôćĺ  private withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
707Ôćĺ    let timerId: ReturnType<typeof setTimeout> | undefined;
708Ôćĺ
709Ôćĺ    const timeout = new Promise<never>((_, reject) => {
710Ôćĺ      timerId = setTimeout(() => {
711Ôćĺ        reject(
712Ôćĺ          new Error(
713Ôćĺ            `[EventBroadcaster] ${label} timed out after ${ms}ms -- frontend did not respond`
714Ôćĺ          )
715Ôćĺ        );
716Ôćĺ      }, ms);
717Ôćĺ    });
718Ôćĺ
719Ôćĺ    return Promise.race([promise, timeout]).finally(() => {
720Ôćĺ      if (timerId !== undefined) clearTimeout(timerId);
721Ôćĺ    });
722Ôćĺ  }
723Ôćĺ}
724Ôćĺ
725Ôćĺ/** Singleton instance shared across the entire sidecar process */
726Ôćĺexport const EventBroadcaster = new EventBroadcasterClass();
727Ôćĺ

  1Ôćĺ// sidecar/health.ts
  2Ôćĺ// Health endpoint handler and graceful shutdown coordinator for the agent-server.
  3Ôćĺ//
  4Ôćĺ// Health: GET /health returns uptime, memory, agents, connections.
  5Ôćĺ// Readiness: GET /readyz returns 200 if agents are initialized, 503 if not.
  6Ôćĺ// Graceful shutdown: drains in-flight turns before closing connections.
  7Ôćĺ
  8Ôćĺimport type { IncomingMessage, ServerResponse } from "http";
  9Ôćĺimport type { WebSocketServer } from "ws";
 10Ôćĺimport { getRegisteredAgentTypes, getAgent } from "./agents/registry";
 11Ôćĺimport type { AgentType } from "../shared/enums";
 12Ôćĺimport { EventBroadcaster } from "./event-broadcaster";
 13Ôćĺ
 14Ôćĺ// ============================================================================
 15Ôćĺ// Types
 16Ôćĺ// ============================================================================
 17Ôćĺ
 18Ôćĺexport interface HealthResponse {
 19Ôćĺ  status: "ok";
 20Ôćĺ  uptime: number;
 21Ôćĺ  memoryMb: number;
 22Ôćĺ  agents: string[];
 23Ôćĺ  connections: number;
 24Ôćĺ  version: string;
 25Ôćĺ  timestamp: string;
 26Ôćĺ}
 27Ôćĺ
 28Ôćĺexport interface ShutdownConfig {
 29Ôćĺ  /** Maximum time (ms) to wait for in-flight turns to drain. Default: 30_000 */
 30Ôćĺ  drainTimeoutMs: number;
 31Ôćĺ}
 32Ôćĺ
 33Ôćĺconst DEFAULT_SHUTDOWN_CONFIG: ShutdownConfig = {
 34Ôćĺ  drainTimeoutMs: 30_000,
 35Ôćĺ};
 36Ôćĺ
 37Ôćĺ// ============================================================================
 38Ôćĺ// Module state
 39Ôćĺ// ============================================================================
 40Ôćĺ
 41Ôćĺ/** Set to true once agents have been initialized */
 42Ôćĺlet agentsInitialized = false;
 43Ôćĺ
 44Ôćĺ/** Set to true when shutdown has been signaled */
 45Ôćĺlet shuttingDown = false;
 46Ôćĺ
 47Ôćĺ/** Active sessions (sessionId -> agentType). Add on turn/start, remove on idle/error/cancelled. */
 48Ôćĺconst activeSessions = new Map<string, string>();
 49Ôćĺ
 50Ôćĺ/** Process start time, used for uptime calculation */
 51Ôćĺconst startTime = Date.now();
 52Ôćĺ
 53Ôćĺ// ============================================================================
 54Ôćĺ// State accessors (exported for index.ts and tests)
 55Ôćĺ// ============================================================================
 56Ôćĺ
 57Ôćĺexport function setAgentsInitialized(value: boolean): void {
 58Ôćĺ  agentsInitialized = value;
 59Ôćĺ}
 60Ôćĺ
 61Ôćĺexport function isAgentsInitialized(): boolean {
 62Ôćĺ  return agentsInitialized;
 63Ôćĺ}
 64Ôćĺ
 65Ôćĺexport function isShuttingDown(): boolean {
 66Ôćĺ  return shuttingDown;
 67Ôćĺ}
 68Ôćĺ
 69Ôćĺexport function setShuttingDown(value: boolean): void {
 70Ôćĺ  shuttingDown = value;
 71Ôćĺ}
 72Ôćĺ
 73Ôćĺexport function getActiveSessions(): Map<string, string> {
 74Ôćĺ  return activeSessions;
 75Ôćĺ}
 76Ôćĺ
 77Ôćĺexport function trackSession(sessionId: string, agentType: string): void {
 78Ôćĺ  activeSessions.set(sessionId, agentType);
 79Ôćĺ}
 80Ôćĺ
 81Ôćĺexport function untrackSession(sessionId: string): void {
 82Ôćĺ  activeSessions.delete(sessionId);
 83Ôćĺ}
 84Ôćĺ
 85Ôćĺexport function getActiveSessionCount(): number {
 86Ôćĺ  return activeSessions.size;
 87Ôćĺ}
 88Ôćĺ
 89Ôćĺ// ============================================================================
 90Ôćĺ// Health endpoint handler
 91Ôćĺ// ============================================================================
 92Ôćĺ
 93Ôćĺ/**
 94Ôćĺ * Builds the health response payload.
 95Ôćĺ * Separated from the HTTP handler so it can be tested independently.
 96Ôćĺ */
 97Ôćĺexport function buildHealthResponse(wss: WebSocketServer | null): HealthResponse {
 98Ôćĺ  const uptimeSeconds = (Date.now() - startTime) / 1000;
 99Ôćĺ  const memoryMb = Math.round((process.memoryUsage.rss() / 1024 / 1024) * 100) / 100;
100Ôćĺ  const agents = getRegisteredAgentTypes();
101Ôćĺ  const connections = wss ? wss.clients.size : 0;
102Ôćĺ
103Ôćĺ  return {
104Ôćĺ    status: "ok",
105Ôćĺ    uptime: Math.round(uptimeSeconds * 100) / 100,
106Ôćĺ    memoryMb,
107Ôćĺ    agents,
108Ôćĺ    connections,
109Ôćĺ    version: "1.0.0",
110Ôćĺ    timestamp: new Date().toISOString(),
111Ôćĺ  };
112Ôćĺ}
113Ôćĺ
114Ôćĺ/**
115Ôćĺ * HTTP request handler for the agent-server.
116Ôćĺ * Handles GET /health, GET /readyz, and returns 404 for everything else.
117Ôćĺ * Non-GET requests and WebSocket upgrades are not routed here.
118Ôćĺ */
119Ôćĺexport function handleHttpRequest(
120Ôćĺ  req: IncomingMessage,
121Ôćĺ  res: ServerResponse,
122Ôćĺ  wss: WebSocketServer | null
123Ôćĺ): void {
124Ôćĺ  const url = req.url || "/";
125Ôćĺ  const method = req.method || "GET";
126Ôćĺ
127Ôćĺ  if (method === "GET" && url === "/health") {
128Ôćĺ    const body = JSON.stringify(buildHealthResponse(wss));
129Ôćĺ    res.writeHead(200, {
130Ôćĺ      "Content-Type": "application/json",
131Ôćĺ      "Cache-Control": "no-store",
132Ôćĺ    });
133Ôćĺ    res.end(body);
134Ôćĺ    return;
135Ôćĺ  }
136Ôćĺ
137Ôćĺ  if (method === "GET" && url === "/readyz") {
138Ôćĺ    if (agentsInitialized && !shuttingDown) {
139Ôćĺ      res.writeHead(200, { "Content-Type": "application/json" });
140Ôćĺ      res.end(JSON.stringify({ status: "ready" }));
141Ôćĺ    } else {
142Ôćĺ      const reason = shuttingDown ? "shutting down" : "agents not initialized";
143Ôćĺ      res.writeHead(503, { "Content-Type": "application/json" });
144Ôćĺ      res.end(JSON.stringify({ status: "not ready", reason }));
145Ôćĺ    }
146Ôćĺ    return;
147Ôćĺ  }
148Ôćĺ
149Ôćĺ  // Everything else: 404 (WebSocket upgrades are handled separately by the WS server)
150Ôćĺ  res.writeHead(404, { "Content-Type": "text/plain" });
151Ôćĺ  res.end("Not Found");
152Ôćĺ}
153Ôćĺ
154Ôćĺ// ============================================================================
155Ôćĺ// Graceful shutdown with turn draining
156Ôćĺ// ============================================================================
157Ôćĺ
158Ôćĺ/**
159Ôćĺ * Waits for all active sessions to complete, up to the configured timeout.
160Ôćĺ * Returns true if all sessions drained, false if timeout was reached.
161Ôćĺ */
162Ôćĺexport function waitForDrain(config: ShutdownConfig = DEFAULT_SHUTDOWN_CONFIG): Promise<boolean> {
163Ôćĺ  return new Promise((resolve) => {
164Ôćĺ    if (activeSessions.size === 0) {
165Ôćĺ      resolve(true);
166Ôćĺ      return;
167Ôćĺ    }
168Ôćĺ
169Ôćĺ    const deadline = Date.now() + config.drainTimeoutMs;
170Ôćĺ
171Ôćĺ    const checkInterval = setInterval(() => {
172Ôćĺ      if (activeSessions.size === 0) {
173Ôćĺ        clearInterval(checkInterval);
174Ôćĺ        resolve(true);
175Ôćĺ        return;
176Ôćĺ      }
177Ôćĺ
178Ôćĺ      if (Date.now() >= deadline) {
179Ôćĺ        clearInterval(checkInterval);
180Ôćĺ        resolve(false);
181Ôćĺ        return;
182Ôćĺ      }
183Ôćĺ    }, 100);
184Ôćĺ  });
185Ôćĺ}
186Ôćĺ
187Ôćĺ/**
188Ôćĺ * Cancels all remaining active sessions using the proper cancellation flow.
189Ôćĺ * Tries agent.cancel() first (which sets cancelledByUser, creates checkpoints,
190Ôćĺ * and terminates subprocesses), then falls back to direct event emission.
191Ôćĺ */
192Ôćĺexport async function cancelRemainingSessions(): Promise<void> {
193Ôćĺ  const entries = [...activeSessions];
194Ôćĺ  for (const [sessionId, agentType] of entries) {
195Ôćĺ    console.log(`[SHUTDOWN] Force-cancelling session ${sessionId} (agent=${agentType})`);
196Ôćĺ    const agent = getAgent(agentType as AgentType);
197Ôćĺ    if (agent) {
198Ôćĺ      try {
199Ôćĺ        await agent.cancel(sessionId);
200Ôćĺ      } catch (err) {
201Ôćĺ        console.error(
202Ôćĺ          `[SHUTDOWN] agent.cancel() failed for ${sessionId}, emitting events directly:`,
203Ôćĺ          err
204Ôćĺ        );
205Ôćĺ        EventBroadcaster.emitMessageCancelled(sessionId, agentType as any);
206Ôćĺ        EventBroadcaster.emitSessionCancelled(sessionId, agentType as any);
207Ôćĺ      }
208Ôćĺ    } else {
209Ôćĺ      EventBroadcaster.emitMessageCancelled(sessionId, agentType as any);
210Ôćĺ      EventBroadcaster.emitSessionCancelled(sessionId, agentType as any);
211Ôćĺ    }
212Ôćĺ  }
213Ôćĺ  activeSessions.clear();
214Ôćĺ}
215Ôćĺ
216Ôćĺ// ============================================================================
217Ôćĺ// Reset (for tests)
218Ôćĺ// ============================================================================
219Ôćĺ
220Ôćĺexport function resetHealthState(): void {
221Ôćĺ  agentsInitialized = false;
222Ôćĺ  shuttingDown = false;
223Ôćĺ  activeSessions.clear();
224Ôćĺ}
225Ôćĺ

  1Ôćĺ// backend/src/services/agent-client.ts
