  5Ôćĺ//   Backend Ôćĺ Agent: { method: "initialize", params: { version: "1.0", capabilities: {} } }
  6Ôćĺ//   Agent Ôćĺ Backend: { result: { version: "1.0", agents: [...], capabilities: {} } }
  7Ôćĺ//   Backend Ôćĺ Agent: { method: "initialized" } (notification)
