 42Ôćĺ// ============================================================================
 43Ôćĺ// Types
 44Ôćĺ// ============================================================================
 45Ôćĺ
 46Ôćĺexport type AgentEventHandler = (event: AgentEvent) => void;
 47Ôćĺ
 48Ôćĺexport interface AgentClientOptions {
 49Ôćĺ  /** ws://127.0.0.1:{port} ÔÇö the agent-server URL */
 50Ôćĺ  url: string;
