 54Ôćĺ  onConnected?: (agents: AgentInfo[]) => void;
 55Ôćĺ  /** Called when the connection drops */
 56Ôćĺ  onDisconnected?: () => void;
 57Ôćĺ}
 58Ôćĺ
 59Ôćĺ// ============================================================================
 60Ôćĺ// Reconnect constants
 61Ôćĺ// ============================================================================
 62Ôćĺ
 63Ôćĺconst BASE_RECONNECT_DELAY_MS = 1_000;
 64Ôćĺconst MAX_RECONNECT_DELAY_MS = 30_000;
 65Ôćĺconst HANDSHAKE_TIMEOUT_MS = 10_000;
 66Ôćĺconst PROTOCOL_VERSION = "1.0";
