 68Ôćĺ// ============================================================================
 69Ôćĺ// AgentClient
 70Ôćĺ// ============================================================================
 71Ôćĺ
 72Ôćĺexport class AgentClient {
 73Ôćĺ  private url: string;
 74Ôćĺ  private ws: WebSocket | null = null;
 75Ôćĺ  private peer: JSONRPCServerAndClient | null = null;
 76Ôćĺ  private onEvent: AgentEventHandler;
 77Ôćĺ  private onConnected?: (agents: AgentInfo[]) => void;
 78Ôćĺ  private onDisconnected?: () => void;
 79Ôćĺ
 80Ôćĺ  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 81Ôćĺ  private reconnectAttempt = 0;
 82Ôćĺ  private disposed = false;
 83Ôćĺ  private connected = false;
 84Ôćĺ
 85Ôćĺ  /** Agents discovered during the initialize handshake */
 86Ôćĺ  private agents: AgentInfo[] = [];
 87Ôćĺ
 88Ôćĺ  constructor(options: AgentClientOptions) {
 89Ôćĺ    this.url = options.url;
 90Ôćĺ    this.onEvent = options.onEvent ?? (() => {});
 91Ôćĺ    this.onConnected = options.onConnected;
 92Ôćĺ    this.onDisconnected = options.onDisconnected;
 93Ôćĺ  }
 94Ôćĺ
 95Ôćĺ  // ==========================================================================
 96Ôćĺ  // Public API
 97Ôćĺ  // ==========================================================================
 98Ôćĺ
