107Ôćĺ  }
108Ôćĺ
109Ôćĺ  /** Permanently disconnect and stop reconnecting. */
110Ôćĺ  disconnect(): void {
111Ôćĺ    this.disposed = true;
112Ôćĺ    this.cancelReconnect();
