130Ôćĺ  }
131Ôćĺ
132Ôćĺ  async sendTurnCancel(params: TurnCancelRequest): Promise<void> {
133Ôćĺ    await this.request(AGENT_RPC_METHODS.TURN_CANCEL, params);
134Ôćĺ  }
135Ôćĺ
136Ôćĺ  async sendTurnRespond(params: TurnRespondRequest): Promise<void> {
137Ôćĺ    await this.request(AGENT_RPC_METHODS.TURN_RESPOND, params);
138Ôćĺ  }
139Ôćĺ
140Ôćĺ  // ---- Session lifecycle RPCs ----
141Ôćĺ
142Ôćĺ  async sendSessionReset(params: SessionResetRequest): Promise<void> {
143Ôćĺ    await this.request(AGENT_RPC_METHODS.SESSION_RESET, params);
144Ôćĺ  }
145Ôćĺ
146Ôćĺ  async sendSessionStop(params: SessionStopRequest): Promise<void> {
147Ôćĺ    await this.request(AGENT_RPC_METHODS.SESSION_STOP, params);
148Ôćĺ  }
149Ôćĺ
150Ôćĺ  // ---- Provider operations ----
151Ôćĺ
152Ôćĺ  async sendProviderAuth(params: ProviderAuthRequest): Promise<unknown> {
153Ôćĺ    return this.request(AGENT_RPC_METHODS.PROVIDER_AUTH, params);
154Ôćĺ  }
155Ôćĺ
156Ôćĺ  async sendProviderInitWorkspace(params: ProviderInitWorkspaceRequest): Promise<unknown> {
157Ôćĺ    return this.request(AGENT_RPC_METHODS.PROVIDER_INIT_WORKSPACE, params);
158Ôćĺ  }
159Ôćĺ
160Ôćĺ  async sendProviderContextUsage(params: ProviderContextUsageRequest): Promise<unknown> {
161Ôćĺ    return this.request(AGENT_RPC_METHODS.PROVIDER_CONTEXT_USAGE, params);
162Ôćĺ  }
163Ôćĺ
164Ôćĺ  async sendProviderUpdateMode(params: ProviderUpdateModeRequest): Promise<void> {
165Ôćĺ    this.notify(AGENT_RPC_METHODS.PROVIDER_UPDATE_MODE, params);
166Ôćĺ  }
