175Ôćĺ  // ==========================================================================
176Ôćĺ  // Connection lifecycle
177Ôćĺ  // ==========================================================================
178Ôćĺ
179Ôćĺ  private openConnection(): void {
180Ôćĺ    if (this.disposed) return;
181Ôćĺ
182Ôćĺ    console.log(`[AgentClient] Connecting to ${this.url}...`);
183Ôćĺ
184Ôćĺ    try {
185Ôćĺ      this.ws = new WebSocket(this.url);
186Ôćĺ    } catch (err) {
187Ôćĺ      console.error("[AgentClient] Failed to create WebSocket:", err);
188Ôćĺ      this.scheduleReconnect();
189Ôćĺ      return;
190Ôćĺ    }
191Ôćĺ
192Ôćĺ    this.ws.on("open", () => {
193Ôćĺ      console.log("[AgentClient] WebSocket connected, starting handshake...");
194Ôćĺ      this.reconnectAttempt = 0;
195Ôćĺ      this.setupPeer();
196Ôćĺ      void this.performHandshake();
197Ôćĺ    });
198Ôćĺ
199Ôćĺ    this.ws.on("message", (data: Buffer | string) => {
200Ôćĺ      const message = typeof data === "string" ? data : data.toString("utf8");
201Ôćĺ      this.handleMessage(message);
202Ôćĺ    });
203Ôćĺ
204Ôćĺ    this.ws.on("close", (code, reason) => {
205Ôćĺ      console.log(`[AgentClient] Connection closed: ${code} ${reason.toString()}`);
206Ôćĺ      this.teardownPeer();
207Ôćĺ      if (!this.disposed) this.scheduleReconnect();
208Ôćĺ    });
209Ôćĺ
210Ôćĺ    this.ws.on("error", (err) => {
211Ôćĺ      console.error("[AgentClient] WebSocket error:", err.message);
212Ôćĺ    });
213Ôćĺ  }
214Ôćĺ
215Ôćĺ  private closeConnection(): void {
216Ôćĺ    if (this.ws) {
217Ôćĺ      this.ws.removeAllListeners();
218Ôćĺ      if (this.ws.readyState === WebSocket.OPEN || this.ws.readyState === WebSocket.CONNECTING) {
219Ôćĺ        this.ws.close(1000, "Client disconnecting");
220Ôćĺ      }
221Ôćĺ      this.ws = null;
222Ôćĺ    }
223Ôćĺ    this.teardownPeer();
224Ôćĺ  }
