226Ôćĺ  // ==========================================================================
227Ôćĺ  // JSON-RPC peer
228Ôćĺ  // ==========================================================================
229Ôćĺ
230Ôćĺ  private setupPeer(): void {
231Ôćĺ    const server = new JSONRPCServer({
232Ôćĺ      errorListener: (message, data) => {
233Ôćĺ        console.error("[AgentClient] RPC server error:", message, data);
234Ôćĺ      },
235Ôćĺ    });
236Ôćĺ
237Ôćĺ    const client = new JSONRPCClient((payload) => {
238Ôćĺ      if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
239Ôćĺ        return Promise.reject(new Error("WebSocket is not open"));
240Ôćĺ      }
241Ôćĺ      try {
242Ôćĺ        this.ws.send(JSON.stringify(payload));
243Ôćĺ        return Promise.resolve();
244Ôćĺ      } catch (error) {
245Ôćĺ        return Promise.reject(error instanceof Error ? error : new Error(String(error)));
246Ôćĺ      }
247Ôćĺ    });
248Ôćĺ
249Ôćĺ    this.peer = new JSONRPCServerAndClient(server, client, {
250Ôćĺ      errorListener: (message, data) => {
251Ôćĺ        console.error("[AgentClient] RPC client error:", message, data);
252Ôćĺ      },
253Ôćĺ    });
254Ôćĺ
255Ôćĺ    // Register handlers for all agent-event notification methods.
256Ôćĺ    // The agent-server sends these as JSON-RPC notifications (no id).
257Ôćĺ    for (const eventName of Object.values(AGENT_EVENT_NAMES)) {
258Ôćĺ      this.peer.addMethod(eventName, async (params) => {
259Ôćĺ        this.dispatchEvent(eventName, params);
260Ôćĺ        return undefined; // notifications don't return a value
261Ôćĺ      });
262Ôćĺ    }
263Ôćĺ  }
264Ôćĺ
265Ôćĺ  private teardownPeer(): void {
266Ôćĺ    const wasConnected = this.connected;
267Ôćĺ    this.connected = false;
268Ôćĺ    if (this.peer) {
269Ôćĺ      this.peer.rejectAllPendingRequests("Connection closed");
270Ôćĺ      this.peer = null;
271Ôćĺ    }
272Ôćĺ    if (wasConnected) {
273Ôćĺ      this.onDisconnected?.();
274Ôćĺ    }
275Ôćĺ  }
