277Ôćĺ  private dispatchEvent(eventName: string, params: unknown): void {
278Ôćĺ    // Validate and normalize the event payload using the canonical schema.
279Ôćĺ    // If parsing fails, log and skip ÔÇö don't crash the client.
280Ôćĺ    const parsed = AgentEventSchema.safeParse(params);
281Ôćĺ    if (!parsed.success) {
282Ôćĺ      console.error(`[AgentClient] Invalid event payload for "${eventName}":`, parsed.error.message);
283Ôćĺ      return;
284Ôćĺ    }
285Ôćĺ    try {
286Ôćĺ      this.onEvent(parsed.data);
287Ôćĺ    } catch (err) {
288Ôćĺ      console.error(`[AgentClient] Event handler threw for "${eventName}":`, err);
289Ôćĺ    }
290Ôćĺ  }
