292Ôćĺ  // ==========================================================================
293Ôćĺ  // Handshake
294Ôćĺ  // ==========================================================================
295Ôćĺ
296Ôćĺ  private async performHandshake(): Promise<void> {
297Ôćĺ    if (!this.peer) return;
298Ôćĺ
299Ôćĺ    try {
300Ôćĺ      const rawResult = await this.withTimeout(
301Ôćĺ        this.peer.request(AGENT_RPC_METHODS.INITIALIZE, {
302Ôćĺ          version: PROTOCOL_VERSION,
303Ôćĺ          capabilities: {},
304Ôćĺ        }),
305Ôćĺ        HANDSHAKE_TIMEOUT_MS,
306Ôćĺ        "initialize"
307Ôćĺ      );
308Ôćĺ
309Ôćĺ      const parsed = InitializeResultSchema.safeParse(rawResult);
310Ôćĺ      if (!parsed.success) {
311Ôćĺ        throw new Error(`Invalid initialize response: ${parsed.error.message}`);
312Ôćĺ      }
313Ôćĺ      const result: InitializeResult = parsed.data;
314Ôćĺ
315Ôćĺ      this.agents = result.agents;
316Ôćĺ      console.log(
317Ôćĺ        `[AgentClient] Handshake complete: version=${result.version} agents=[${this.agents.map((a) => a.type).join(", ")}]`
318Ôćĺ      );
319Ôćĺ
320Ôćĺ      // Send "initialized" notification (fire-and-forget)
321Ôćĺ      this.peer.notify(AGENT_RPC_METHODS.INITIALIZED, {}, undefined);
322Ôćĺ
323Ôćĺ      this.connected = true;
324Ôćĺ      this.onConnected?.(this.agents);
325Ôćĺ    } catch (err) {
326Ôćĺ      console.error("[AgentClient] Handshake failed:", err);
327Ôćĺ      // Close and reconnect
328Ôćĺ      this.closeConnection();
329Ôćĺ      if (!this.disposed) this.scheduleReconnect();
330Ôćĺ    }
331Ôćĺ  }
