336Ôćĺ
337Ôćĺ  private handleMessage(message: string): void {
338Ôćĺ    if (!this.peer) return;
339Ôćĺ
340Ôćĺ    let payload: unknown;
341Ôćĺ    try {
342Ôćĺ      payload = JSON.parse(message);
343Ôćĺ    } catch {
344Ôćĺ      console.error("[AgentClient] Failed to parse JSON:", message.slice(0, 200));
345Ôćĺ      return;
346Ôćĺ    }
347Ôćĺ
348Ôćĺ    if (!isJsonRpcPayload(payload)) {
349Ôćĺ      console.error("[AgentClient] Received non-JSON-RPC payload");
350Ôćĺ      return;
351Ôćĺ    }
352Ôćĺ
353Ôćĺ    void this.peer.receiveAndSend(payload, undefined, undefined).catch((e) => {
354Ôćĺ      console.error("[AgentClient] Failed to handle message:", e);
355Ôćĺ    });
356Ôćĺ  }
