362Ôćĺ  private request(method: string, params: unknown): Promise<unknown> {
363Ôćĺ    if (!this.peer || !this.connected) {
364Ôćĺ      return Promise.reject(new Error(`AgentClient is not connected (method=${method})`));
365Ôćĺ    }
366Ôćĺ    return Promise.resolve(this.peer.request(method, params, undefined));
367Ôćĺ  }
368Ôćĺ
369Ôćĺ  private notify(method: string, params: unknown): void {
370Ôćĺ    if (!this.peer || !this.connected) {
371Ôćĺ      console.error(`[AgentClient] Cannot send notification "${method}" ÔÇö not connected`);
372Ôćĺ      return;
373Ôćĺ    }
374Ôćĺ    this.peer.notify(method, params, undefined);
375Ôćĺ  }
