377Ôćĺ  // ==========================================================================
378Ôćĺ  // Reconnect
379Ôćĺ  // ==========================================================================
380Ôćĺ
381Ôćĺ  private scheduleReconnect(): void {
382Ôćĺ    if (this.reconnectTimer || this.disposed) return;
383Ôćĺ    const delay = Math.min(
384Ôćĺ      BASE_RECONNECT_DELAY_MS * 2 ** this.reconnectAttempt,
385Ôćĺ      MAX_RECONNECT_DELAY_MS
386Ôćĺ    );
387Ôćĺ    this.reconnectAttempt++;
388Ôćĺ    console.log(`[AgentClient] Reconnecting in ${delay}ms (attempt ${this.reconnectAttempt})...`);
389Ôćĺ    this.reconnectTimer = setTimeout(() => {
390Ôćĺ      this.reconnectTimer = null;
391Ôćĺ      this.openConnection();
392Ôćĺ    }, delay);
393Ôćĺ  }
394Ôćĺ
395Ôćĺ  private cancelReconnect(): void {
396Ôćĺ    if (this.reconnectTimer) {
397Ôćĺ      clearTimeout(this.reconnectTimer);
398Ôćĺ      this.reconnectTimer = null;
399Ôćĺ    }
400Ôćĺ  }
