406Ôćĺ  private withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
407Ôćĺ    let timerId: ReturnType<typeof setTimeout> | undefined;
408Ôćĺ    const timeout = new Promise<never>((_, reject) => {
409Ôćĺ      timerId = setTimeout(() => {
410Ôćĺ        reject(new Error(`[AgentClient] ${label} timed out after ${ms}ms`));
411Ôćĺ      }, ms);
412Ôćĺ    });
413Ôćĺ    return Promise.race([promise, timeout]).finally(() => {
414Ôćĺ      if (timerId !== undefined) clearTimeout(timerId);
415Ôćĺ    });
416Ôćĺ  }
417Ôćĺ}
