  2Ôćĺ// Agent handler interface, type definitions, and runtime registry.
  3Ôćĺ// Each agent type (claude, codex, etc.) implements AgentHandler and
  4Ôćĺ// registers itself in the registry during sidecar startup.
  5Ôćĺ
  6Ôćĺimport { getErrorMessage } from "../../shared/lib/errors";
  7Ôćĺimport type { AgentType, QueryRequest } from "../protocol";
  8Ôćĺ
  9Ôćĺ// ============================================================================
 10Ôćĺ// Type Definitions
 11Ôćĺ// ============================================================================
 12Ôćĺ
 13Ôćĺ/** Options passed to query(), validated by QueryRequestSchema in protocol.ts */
 14Ôćĺexport type QueryOptions = QueryRequest["options"];
 15Ôćĺ
 16Ôćĺ/**
 17Ôćĺ * Declares which optional features an agent handler supports.
 18Ôćĺ * Used for capability-based dispatch ÔÇö call sites check capabilities
 19Ôćĺ * instead of checking agentType strings or casting to concrete classes.
 20Ôćĺ */
 21Ôćĺexport interface AgentCapabilities {
 22Ôćĺ  /** Supports auth check (e.g., Claude account info) */
 23Ôćĺ  auth: boolean;
 24Ôćĺ  /** Supports workspace initialization (slash commands, MCP servers) */
 25Ôćĺ  workspaceInit: boolean;
 26Ôćĺ  /** Supports context usage queries */
 27Ôćĺ  contextUsage: boolean;
 28Ôćĺ  /** Supports runtime permission mode changes */
 29Ôćĺ  permissionMode: boolean;
 30Ôćĺ  /** Model switching behavior: can change model mid-session, requires restart, or unsupported */
 31Ôćĺ  modelSwitch: "in-session" | "restart-session" | "unsupported";
 32Ôćĺ  /** Supports multi-turn conversations (prompt queue between turns) */
 33Ôćĺ  multiTurn: boolean;
 34Ôćĺ  /** Supports resuming from a previous session checkpoint */
 35Ôćĺ  sessionResume: boolean;
 36Ôćĺ}
 37Ôćĺ
 38Ôćĺ// ============================================================================
 39Ôćĺ// Optional method parameter types (provider-neutral names)
 40Ôćĺ// ============================================================================
 41Ôćĺ
 42Ôćĺexport interface AuthParams {
 43Ôćĺ  id: string;
 44Ôćĺ  cwd: string;
 45Ôćĺ}
 46Ôćĺ
 47Ôćĺexport interface InitWorkspaceParams {
 48Ôćĺ  id: string;
 49Ôćĺ  cwd: string;
 50Ôćĺ  ghToken?: string;
 51Ôćĺ  claudeEnvVars?: string;
 52Ôćĺ}
 53Ôćĺ
 54Ôćĺexport interface ContextUsageParams {
 55Ôćĺ  id: string;
 56Ôćĺ  options: { cwd: string; claudeSessionId: string };
 57Ôćĺ}
 58Ôćĺ
 59Ôćĺ/**
 60Ôćĺ * Common interface for all agent handlers.
 61Ôćĺ *
 62Ôćĺ * Core lifecycle methods (required):
 63Ôćĺ * - initialize() ÔÇö one-time setup (e.g., discover executable)
 64Ôćĺ * - query() ÔÇö process a user prompt
 65Ôćĺ * - cancel() ÔÇö cancel a running session
 66Ôćĺ * - reset() ÔÇö tear down generator for a session
 67Ôćĺ *
 68Ôćĺ * Optional provider-specific methods (guarded by capabilities):
 69Ôćĺ * - auth() ÔÇö check account auth info
 70Ôćĺ * - initWorkspace() ÔÇö get slash commands + MCP server status
 71Ôćĺ * - getContextUsage() ÔÇö fetch context window usage
 72Ôćĺ * - updatePermissionMode() ÔÇö hot-swap permission mode on active query
 73Ôćĺ */
 74Ôćĺexport interface AgentHandler {
 75Ôćĺ  readonly agentType: AgentType;
 76Ôćĺ  readonly capabilities: AgentCapabilities;
 77Ôćĺ
 78Ôćĺ  initialize(): { success: boolean; error?: string };
 79Ôćĺ
 80Ôćĺ  query(sessionId: string, prompt: string, options: QueryOptions): Promise<void>;
 81Ôćĺ
 82Ôćĺ  cancel(sessionId: string): Promise<void>;
 83Ôćĺ
 84Ôćĺ  reset(sessionId: string): void;
 85Ôćĺ
 86Ôćĺ  // Optional provider-specific methods (guarded by capabilities)
 87Ôćĺ  auth?(params: AuthParams): Promise<any>;
 88Ôćĺ  initWorkspace?(params: InitWorkspaceParams): Promise<any>;
 89Ôćĺ  getContextUsage?(params: ContextUsageParams): Promise<any>;
 90Ôćĺ  updatePermissionMode?(sessionId: string, permissionMode: string): Promise<void>;
 91Ôćĺ}
 92Ôćĺ
 93Ôćĺ// ============================================================================
 94Ôćĺ// Agent Registry
 95Ôćĺ// ============================================================================
 96Ôćĺ
 97Ôćĺconst registry = new Map<AgentType, AgentHandler>();
 98Ôćĺ
 99Ôćĺ/**
100Ôćĺ * Registers an agent handler in the registry.
101Ôćĺ * Overwrites any existing handler for the same agentType.
102Ôćĺ */
103Ôćĺexport function registerAgent(handler: AgentHandler): void {
104Ôćĺ  registry.set(handler.agentType, handler);
105Ôćĺ}
106Ôćĺ
107Ôćĺ/**
108Ôćĺ * Retrieves the agent handler for a given type.
109Ôćĺ * Returns undefined if no handler is registered for that type.
110Ôćĺ */
111Ôćĺexport function getAgent(type: AgentType): AgentHandler | undefined {
112Ôćĺ  return registry.get(type);
113Ôćĺ}
114Ôćĺ
115Ôćĺ/**
116Ôćĺ * Initializes all registered agents and returns their results.
117Ôćĺ * Called once during sidecar startup after all agents are registered.
118Ôćĺ */
119Ôćĺexport function initializeAllAgents(): Map<AgentType, { success: boolean; error?: string }> {
120Ôćĺ  const results = new Map<AgentType, { success: boolean; error?: string }>();
121Ôćĺ  for (const [type, handler] of registry) {
122Ôćĺ    try {
123Ôćĺ      const result = handler.initialize();
124Ôćĺ      results.set(type, result);
125Ôćĺ    } catch (error) {
126Ôćĺ      results.set(type, {
127Ôćĺ        success: false,
128Ôćĺ        error: getErrorMessage(error),
129Ôćĺ      });
130Ôćĺ    }
131Ôćĺ  }
132Ôćĺ  return results;
133Ôćĺ}
134Ôćĺ
135Ôćĺ/**
136Ôćĺ * Returns the list of registered agent type names.
137Ôćĺ * Used by the health endpoint to report available agents.
138Ôćĺ */
139Ôćĺexport function getRegisteredAgentTypes(): AgentType[] {
140Ôćĺ  return Array.from(registry.keys());
141Ôćĺ}
142Ôćĺ
143Ôćĺ/**
144Ôćĺ * Clears the registry. Used in tests to reset state between runs.
145Ôćĺ */
146Ôćĺexport function clearAgentRegistry(): void {
147Ôćĺ  registry.clear();
148Ôćĺ}
