 49Ôćĺ// buildPromptIterable ÔÇö parses queue messages into SDK-compatible user turns
 50Ôćĺ// ============================================================================
 51Ôćĺ
 52Ôćĺ/**
 53Ôćĺ * Wraps an AsyncQueue of raw prompt strings into the async-iterable format
 54Ôćĺ * expected by the Claude Agent SDK. Handles both plain text and JSON-encoded
 55Ôćĺ * content blocks (when user attaches images).
 56Ôćĺ */
 57Ôćĺfunction buildPromptIterable(queue: AsyncQueue<string>, sessionId: string) {
 58Ôćĺ  return (async function* () {
 59Ôćĺ    for await (const message of queue) {
 60Ôćĺ      let content: string | unknown[] = message;
 61Ôćĺ      if (message && message.startsWith("[")) {
 62Ôćĺ        try {
 63Ôćĺ          const parsed = JSON.parse(message);
 64Ôćĺ          if (Array.isArray(parsed) && parsed.length > 0 && parsed[0]?.type) {
 65Ôćĺ            content = parsed;
 66Ôćĺ          }
 67Ôćĺ        } catch {
 68Ôćĺ          // Not valid JSON ÔÇö keep as plain text string
 69Ôćĺ        }
 70Ôćĺ      }
 71Ôćĺ
 72Ôćĺ      yield {
 73Ôćĺ        type: "user" as const,
 74Ôćĺ        message: { role: "user" as const, content },
 75Ôćĺ        parent_tool_use_id: null,
 76Ôćĺ        session_id: sessionId,
