102Ôćĺ  async query(sessionId: string, prompt: string, options: QueryOptions): Promise<void> {
103Ôćĺ    const tQueryStart = Date.now();
104Ôćĺ    console.log(`[TIMING][query] START session=${sessionId} promptLength=${prompt.length}`);
105Ôćĺ    if (blockIfNotInitialized(sessionId)) return;
106Ôćĺ
107Ôćĺ    const session = claudeSessions.get(sessionId);
108Ôćĺ    const modelChanged = session?.currentModel !== options.model;
109Ôćĺ    const maxThinkingTokensChanged =
110Ôćĺ      session?.currentMaxThinkingTokens !== options.maxThinkingTokens;
111Ôćĺ    const settingsChangedFlag = settingsChanged(session?.currentSettings, options);
112Ôćĺ
113Ôćĺ    if (session) {
114Ôćĺ      session.turnId = options.turnId;
115Ôćĺ      session.cwd = options.cwd;
116Ôćĺ    }
117Ôćĺ
118Ôćĺ    const canReuse =
119Ôćĺ      isSessionActive(session) && options.shouldResetGenerator !== true && !settingsChangedFlag;
120Ôćĺ
121Ôćĺ    if (canReuse) {
122Ôćĺ      console.log(
123Ôćĺ        `[TIMING][query] REUSE session=${sessionId} decisionTime=${Date.now() - tQueryStart}ms`
124Ôćĺ      );
125Ôćĺ
126Ôćĺ      // Hot-swap model if it changed
127Ôćĺ      if (modelChanged && session) {
128Ôćĺ        const query = claudeQueries.get(sessionId);
129Ôćĺ        if (query) {
130Ôćĺ          const envVars = options.claudeEnvVars ? parseEnvString(options.claudeEnvVars) : {};
131Ôćĺ          const mappedModel = mapModelForProvider(options.model, envVars);
132Ôćĺ          console.log(
133Ôćĺ            `Model changed from ${session.currentModel} to ${options.model}, using setModel callback`
134Ôćĺ          );
135Ôćĺ          try {
136Ôćĺ            await query.setModel(mappedModel);
137Ôćĺ            const updatedSession = claudeSessions.get(sessionId);
138Ôćĺ            if (updatedSession) updatedSession.currentModel = options.model;
139Ôćĺ          } catch (error) {
140Ôćĺ            console.error(`Failed to update model: ${getErrorMessage(error)}`);
141Ôćĺ          }
142Ôćĺ        }
143Ôćĺ      }
144Ôćĺ
145Ôćĺ      // Hot-swap maxThinkingTokens if it changed
146Ôćĺ      const query = claudeQueries.get(sessionId);
147Ôćĺ      if (maxThinkingTokensChanged && session && query) {
148Ôćĺ        try {
149Ôćĺ          await query.setMaxThinkingTokens(options.maxThinkingTokens ?? null);
150Ôćĺ          session.currentMaxThinkingTokens = options.maxThinkingTokens;
151Ôćĺ        } catch (error) {
152Ôćĺ          console.error(`Failed to update maxThinkingTokens: ${getErrorMessage(error)}`);
153Ôćĺ        }
154Ôćĺ      }
155Ôćĺ
156Ôćĺ      // Update permission mode if provided
157Ôćĺ      if (query && options.permissionMode) {
158Ôćĺ        try {
159Ôćĺ          await query.setPermissionMode(options.permissionMode as PermissionMode);
160Ôćĺ        } catch (error) {
161Ôćĺ          console.error(`Failed to update permission mode: ${getErrorMessage(error)}`);
162Ôćĺ        }
163Ôćĺ      }
164Ôćĺ
165Ôćĺ      // Push the new prompt into the existing generator
166Ôćĺ      // isSessionActive type guard narrows sendMessage to be defined
167Ôćĺ      session.sendMessage(prompt);
168Ôćĺ    } else {
169Ôćĺ      const reason = !session
170Ôćĺ        ? "new session"
171Ôćĺ        : !isSessionActive(session)
172Ôćĺ          ? "no active generator"
173Ôćĺ          : options.shouldResetGenerator
174Ôćĺ            ? "should reset generator"
175Ôćĺ            : "settings changed";
176Ôćĺ      console.log(
177Ôćĺ        `[TIMING][query] NEW_GENERATOR session=${sessionId} reason="${reason}" decisionTime=${Date.now() - tQueryStart}ms`
178Ôćĺ      );
179Ôćĺ
180Ôćĺ      if (isSessionActive(session)) {
181Ôćĺ        terminateSession(sessionId);
182Ôćĺ      }
183Ôćĺ
184Ôćĺ      const newSession: SessionState = {
185Ôćĺ        currentSettings: {
186Ôćĺ          claudeEnvVars: options.claudeEnvVars,
187Ôćĺ          additionalDirectories: options.additionalDirectories,
188Ôćĺ          chromeEnabled: options.chromeEnabled,
189Ôćĺ          strictDataPrivacy: options.strictDataPrivacy,
190Ôćĺ        },
191Ôćĺ        currentModel: options.model,
192Ôćĺ        currentMaxThinkingTokens: options.maxThinkingTokens,
193Ôćĺ        turnId: options.turnId,
194Ôćĺ        cwd: options.cwd,
195Ôćĺ      };
196Ôćĺ      claudeSessions.set(sessionId, newSession);
197Ôćĺ
198Ôćĺ      void this.processWithGenerator(sessionId, prompt, options);
199Ôćĺ    }
200Ôćĺ  }
