202Ôćĺ  async cancel(sessionId: string): Promise<void> {
203Ôćĺ    console.log("Handling Claude cancel request for session:", sessionId);
204Ôćĺ    if (blockIfNotInitialized(sessionId)) return;
205Ôćĺ
206Ôćĺ    const existingQuery = claudeQueries.get(sessionId);
207Ôćĺ    const session = claudeSessions.get(sessionId);
208Ôćĺ
209Ôćĺ    if (isSessionActive(session) && existingQuery) {
210Ôćĺ      console.log(`Force-closing query for session ${sessionId}`);
211Ôćĺ
212Ôćĺ      // 1. Flag cancellation so the post-loop path persists the cancelled message
213Ôćĺ      session.cancelledByUser = true;
214Ôćĺ
215Ôćĺ      // 2. Create checkpoint before process dies
216Ôćĺ      if (session.turnId && session.cwd) {
217Ôćĺ        createCheckpoint(sessionId, session.turnId, "end", session.cwd, "claudeHandler");
218Ôćĺ      }
219Ôćĺ
220Ôćĺ      // 3. Force kill: close() terminates CLI subprocess + all children + MCP transports
221Ôćĺ      existingQuery.close();
222Ôćĺ
223Ôćĺ      // 4. Signal prompt generator to stop ÔÇö finally block owns cleanup
224Ôćĺ      terminateSession(sessionId);
225Ôćĺ    } else {
226Ôćĺ      console.log(`No active session found for ${sessionId} to cancel`);
227Ôćĺ    }
228Ôćĺ  }
229Ôćĺ
230Ôćĺ  reset(sessionId: string): void {
231Ôćĺ    console.log(`Handling reset generator request for session: ${sessionId}`);
232Ôćĺ    const session = claudeSessions.get(sessionId);
233Ôćĺ    if (session) {
234Ôćĺ      console.log(`Terminating generator for session ${sessionId} on reset request`);
235Ôćĺ      terminateSession(sessionId);
236Ôćĺ    }
237Ôćĺ  }
