  2Ôćĺ// Manages pending tool requests being relayed from the agent-server to the frontend.
  3Ôćĺ//
  4Ôćĺ// Flow:
  5Ôćĺ//   Agent emits tool.request event
  6Ôćĺ//   Ôćĺ handleAgentEvent calls toolRelay.relay()
  7Ôćĺ//   Ôćĺ Backend pushes q:event { event: "tool:request", data: {...} } to all frontend WS clients
  8Ôćĺ//   Ôćĺ Frontend handles the request (browser automation, diff, terminal, plan, question)
  9Ôćĺ//   Ôćĺ Frontend sends q:tool_response { requestId, result/error } back via WS
 10Ôćĺ//   Ôćĺ Backend calls toolRelay.resolve/reject
 11Ôćĺ//   Ôćĺ relay() promise resolves Ôćĺ agent-event-handler sends result back to agent-server
 12Ôćĺ//
 13Ôćĺ// Timeout handling: each tool request has a timeout (set by the agent-server).
 14Ôćĺ// If the frontend doesn't respond within the timeout, the pending promise is rejected.
 15Ôćĺ
 16Ôćĺimport type { ToolRequestEvent } from "../../../shared/agent-events";
 17Ôćĺimport type { ToolRequestEventData, QServerFrame } from "../../../shared/types/query-protocol";
 18Ôćĺimport { broadcast } from "./ws.service";
 19Ôćĺ
 20Ôćĺ// ---- Types ----
 21Ôćĺ
 22Ôćĺinterface PendingRelay {
 23Ôćĺ  resolve: (result: unknown) => void;
 24Ôćĺ  reject: (error: Error) => void;
 25Ôćĺ  timer: ReturnType<typeof setTimeout>;
 26Ôćĺ  sessionId: string;
 27Ôćĺ  method: string;
 28Ôćĺ}
 29Ôćĺ
 30Ôćĺ// ---- Singleton State ----
 31Ôćĺ
 32Ôćĺconst pending = new Map<string, PendingRelay>();
 33Ôćĺ
 34Ôćĺ// ---- Public API ----
 35Ôćĺ
 36Ôćĺ/**
 37Ôćĺ * Relay a tool request from the agent to the frontend via WebSocket.
 38Ôćĺ *
 39Ôćĺ * Returns a promise that resolves when the frontend sends back q:tool_response,
 40Ôćĺ * or rejects if the timeout expires.
 41Ôćĺ *
 42Ôćĺ * The caller (agent-event-handler) uses the resolved value to send the result
 43Ôćĺ * back to the agent-server via agentClient.sendTurnRespond().
 44Ôćĺ */
 45Ôćĺexport function relay(event: ToolRequestEvent): Promise<unknown> {
 46Ôćĺ  const { requestId, sessionId, method, params, timeoutMs } = event;
 47Ôćĺ
 48Ôćĺ  // If there's already a pending request with this ID, reject the old one
 49Ôćĺ  // (shouldn't happen in practice, but prevents leaked promises)
 50Ôćĺ  const existing = pending.get(requestId);
 51Ôćĺ  if (existing) {
 52Ôćĺ    clearTimeout(existing.timer);
 53Ôćĺ    existing.reject(new Error(`Superseded by new relay for requestId=${requestId}`));
 54Ôćĺ    pending.delete(requestId);
 55Ôćĺ  }
 56Ôćĺ
 57Ôćĺ  return new Promise<unknown>((resolve, reject) => {
 58Ôćĺ    // Set timeout ÔÇö reject if frontend doesn't respond in time
 59Ôćĺ    const timer = setTimeout(() => {
 60Ôćĺ      pending.delete(requestId);
 61Ôćĺ      reject(new Error(`Tool relay timed out after ${timeoutMs}ms (requestId=${requestId}, method=${method})`));
 62Ôćĺ    }, timeoutMs);
 63Ôćĺ
 64Ôćĺ    // Store the pending relay
 65Ôćĺ    pending.set(requestId, { resolve, reject, timer, sessionId, method });
 66Ôćĺ
 67Ôćĺ    // Push q:event to all connected frontend clients
 68Ôćĺ    const eventData: ToolRequestEventData = {
 69Ôćĺ      requestId,
 70Ôćĺ      sessionId,
 71Ôćĺ      method,
 72Ôćĺ      params,
 73Ôćĺ      timeoutMs,
 74Ôćĺ    };
 75Ôćĺ
 76Ôćĺ    const frame: QServerFrame = {
 77Ôćĺ      type: "q:event",
 78Ôćĺ      event: "tool:request",
 79Ôćĺ      data: eventData,
 80Ôćĺ    };
 81Ôćĺ
 82Ôćĺ    broadcast(JSON.stringify(frame));
 83Ôćĺ  });
 84Ôćĺ}
 85Ôćĺ
 86Ôćĺ/**
 87Ôćĺ * Resolve a pending tool relay with the frontend's response.
 88Ôćĺ * Called when the query engine receives a q:tool_response frame with a result.
 89Ôćĺ */
 90Ôćĺexport function resolve(requestId: string, result: unknown): boolean {
 91Ôćĺ  const entry = pending.get(requestId);
 92Ôćĺ  if (!entry) return false;
 93Ôćĺ
 94Ôćĺ  clearTimeout(entry.timer);
 95Ôćĺ  pending.delete(requestId);
 96Ôćĺ  entry.resolve(result);
 97Ôćĺ  return true;
 98Ôćĺ}
