138Ôćĺ            ("linux", "x86_64", true) => Ok(Self::LinuxX64Musl),
139Ôćĺ            ("linux", "x86_64", false) => Ok(Self::LinuxX64),
140Ôćĺ            ("linux", "aarch64", _) => Ok(Self::LinuxArm64),
141Ôćĺ            ("macos", "aarch64", _) => Ok(Self::MacosArm64),
142Ôćĺ            ("macos", "x86_64", _) => Ok(Self::MacosX64),
143Ôćĺ            ("windows", "x86_64", _) => Ok(Self::WindowsX64),
144Ôćĺ            ("windows", "aarch64", _) => Ok(Self::WindowsArm64),
145Ôćĺ            _ => Err(AgentError::UnsupportedPlatform {
146Ôćĺ                os: os.to_string(),
