112Ôćĺ#[cfg(unix)]
113Ôćĺpub fn is_process_running(pid: u32) -> bool {
114Ôćĺ    let result = unsafe { libc::kill(pid as i32, 0) };
115Ôćĺ    if result == 0 {
116Ôćĺ        return true;
117Ôćĺ    }
118Ôćĺ    match std::io::Error::last_os_error().raw_os_error() {
119Ôćĺ        Some(code) if code == libc::EPERM => true,
120Ôćĺ        _ => false,
121Ôćĺ    }
122Ôćĺ}
123Ôćĺ
124Ôćĺ#[cfg(windows)]
125Ôćĺpub fn is_process_running(pid: u32) -> bool {
126Ôćĺ    use windows::Win32::Foundation::CloseHandle;
127Ôćĺ    use windows::Win32::System::Threading::{
128Ôćĺ        GetExitCodeProcess, OpenProcess, PROCESS_QUERY_LIMITED_INFORMATION,
129Ôćĺ    };
130Ôćĺ
131Ôćĺ    unsafe {
132Ôćĺ        let handle = match OpenProcess(PROCESS_QUERY_LIMITED_INFORMATION, false, pid) {
133Ôćĺ            Ok(h) => h,
134Ôćĺ            Err(_) => return false,
135Ôćĺ        };
136Ôćĺ        let mut exit_code = 0u32;
137Ôćĺ        let ok = GetExitCodeProcess(handle, &mut exit_code).is_ok();
138Ôćĺ        let _ = CloseHandle(handle);
139Ôćĺ        ok && exit_code == 259
140Ôćĺ    }
141Ôćĺ}
