147Ôćĺpub fn check_health(base_url: &str, token: Option<&str>) -> Result<bool, CliError> {
148Ôćĺ    let url = format!("{base_url}/v1/health");
149Ôćĺ    let started_at = Instant::now();
150Ôćĺ    let client = HttpClient::builder()
151Ôćĺ        .connect_timeout(HEALTH_CHECK_CONNECT_TIMEOUT)
152Ôćĺ        .timeout(HEALTH_CHECK_REQUEST_TIMEOUT)
153Ôćĺ        .build()?;
154Ôćĺ    let mut request = client.get(url);
155Ôćĺ    if let Some(token) = token {
156Ôćĺ        request = request.bearer_auth(token);
157Ôćĺ    }
158Ôćĺ    match request.send() {
159Ôćĺ        Ok(response) if response.status().is_success() => {
160Ôćĺ            tracing::info!(
161Ôćĺ                elapsed_ms = started_at.elapsed().as_millis(),
162Ôćĺ                "daemon health check succeeded"
163Ôćĺ            );
164Ôćĺ            Ok(true)
165Ôćĺ        }
166Ôćĺ        Ok(response) => {
167Ôćĺ            tracing::warn!(
168Ôćĺ                status = %response.status(),
169Ôćĺ                elapsed_ms = started_at.elapsed().as_millis(),
170Ôćĺ                "daemon health check returned non-success status"
171Ôćĺ            );
172Ôćĺ            Ok(false)
173Ôćĺ        }
174Ôćĺ        Err(err) => {
175Ôćĺ            tracing::warn!(
176Ôćĺ                error = %err,
177Ôćĺ                elapsed_ms = started_at.elapsed().as_millis(),
178Ôćĺ                "daemon health check request failed"
179Ôćĺ            );
180Ôćĺ            Ok(false)
181Ôćĺ        }
182Ôćĺ    }
183Ôćĺ}
