 53Ôćĺ/// communicating with agent subprocesses via the ACP stdio bridge.
 54Ôćĺpub trait AcpDispatch: Send + Sync + 'static {
 55Ôćĺ    /// Send a JSON-RPC payload to the agent process identified by `server_id`.
 56Ôćĺ    /// If the instance does not exist yet and `bootstrap_agent` is provided,
 57Ôćĺ    /// the implementation should create it for that agent.
