 61Ôćĺ        bootstrap_agent: Option<&str>,
 62Ôćĺ        payload: Value,
 63Ôćĺ    ) -> Pin<Box<dyn Future<Output = Result<AcpDispatchResult, String>> + Send + '_>>;
 64Ôćĺ
 65Ôćĺ    /// Open a stream of raw JSON-RPC notification payloads from the agent
 66Ôćĺ    /// process. Each item is a `serde_json::Value` containing a complete
 67Ôćĺ    /// JSON-RPC message (notification or response).
 68Ôćĺ    fn notification_stream(
