207Ôćĺ                    .await
208Ôćĺ                    .map_err(|err| err.to_string())?;
209Ôćĺ                sqlx::query("PRAGMA synchronous=NORMAL;")
210Ôćĺ                    .execute(pool)
211Ôćĺ                    .await
212Ôćĺ                    .map_err(|err| err.to_string())?;
213Ôćĺ
