132Ôćĺfunction resolveBinaryFromCliPackage(
133Ôćĺ  require: ReturnType<typeof import("node:module").createRequire>,
134Ôćĺ  path: typeof import("node:path"),
135Ôćĺ  fs: typeof import("node:fs"),
136Ôćĺ): string | null {
137Ôćĺ  const key = `${process.platform}-${process.arch}`;
138Ôćĺ  const pkg = PLATFORM_PACKAGES[key];
139Ôćĺ  if (!pkg) {
140Ôćĺ    return null;
141Ôćĺ  }
142Ôćĺ  try {
143Ôćĺ    const pkgPath = require.resolve(`${pkg}/package.json`);
144Ôćĺ    const bin = process.platform === "win32" ? "sandbox-agent.exe" : "sandbox-agent";
145Ôćĺ    const resolved = path.join(path.dirname(pkgPath), "bin", bin);
146Ôćĺ    return fs.existsSync(resolved) ? resolved : null;
147Ôćĺ  } catch {
148Ôćĺ    return null;
149Ôćĺ  }
150Ôćĺ}
