152Ôćĺfunction resolveBinaryFromPath(fs: typeof import("node:fs"), path: typeof import("node:path")): string | null {
153Ôćĺ  const pathEnv = process.env.PATH ?? "";
154Ôćĺ  const separator = process.platform === "win32" ? ";" : ":";
155Ôćĺ  const candidates = pathEnv.split(separator).filter(Boolean);
156Ôćĺ  const bin = process.platform === "win32" ? "sandbox-agent.exe" : "sandbox-agent";
157Ôćĺ  for (const dir of candidates) {
158Ôćĺ    const resolved = path.join(dir, bin);
159Ôćĺ    if (fs.existsSync(resolved)) {
160Ôćĺ      return resolved;
161Ôćĺ    }
162Ôćĺ  }
163Ôćĺ  return null;
164Ôćĺ}
