166Ôćĺasync function getFreePort(net: typeof import("node:net"), host: string): Promise<number> {
167Ôćĺ  return new Promise((resolve, reject) => {
168Ôćĺ    const server = net.createServer();
169Ôćĺ    server.unref();
170Ôćĺ    server.on("error", reject);
171Ôćĺ    server.listen(0, host, () => {
172Ôćĺ      const address = server.address() as AddressInfo;
173Ôćĺ      server.close(() => resolve(address.port));
174Ôćĺ    });
175Ôćĺ  });
176Ôćĺ}
