178Ôćĺasync function waitForHealth(baseUrl: string, fetcher: typeof fetch | undefined, timeoutMs: number, child: ChildProcess, token: string): Promise<void> {
179Ôćĺ  if (!fetcher) {
180Ôćĺ    throw new Error("Fetch API is not available; provide a fetch implementation.");
181Ôćĺ  }
182Ôćĺ  const start = Date.now();
183Ôćĺ  let lastError: string | undefined;
184Ôćĺ
185Ôćĺ  while (Date.now() - start < timeoutMs) {
186Ôćĺ    if (child.exitCode !== null) {
187Ôćĺ      throw new Error("sandbox-agent exited before becoming healthy.");
188Ôćĺ    }
189Ôćĺ    try {
190Ôćĺ      const response = await fetcher(`${baseUrl}/v1/health`, {
191Ôćĺ        headers: { Authorization: `Bearer ${token}` },
192Ôćĺ      });
193Ôćĺ      if (response.ok) {
194Ôćĺ        return;
195Ôćĺ      }
196Ôćĺ      lastError = `status ${response.status}`;
197Ôćĺ    } catch (err) {
198Ôćĺ      lastError = err instanceof Error ? err.message : String(err);
199Ôćĺ    }
200Ôćĺ    await new Promise((resolve) => setTimeout(resolve, 200));
201Ôćĺ  }
202Ôćĺ
203Ôćĺ  throw new Error(`Timed out waiting for sandbox-agent health (${lastError ?? "unknown error"}).`);
204Ôćĺ}
205Ôćĺ
206Ôćĺasync function waitForExit(child: ChildProcess, timeoutMs: number): Promise<boolean> {
207Ôćĺ  if (child.exitCode !== null) {
208Ôćĺ    return true;
209Ôćĺ  }
210Ôćĺ  return new Promise((resolve) => {
211Ôćĺ    const timer = setTimeout(() => resolve(false), timeoutMs);
212Ôćĺ    child.once("exit", () => {
213Ôćĺ      clearTimeout(timer);
214Ôćĺ      resolve(true);
215Ôćĺ    });
216Ôćĺ  });
217Ôćĺ}
218Ôćĺ
219Ôćĺfunction registerProcessCleanup(child: ChildProcess): { dispose: () => void } {
220Ôćĺ  const handler = () => {
221Ôćĺ    if (child.exitCode === null) {
222Ôćĺ      child.kill("SIGTERM");
223Ôćĺ    }
224Ôćĺ  };
225Ôćĺ
226Ôćĺ  process.once("exit", handler);
227Ôćĺ  process.once("SIGINT", handler);
228Ôćĺ  process.once("SIGTERM", handler);
229Ôćĺ
230Ôćĺ  return {
231Ôćĺ    dispose: () => {
232Ôćĺ      process.off("exit", handler);
233Ôćĺ      process.off("SIGINT", handler);
234Ôćĺ      process.off("SIGTERM", handler);
235Ôćĺ    },
236Ôćĺ  };
237Ôćĺ}
