133Ôćĺexport interface SessionPersistDriver {
134Ôćĺ  getSession(id: string): Promise<SessionRecord | null>;
135Ôćĺ  listSessions(request?: ListPageRequest): Promise<ListPage<SessionRecord>>;
136Ôćĺ  updateSession(session: SessionRecord): Promise<void>;
137Ôćĺ  listEvents(request: ListEventsRequest): Promise<ListPage<SessionEvent>>;
138Ôćĺ  insertEvent(event: SessionEvent): Promise<void>;
139Ôćĺ}
