14Ôćĺexport type FsSubset = {
15Ôćĺ  accessSync: (path: string, mode?: number) => void;
16Ôćĺ  chmodSync: (path: string, mode: number) => void;
17Ôćĺ  constants: { X_OK: number };
18Ôćĺ};
