20Ôćĺexport function isBunRuntime(): boolean {
21Ôćĺ  if (typeof process?.versions?.bun === "string") return true;
22Ôćĺ  const userAgent = process?.env?.npm_config_user_agent || "";
23Ôćĺ  return userAgent.includes("bun/");
24Ôćĺ}
