26Ôćĺconst PERMISSION_ERRORS = new Set(["EACCES", "EPERM", "ENOEXEC"]);
27Ôćĺ
28Ôćĺfunction isPermissionError(error: unknown): boolean {
29Ôćĺ  if (!error || typeof error !== "object") return false;
30Ôćĺ  const code = (error as { code?: unknown }).code;
31Ôćĺ  return typeof code === "string" && PERMISSION_ERRORS.has(code);
32Ôćĺ}
