34Ôćĺ/**
35Ôćĺ * Checks if a binary is executable and attempts to make it executable if not.
36Ôćĺ * Returns true if the binary is (or was made) executable, false if it couldn't
37Ôćĺ * be made executable due to permission errors. Throws for other errors.
38Ôćĺ *
39Ôćĺ * Requires fs to be passed in to avoid static imports that break browser builds.
40Ôćĺ */
41Ôćĺexport function assertExecutable(binPath: string, fs: FsSubset): boolean {
42Ôćĺ  if (process.platform === "win32") {
43Ôćĺ    return true;
44Ôćĺ  }
45Ôćĺ
46Ôćĺ  try {
47Ôćĺ    fs.accessSync(binPath, fs.constants.X_OK);
48Ôćĺ    return true;
49Ôćĺ  } catch {
50Ôćĺ    // Not executable, try to fix
51Ôćĺ  }
52Ôćĺ
53Ôćĺ  try {
54Ôćĺ    fs.chmodSync(binPath, 0o755);
55Ôćĺ    return true;
56Ôćĺ  } catch (error) {
57Ôćĺ    if (isPermissionError(error)) {
58Ôćĺ      return false;
59Ôćĺ    }
60Ôćĺ    throw error;
61Ôćĺ  }
62Ôćĺ}
63Ôćĺ
64Ôćĺexport function formatNonExecutableBinaryMessage(options: NonExecutableBinaryMessageOptions): string {
65Ôćĺ  const { binPath, trustPackages, bunInstallBlocks, genericInstallCommands, binaryName } = options;
66Ôćĺ
67Ôćĺ  const label = binaryName ?? "sandbox-agent";
68Ôćĺ  const lines = [`${label} binary is not executable: ${binPath}`];
69Ôćĺ
70Ôćĺ  if (isBunRuntime()) {
71Ôćĺ    lines.push("Allow Bun to run postinstall scripts for native binaries and reinstall:");
72Ôćĺ    for (const block of bunInstallBlocks) {
73Ôćĺ      lines.push(`${block.label}:`);
74Ôćĺ      for (const command of block.commands) {
75Ôćĺ        lines.push(`  ${command}`);
76Ôćĺ      }
77Ôćĺ    }
78Ôćĺ    lines.push(`Or run: chmod +x "${binPath}"`);
79Ôćĺ    return lines.join("\n");
80Ôćĺ  }
81Ôćĺ
82Ôćĺ  lines.push("Postinstall scripts for native packages did not run, so the binary was left non-executable.");
83Ôćĺ  if (genericInstallCommands && genericInstallCommands.length > 0) {
84Ôćĺ    lines.push("Reinstall with scripts enabled:");
85Ôćĺ    for (const command of genericInstallCommands) {
86Ôćĺ      lines.push(`  ${command}`);
87Ôćĺ    }
88Ôćĺ  } else {
89Ôćĺ    lines.push("Reinstall with scripts enabled for:");
90Ôćĺ    lines.push(`  ${trustPackages}`);
91Ôćĺ  }
92Ôćĺ  lines.push(`Or run: chmod +x "${binPath}"`);
93Ôćĺ  return lines.join("\n");
94Ôćĺ}
