548Ôćĺ      this.seenResponseIdOrder.push(responseId);
549Ôćĺ      if (this.seenResponseIdOrder.length > 2048) {
550Ôćĺ        const oldest = this.seenResponseIdOrder.shift();
551Ôćĺ        if (oldest) {
552Ôćĺ          this.seenResponseIds.delete(oldest);
553Ôćĺ        }
554Ôćĺ      }
555Ôćĺ    }
556Ôćĺ
557Ôćĺ    this.observeEnvelope(envelope, "inbound");
558Ôćĺ
559Ôćĺ    try {
560Ôćĺ      this.readableController?.enqueue(envelope);
561Ôćĺ    } catch (error) {
562Ôćĺ      this.failReadable(error);
563Ôćĺ    }
564Ôćĺ  }
565Ôćĺ
566Ôćĺ  private failReadable(error: unknown): void {
567Ôćĺ    if (this.closed) {
568Ôćĺ      return;
569Ôćĺ    }
570Ôćĺ
571Ôćĺ    this.closed = true;
572Ôćĺ
573Ôćĺ    try {
574Ôćĺ      this.readableController?.error(error);
575Ôćĺ    } catch {
576Ôćĺ      // no-op
577Ôćĺ    }
578Ôćĺ
579Ôćĺ    this.readableController = null;
580Ôćĺ
581Ôćĺ    if (this.sseAbortController) {
582Ôćĺ      this.sseAbortController.abort();
583Ôćĺ    }
584Ôćĺ  }
585Ôćĺ
586Ôćĺ  private observeEnvelope(message: AnyMessage, direction: AcpEnvelopeDirection): void {
587Ôćĺ    if (!this.onEnvelope) {
588Ôćĺ      return;
589Ôćĺ    }
590Ôćĺ
591Ôćĺ    this.onEnvelope(message, direction);
592Ôćĺ  }
593Ôćĺ
594Ôćĺ  private buildHeaders(extra?: HeadersInit): Headers {
595Ôćĺ    const headers = new Headers(this.defaultHeaders ?? undefined);
596Ôćĺ
597Ôćĺ    if (this.token) {
598Ôćĺ      headers.set("Authorization", `Bearer ${this.token}`);
599Ôćĺ    }
600Ôćĺ
601Ôćĺ    if (extra) {
602Ôćĺ      const merged = new Headers(extra);
603Ôćĺ      merged.forEach((value, key) => headers.set(key, value));
604Ôćĺ    }
605Ôćĺ
606Ôćĺ    return headers;
607Ôćĺ  }
608Ôćĺ
609Ôćĺ  private buildUrl(query?: URLSearchParams | null): string {
610Ôćĺ    const url = new URL(`${this.baseUrl}${this.path}`);
611Ôćĺ    if (query) {
612Ôćĺ      for (const [key, value] of query.entries()) {
613Ôćĺ        url.searchParams.set(key, value);
614Ôćĺ      }
615Ôćĺ    }
616Ôćĺ    return url.toString();
617Ôćĺ  }
618Ôćĺ
619Ôćĺ  private bootstrapQueryIfNeeded(): URLSearchParams | null {
620Ôćĺ    if (this.postedOnce || !this.bootstrapQuery || this.bootstrapQuery.size === 0) {
621Ôćĺ      return null;
622Ôćĺ    }
623Ôćĺ    return this.bootstrapQuery;
624Ôćĺ  }
625Ôćĺ}
626Ôćĺ
627Ôćĺfunction buildClientHandlers(client?: Partial<Client>): Client {
628Ôćĺ  const fallbackPermission: RequestPermissionResponse = {
629Ôćĺ    outcome: {
630Ôćĺ      outcome: "cancelled",
631Ôćĺ    } as RequestPermissionOutcome,
632Ôćĺ  };
633Ôćĺ
634Ôćĺ  return {
635Ôćĺ    requestPermission: async (request: RequestPermissionRequest) => {
636Ôćĺ      if (client?.requestPermission) {
637Ôćĺ        return client.requestPermission(request);
638Ôćĺ      }
639Ôćĺ      return fallbackPermission;
640Ôćĺ    },
641Ôćĺ    sessionUpdate: async (notification: SessionNotification) => {
642Ôćĺ      if (client?.sessionUpdate) {
643Ôćĺ        await client.sessionUpdate(notification);
644Ôćĺ      }
645Ôćĺ    },
646Ôćĺ    readTextFile: client?.readTextFile,
647Ôćĺ    writeTextFile: client?.writeTextFile,
648Ôćĺ    createTerminal: client?.createTerminal,
649Ôćĺ    terminalOutput: client?.terminalOutput,
650Ôćĺ    releaseTerminal: client?.releaseTerminal,
651Ôćĺ    waitForTerminalExit: client?.waitForTerminalExit,
652Ôćĺ    killTerminal: client?.killTerminal,
653Ôćĺ    extMethod: client?.extMethod,
654Ôćĺ    extNotification: async (method: string, params: Record<string, unknown>) => {
655Ôćĺ      if (client?.extNotification) {
656Ôćĺ        await client.extNotification(method, params);
657Ôćĺ      }
658Ôćĺ    },
659Ôćĺ  };
660Ôćĺ}
661Ôćĺ
662Ôćĺfunction responseEnvelopeId(message: AnyMessage): string | null {
663Ôćĺ  if (typeof message !== "object" || message === null) {
664Ôćĺ    return null;
665Ôćĺ  }
666Ôćĺ  const record = message as Record<string, unknown>;
667Ôćĺ  if ("method" in record) {
668Ôćĺ    return null;
669Ôćĺ  }
670Ôćĺ  if (!("result" in record) && !("error" in record)) {
671Ôćĺ    return null;
672Ôćĺ  }
673Ôćĺ  const id = record.id;
674Ôćĺ  if (id === null || id === undefined) {
675Ôćĺ    return null;
676Ôćĺ  }
677Ôćĺ  return String(id);
678Ôćĺ}
679Ôćĺ
680Ôćĺasync function readProblem(response: Response): Promise<ProblemDetails | undefined> {
681Ôćĺ  try {
682Ôćĺ    const text = await response.clone().text();
683Ôćĺ    if (!text) {
684Ôćĺ      return undefined;
685Ôćĺ    }
686Ôćĺ    return JSON.parse(text) as ProblemDetails;
687Ôćĺ  } catch {
688Ôćĺ    return undefined;
689Ôćĺ  }
690Ôćĺ}
691Ôćĺ
692Ôćĺfunction isAbortError(error: unknown): boolean {
693Ôćĺ  return error instanceof DOMException && error.name === "AbortError";
694Ôćĺ}
695Ôćĺ
696Ôćĺfunction delay(ms: number): Promise<void> {
697Ôćĺ  return new Promise((resolve) => setTimeout(resolve, ms));
698Ôćĺ}
699Ôćĺ
700Ôćĺfunction timeoutSignal(timeoutMs: number): AbortSignal | undefined {
701Ôćĺ  if (typeof AbortSignal !== "undefined" && typeof AbortSignal.timeout === "function") {
702Ôćĺ    return AbortSignal.timeout(timeoutMs);
703Ôćĺ  }
704Ôćĺ  return undefined;
705Ôćĺ}
706Ôćĺ
707Ôćĺfunction normalizePath(path: string): string {
708Ôćĺ  if (!path.startsWith("/")) {
709Ôćĺ    return `/${path}`;
710Ôćĺ  }
711Ôćĺ  return path;
712Ôćĺ}
713Ôćĺ
714Ôćĺfunction buildQueryParams(source: Record<string, QueryValue>): URLSearchParams {
715Ôćĺ  const params = new URLSearchParams();
716Ôćĺ  for (const [key, value] of Object.entries(source)) {
717Ôćĺ    if (value === undefined || value === null) {
718Ôćĺ      continue;
719Ôćĺ    }
720Ôćĺ    params.set(key, String(value));
721Ôćĺ  }
722Ôćĺ  return params;
723Ôćĺ}
