  3Ôćĺ//
  4Ôćĺ// Adapted from sidecar/db/session-writer.ts. Key differences:
  5Ôćĺ// - Uses backend's getDatabase() (not sidecar's)
  6Ôćĺ// - No notifyBackend() calls (backend handles WS push via invalidate())
  7Ôćĺ// - No FrontendClient calls (backend pushes via query-engine directly)
  8Ôćĺ// - Takes event objects instead of positional args
  9Ôćĺ//
 10Ôćĺ// All functions are synchronous (better-sqlite3 is synchronous).
 11Ôćĺ// Callers (agent-event-handler.ts) call invalidate() after persistence succeeds.
 12Ôćĺ
 13Ôćĺimport { getDatabase } from "../lib/database";
 14Ôćĺimport { uuidv7 } from "../../../shared/lib/uuid";
 15Ôćĺimport { getErrorMessage } from "../../../shared/lib/errors";
 16Ôćĺimport type {
 17Ôćĺ  MessageAssistantEvent,
 18Ôćĺ  MessageToolResultEvent,
 19Ôćĺ  MessageResultEvent,
 20Ôćĺ  MessageCancelledEvent,
 21Ôćĺ  SessionStartedEvent,
 22Ôćĺ  SessionIdleEvent,
