 28Ôćĺ// ============================================================================
 29Ôćĺ// WriteResult type (mirrors sidecar's pattern)
 30Ôćĺ// ============================================================================
 31Ôćĺ
 32Ôćĺexport type WriteResult<T = string> = { ok: true; value: T } | { ok: false; error: string };
 33Ôćĺ
 34Ôćĺ// ============================================================================
 35Ôćĺ// Message writes
 36Ôćĺ// ============================================================================
