 38Ôćĺ/**
 39Ôćĺ * Save an assistant message to the messages table.
 40Ôćĺ * Mirrors sidecar saveAssistantMessage() logic:
 41Ôćĺ * - Generates a local UUID7 message ID
 42Ôćĺ * - Stores flat content array, except for cancelled messages which get an envelope
 43Ôćĺ * - Records the agent_message_id and parent_tool_use_id for linking
 44Ôćĺ */
 45Ôćĺexport function persistAssistantMessage(event: MessageAssistantEvent): WriteResult {
 46Ôćĺ  const db = getDatabase();
 47Ôćĺ  const messageId = uuidv7();
 48Ôćĺ  const sentAt = new Date().toISOString();
 49Ôćĺ
 50Ôćĺ  // Store flat content array for normal messages. For "cancelled" messages,
 51Ôćĺ  // write envelope so the frontend can detect cancellation from DB content.
 52Ôćĺ  const contentPayload =
 53Ôćĺ    event.message.stop_reason === "cancelled"
 54Ôćĺ      ? { message: { stop_reason: "cancelled" }, blocks: event.message.content ?? [] }
 55Ôćĺ      : (event.message.content ?? []);
 56Ôćĺ  const content = JSON.stringify(contentPayload);
 57Ôćĺ
 58Ôćĺ  try {
 59Ôćĺ    db.prepare(
 60Ôćĺ      `INSERT INTO messages (id, session_id, role, content, sent_at, model, agent_message_id, parent_tool_use_id)
 61Ôćĺ       VALUES (?, ?, 'assistant', ?, ?, ?, ?, ?)`
 62Ôćĺ    ).run(
 63Ôćĺ      messageId,
 64Ôćĺ      event.sessionId,
 65Ôćĺ      content,
 66Ôćĺ      sentAt,
 67Ôćĺ      event.model || null,
 68Ôćĺ      event.message.id || null,
 69Ôćĺ      event.message.parent_tool_use_id || null
 70Ôćĺ    );
 71Ôćĺ    return { ok: true, value: messageId };
 72Ôćĺ  } catch (error) {
 73Ôćĺ    const msg = getErrorMessage(error);
 74Ôćĺ    console.error(`[AgentPersistence] Failed to save assistant message:`, msg);
 75Ôćĺ    return { ok: false, error: msg };
 76Ôćĺ  }
 77Ôćĺ}
