 92Ôćĺ       VALUES (?, ?, 'user', ?, ?, ?, ?)`
 93Ôćĺ    ).run(
 94Ôćĺ      messageId,
 95Ôćĺ      event.sessionId,
 96Ôćĺ      content,
 97Ôćĺ      sentAt,
 98Ôćĺ      event.message.id || null,
 99Ôćĺ      event.message.parent_tool_use_id || null
100Ôćĺ    );
101Ôćĺ    return { ok: true, value: messageId };
102Ôćĺ  } catch (error) {
