119Ôćĺ/**
120Ôćĺ * Persist a cancellation: insert a cancelled assistant message marker
121Ôćĺ * and set session status to idle.
122Ôćĺ *
123Ôćĺ * The cancelled message uses the envelope format so the frontend can detect
124Ôćĺ * cancellation on reload (the "Turn interrupted" label in AssistantTurn).
125Ôćĺ */
126Ôćĺexport function persistMessageCancelled(event: MessageCancelledEvent): WriteResult {
127Ôćĺ  const db = getDatabase();
128Ôćĺ  const messageId = uuidv7();
129Ôćĺ  const sentAt = new Date().toISOString();
130Ôćĺ
131Ôćĺ  // Empty cancelled message with envelope so frontend detects cancellation
132Ôćĺ  const content = JSON.stringify({
133Ôćĺ    message: { stop_reason: "cancelled" },
134Ôćĺ    blocks: [],
135Ôćĺ  });
136Ôćĺ
137Ôćĺ  try {
138Ôćĺ    db.transaction(() => {
139Ôćĺ      db.prepare(
140Ôćĺ        `INSERT INTO messages (id, session_id, role, content, sent_at, cancelled_at)
141Ôćĺ         VALUES (?, ?, 'assistant', ?, ?, ?)`
142Ôćĺ      ).run(messageId, event.sessionId, content, sentAt, sentAt);
143Ôćĺ
144Ôćĺ      db.prepare(
145Ôćĺ        `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
146Ôćĺ      ).run(event.sessionId);
147Ôćĺ    })();
148Ôćĺ
149Ôćĺ    return { ok: true, value: messageId };
150Ôćĺ  } catch (error) {
151Ôćĺ    const msg = getErrorMessage(error);
152Ôćĺ    console.error(`[AgentPersistence] Failed to persist message.cancelled:`, msg);
153Ôćĺ    return { ok: false, error: msg };
154Ôćĺ  }
155Ôćĺ}
