181Ôćĺ/** Update session status to "idle" when a turn completes. */
182Ôćĺexport function persistSessionIdle(event: SessionIdleEvent): WriteResult<void> {
183Ôćĺ  const db = getDatabase();
184Ôćĺ
185Ôćĺ  try {
