  2Ôćĺuse std::time::Duration;
  3Ôćĺ
  4Ôćĺuse axum::extract::State;
  5Ôćĺuse axum::http::{header, HeaderMap, StatusCode};
  6Ôćĺuse axum::response::sse::KeepAlive;
  7Ôćĺuse axum::response::{IntoResponse, Response, Sse};
  8Ôćĺuse axum::routing::{get, post};
  9Ôćĺuse axum::{Json, Router};
 10Ôćĺuse serde::Serialize;
 11Ôćĺuse serde_json::{json, Value};
 12Ôćĺ
 13Ôćĺuse crate::process::{AdapterError, AdapterRuntime, PostOutcome};
 14Ôćĺ
 15Ôćĺ#[derive(Debug, Serialize)]
 16Ôćĺstruct HealthResponse {
 17Ôćĺ    ok: bool,
 18Ôćĺ}
 19Ôćĺ
 20Ôćĺ#[derive(Debug, Serialize)]
 21Ôćĺstruct Problem {
 22Ôćĺ    r#type: &'static str,
 23Ôćĺ    title: &'static str,
 24Ôćĺ    status: u16,
 25Ôćĺ    detail: String,
 26Ôćĺ}
 27Ôćĺ
 28Ôćĺpub fn build_router(runtime: Arc<AdapterRuntime>) -> Router {
 29Ôćĺ    Router::new()
 30Ôćĺ        .route("/v1/health", get(get_health))
 31Ôćĺ        .route("/v1/rpc", post(post_rpc).get(get_rpc).delete(delete_rpc))
 32Ôćĺ        .with_state(runtime)
 33Ôćĺ}
 34Ôćĺ
 35Ôćĺasync fn get_health() -> Json<HealthResponse> {
 36Ôćĺ    Json(HealthResponse { ok: true })
 37Ôćĺ}
 38Ôćĺ
 39Ôćĺasync fn post_rpc(
 40Ôćĺ    State(runtime): State<Arc<AdapterRuntime>>,
 41Ôćĺ    headers: HeaderMap,
 42Ôćĺ    Json(payload): Json<Value>,
 43Ôćĺ) -> Response {
 44Ôćĺ    if !is_json_content_type(&headers) {
 45Ôćĺ        return problem(
 46Ôćĺ            StatusCode::UNSUPPORTED_MEDIA_TYPE,
 47Ôćĺ            "unsupported_media_type",
 48Ôćĺ            "content-type must be application/json",
 49Ôćĺ        );
 50Ôćĺ    }
 51Ôćĺ
 52Ôćĺ    match runtime.post(payload).await {
 53Ôćĺ        Ok(PostOutcome::Response(value)) => (StatusCode::OK, Json(value)).into_response(),
 54Ôćĺ        Ok(PostOutcome::Accepted) => StatusCode::ACCEPTED.into_response(),
 55Ôćĺ        Err(err) => map_error(err),
 56Ôćĺ    }
 57Ôćĺ}
 58Ôćĺ
 59Ôćĺasync fn get_rpc(
 60Ôćĺ    State(runtime): State<Arc<AdapterRuntime>>,
 61Ôćĺ    headers: HeaderMap,
 62Ôćĺ) -> impl IntoResponse {
 63Ôćĺ    let last_event_id = headers
 64Ôćĺ        .get("last-event-id")
 65Ôćĺ        .and_then(|value| value.to_str().ok())
 66Ôćĺ        .and_then(|value| value.parse::<u64>().ok());
 67Ôćĺ
 68Ôćĺ    let stream = runtime.clone().sse_stream(last_event_id).await;
 69Ôćĺ    Sse::new(stream).keep_alive(KeepAlive::new().interval(Duration::from_secs(15)))
 70Ôćĺ}
 71Ôćĺ
 72Ôćĺasync fn delete_rpc() -> StatusCode {
 73Ôćĺ    StatusCode::NO_CONTENT
 74Ôćĺ}
 75Ôćĺ
 76Ôćĺfn is_json_content_type(headers: &HeaderMap) -> bool {
 77Ôćĺ    headers
 78Ôćĺ        .get(header::CONTENT_TYPE)
 79Ôćĺ        .and_then(|value| value.to_str().ok())
 80Ôćĺ        .map(|value| value.starts_with("application/json"))
 81Ôćĺ        .unwrap_or(false)
 82Ôćĺ}
 83Ôćĺ
 84Ôćĺfn map_error(err: AdapterError) -> Response {
 85Ôćĺ    match err {
 86Ôćĺ        AdapterError::InvalidEnvelope => problem(
 87Ôćĺ            StatusCode::BAD_REQUEST,
 88Ôćĺ            "invalid_envelope",
 89Ôćĺ            "request body must be a JSON-RPC object",
 90Ôćĺ        ),
 91Ôćĺ        AdapterError::Timeout => problem(
 92Ôćĺ            StatusCode::GATEWAY_TIMEOUT,
 93Ôćĺ            "timeout",
 94Ôćĺ            "timed out waiting for agent response",
 95Ôćĺ        ),
 96Ôćĺ        AdapterError::Exited { exit_code, stderr } => {
 97Ôćĺ            let detail = if let Some(stderr) = stderr {
 98Ôćĺ                format!(
 99Ôćĺ                    "agent process exited before responding (exit_code: {:?}, stderr: {})",
100Ôćĺ                    exit_code, stderr
101Ôćĺ                )
102Ôćĺ            } else {
103Ôćĺ                format!(
104Ôćĺ                    "agent process exited before responding (exit_code: {:?})",
105Ôćĺ                    exit_code
106Ôćĺ                )
107Ôćĺ            };
108Ôćĺ            problem(StatusCode::BAD_GATEWAY, "agent_exited", &detail)
109Ôćĺ        }
110Ôćĺ        AdapterError::Write(write) => problem(
111Ôćĺ            StatusCode::BAD_GATEWAY,
112Ôćĺ            "write_failed",
113Ôćĺ            &format!("failed writing to agent stdin: {write}"),
114Ôćĺ        ),
115Ôćĺ        AdapterError::Serialize(ser) => problem(
116Ôćĺ            StatusCode::BAD_REQUEST,
117Ôćĺ            "serialize_failed",
118Ôćĺ            &format!("failed to serialize JSON payload: {ser}"),
119Ôćĺ        ),
120Ôćĺ        AdapterError::Spawn(spawn) => problem(
121Ôćĺ            StatusCode::BAD_GATEWAY,
122Ôćĺ            "spawn_failed",
123Ôćĺ            &format!("failed to start agent process: {spawn}"),
124Ôćĺ        ),
125Ôćĺ        AdapterError::MissingStdin | AdapterError::MissingStdout | AdapterError::MissingStderr => {
126Ôćĺ            problem(
127Ôćĺ                StatusCode::BAD_GATEWAY,
128Ôćĺ                "io_setup_failed",
129Ôćĺ                "agent subprocess pipes were not available",
130Ôćĺ            )
131Ôćĺ        }
132Ôćĺ    }
133Ôćĺ}
134Ôćĺ
135Ôćĺfn problem(status: StatusCode, title: &'static str, detail: &str) -> Response {
136Ôćĺ    (
137Ôćĺ        status,
138Ôćĺ        Json(json!(Problem {
139Ôćĺ            r#type: "about:blank",
140Ôćĺ            title,
141Ôćĺ            status: status.as_u16(),
142Ôćĺ            detail: detail.to_string(),
143Ôćĺ        })),
144Ôćĺ    )
145Ôćĺ        .into_response()
146Ôćĺ}
