164Ôćĺexport function parseBody<T extends z.ZodType>(schema: T, data: unknown): z.infer<T> {
165Ôćĺ  const result = schema.safeParse(data);
166Ôćĺ  if (!result.success) {
167Ôćĺ    const messages = result.error.issues.map((i) => {
168Ôćĺ      const path = i.path.length > 0 ? `${i.path.join('.')}: ` : '';
169Ôćĺ      return `${path}${i.message}`;
