 69Ôćĺ/**
 70Ôćĺ * Subscribe to per-session working status for multiple sessions at once.
 71Ôćĺ * Used by the tab bar to show per-tab spinners correctly.
 72Ôćĺ *
 73Ôćĺ * The workspace's single `session_status` field breaks with multiple tabs ÔÇö
 74Ôćĺ * it gets overwritten by whichever session's event fires last. This hook
 75Ôćĺ * subscribes to each session's detail cache reactively so tab spinners
 76Ôćĺ * reflect each session's actual status.
 77Ôćĺ *
 78Ôćĺ * No extra HTTP fetches when data is already in cache (populated by
 79Ôćĺ * the "session" WS subscription via q:snapshot on status changes).
 80Ôćĺ */
 81Ôćĺexport function useWorkingSessionIds(sessionIds: string[]): Set<string> {
 82Ôćĺ  const queries = useQueries({
 83Ôćĺ    queries: sessionIds.map((id) => ({
 84Ôćĺ      queryKey: queryKeys.sessions.detail(id),
 85Ôćĺ      queryFn: () => SessionService.fetchById(id),
 86Ôćĺ      staleTime: 30_000,
 87Ôćĺ      select: (data: Session): SessionStatus => data.status,
 88Ôćĺ    })),
 89Ôćĺ  });
 90Ôćĺ
 91Ôćĺ  // Derive working IDs from query results. useMemo deps use `queries`
 92Ôćĺ  // directly ÔÇö React Compiler requires it. The select: data.status
 93Ôćĺ  // ensures queries only change identity when a status actually changes.
 94Ôćĺ  return useMemo(() => {
 95Ôćĺ    const ids = new Set<string>();
 96Ôćĺ    sessionIds.forEach((id, i) => {
 97Ôćĺ      if (queries[i]?.data === "working") ids.add(id);
 98Ôćĺ    });
 99Ôćĺ    return ids;
100Ôćĺ  }, [queries, sessionIds]);
101Ôćĺ}
102Ôćĺ
103Ôćĺ/**
104Ôćĺ * Fetch messages for a session ÔÇö fully WS-driven.
105Ôćĺ *
106Ôćĺ * WS subscription pushes q:delta frames with new messages since last cursor.
107Ôćĺ * mergeMessageDelta handles the PaginatedMessages shape, deduplication,
108Ôćĺ * and optimistic placeholder cleanup.
109Ôćĺ * HTTP queryFn is fallback for initial load before WS connects.
110Ôćĺ */
111Ôćĺexport function useMessages(sessionId: string | null) {
112Ôćĺ  useQuerySubscription("messages", {
113Ôćĺ    queryKey: queryKeys.sessions.messages(sessionId || ""),
114Ôćĺ    params: { sessionId: sessionId || "" },
115Ôćĺ    enabled: !!sessionId,
116Ôćĺ    mergeDelta: mergeMessageDelta,
117Ôćĺ  });
118Ôćĺ
119Ôćĺ  const query = useQuery({
120Ôćĺ    queryKey: queryKeys.sessions.messages(sessionId || ""),
121Ôćĺ    queryFn: () => SessionService.fetchMessages(sessionId!, { limit: INITIAL_MESSAGE_PAGE_SIZE }),
122Ôćĺ    enabled: !!sessionId,
123Ôćĺ    refetchInterval: false,
124Ôćĺ    staleTime: Infinity,
125Ôćĺ    refetchOnWindowFocus: false,
126Ôćĺ  });
127Ôćĺ
128Ôćĺ  return query;
129Ôćĺ}
