131Ôćĺ/**
132Ôćĺ * Combined hook for session + messages + status
133Ôćĺ * Replaces the complex useMessages hook
134Ôćĺ */
135Ôćĺexport function useSessionWithMessages(sessionId: string | null) {
136Ôćĺ  const sessionQuery = useSession(sessionId);
137Ôćĺ  const messagesQuery = useMessages(sessionId);
138Ôćĺ
139Ôćĺ  // Unwrap messages from PaginatedMessages (select was removed to expose has_older)
140Ôćĺ  const messages = messagesQuery.data?.messages ?? [];
141Ôćĺ  const hasOlder = messagesQuery.data?.has_older ?? false;
142Ôćĺ
143Ôćĺ  // Parse content helper ÔÇö delegates to pure function in lib/contentParser.ts
144Ôćĺ  // Memoized to prevent Context cascade re-renders
145Ôćĺ  const parseContent = useCallback(
146Ôćĺ    (content: string): (ContentBlock | string)[] | string => parseContentBlocks(content),
147Ôćĺ    []
148Ôćĺ  );
149Ôćĺ
150Ôćĺ  // Build tool result map and parent_tool_use_id map in a single pass.
151Ôćĺ  const { toolResultMap, parentToolUseMap } = useMemo(() => {
152Ôćĺ    const resultMap = new Map();
153Ôćĺ    const parentMap = new Map<string, string>();
154Ôćĺ    if (!messages.length) return { toolResultMap: resultMap, parentToolUseMap: parentMap };
155Ôćĺ
156Ôćĺ    messages.forEach((msg: Message) => {
157Ôćĺ      if (msg.parent_tool_use_id) {
158Ôćĺ        parentMap.set(msg.id, msg.parent_tool_use_id);
159Ôćĺ      }
160Ôćĺ
161Ôćĺ      const blocks = parseContent(msg.content);
162Ôćĺ      if (Array.isArray(blocks)) {
163Ôćĺ        blocks.filter(isToolResultBlock).forEach((block) => {
164Ôćĺ          resultMap.set(block.tool_use_id, block);
165Ôćĺ        });
166Ôćĺ      }
167Ôćĺ    });
168Ôćĺ
169Ôćĺ    return { toolResultMap: resultMap, parentToolUseMap: parentMap };
170Ôćĺ  }, [messages, parseContent]);
171Ôćĺ
172Ôćĺ  // Group subagent messages by their parent Task tool_use_id
173Ôćĺ  const subagentMessages = useMemo(() => {
174Ôćĺ    const map = new Map<string, Message[]>();
175Ôćĺ    if (!messages.length) return map;
176Ôćĺ
177Ôćĺ    messages.forEach((msg: Message) => {
178Ôćĺ      const parentId = parentToolUseMap.get(msg.id);
179Ôćĺ      if (parentId) {
180Ôćĺ        if (!map.has(parentId)) map.set(parentId, []);
181Ôćĺ        map.get(parentId)!.push(msg);
182Ôćĺ      }
183Ôćĺ    });
184Ôćĺ
185Ôćĺ    return map;
186Ôćĺ  }, [messages, parentToolUseMap]);
187Ôćĺ
188Ôćĺ  // Get latest user message's sent_at for duration tracking
189Ôćĺ  const latestMessageSentAt = useMemo(() => {
190Ôćĺ    if (!messages.length) return null;
191Ôćĺ
192Ôćĺ    // Find the latest user message
193Ôćĺ    const latestUserMessage = [...messages].reverse().find((msg: Message) => msg.role === "user");
194Ôćĺ
195Ôćĺ    return latestUserMessage?.sent_at || null;
196Ôćĺ  }, [messages]);
197Ôćĺ
198Ôćĺ  return {
199Ôćĺ    session: sessionQuery.data,
200Ôćĺ    messages,
201Ôćĺ    hasOlder,
202Ôćĺ    sessionStatus: (sessionQuery.data?.status as SessionStatus) || "idle",
203Ôćĺ    latestMessageSentAt,
204Ôćĺ    loading: sessionQuery.isLoading || messagesQuery.isLoading,
205Ôćĺ    error: sessionQuery.error || messagesQuery.error,
206Ôćĺ    parseContent,
207Ôćĺ    toolResultMap,
208Ôćĺ    parentToolUseMap,
209Ôćĺ    subagentMessages,
210Ôćĺ  };
211Ôćĺ}
