213Ôćĺ/**
214Ôćĺ * Load older messages (scroll-up pagination).
215Ôćĺ * Prepends older messages to the cache while preserving has_newer from current cache.
216Ôćĺ */
217Ôćĺexport function useLoadOlderMessages() {
218Ôćĺ  const queryClient = useQueryClient();
219Ôćĺ
220Ôćĺ  return useMutation({
221Ôćĺ    mutationFn: ({ sessionId, beforeSeq }: { sessionId: string; beforeSeq: number }) =>
222Ôćĺ      SessionService.fetchMessages(sessionId, { before: beforeSeq, limit: MESSAGE_PAGE_SIZE }),
223Ôćĺ
224Ôćĺ    onSuccess: (olderPage, { sessionId }) => {
225Ôćĺ      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
226Ôćĺ        if (!old) return olderPage;
227Ôćĺ        // Deduplicate by id (shouldn't happen, but safety first)
228Ôćĺ        const existingIds = new Set(old.messages.map((m) => m.id));
229Ôćĺ        const newMessages = olderPage.messages.filter((m) => !existingIds.has(m.id));
230Ôćĺ        return {
231Ôćĺ          messages: [...newMessages, ...old.messages],
232Ôćĺ          has_older: olderPage.has_older,
233Ôćĺ          has_newer: old.has_newer,
234Ôćĺ        };
235Ôćĺ      });
236Ôćĺ    },
237Ôćĺ  });
238Ôćĺ}
