240Ôćĺ/**
241Ôćĺ * Send message mutation with optimistic update
242Ôćĺ *
243Ôćĺ * Shows user message immediately in the chat while request is in flight.
244Ôćĺ * The optimistic message has a temporary ID that gets replaced on refetch.
245Ôćĺ */
246Ôćĺexport function useSendMessage() {
247Ôćĺ  const queryClient = useQueryClient();
248Ôćĺ
249Ôćĺ  return useMutation({
250Ôćĺ    mutationFn: async ({
251Ôćĺ      sessionId,
252Ôćĺ      content,
253Ôćĺ      model,
254Ôćĺ      cwd,
255Ôćĺ      agentType,
256Ôćĺ    }: {
257Ôćĺ      sessionId: string;
258Ôćĺ      content: string;
259Ôćĺ      model?: string;
260Ôćĺ      cwd?: string;
261Ôćĺ      agentType?: RuntimeAgentType;
262Ôćĺ    }): Promise<Message | void> => {
263Ôćĺ      // Send message via WS command: backend saves user message to DB,
264Ôćĺ      // forwards to agent-server, and pushes q:delta to subscribers.
265Ôćĺ      if (cwd) {
266Ôćĺ        if (!isConnected()) await connect();
267Ôćĺ        const ack = await sendCommand("sendMessage", {
268Ôćĺ          sessionId,
269Ôćĺ          content,
270Ôćĺ          model,
271Ôćĺ          cwd,
272Ôćĺ          agentType: agentType || "claude",
273Ôćĺ        });
274Ôćĺ        if (!ack.accepted) {
275Ôćĺ          throw new Error(ack.error || "Agent rejected the query");
276Ôćĺ        }
277Ôćĺ        // No return value needed ÔÇö WS q:delta handles message reconciliation.
278Ôćĺ        return;
279Ôćĺ      }
280Ôćĺ      // Gateway/web fallback: HTTP POST to backend
281Ôćĺ      return SessionService.sendMessage(sessionId, content, model);
282Ôćĺ    },
283Ôćĺ
284Ôćĺ    // Optimistic update: show user message immediately.
285Ôćĺ    // Status indicators (tab spinner, sidebar) are updated by the workspaces
286Ôćĺ    // WS subscription ÔÇö the sidecar notifies the backend, which pushes fresh
287Ôćĺ    // workspace snapshots within ~50ms.
288Ôćĺ    onMutate: async ({ sessionId, content, model }) => {
289Ôćĺ      await queryClient.cancelQueries({
290Ôćĺ        queryKey: queryKeys.sessions.messages(sessionId),
291Ôćĺ      });
292Ôćĺ
293Ôćĺ      const previousMessages = queryClient.getQueryData<PaginatedMessages>(
294Ôćĺ        queryKeys.sessions.messages(sessionId)
295Ôćĺ      );
296Ôćĺ
297Ôćĺ      // Snapshot workspace-by-repo cache before optimistic update so we can
298Ôćĺ      // restore the exact prior status on error (instead of hardcoding "idle").
299Ôćĺ      const previousWorkspaceByRepo = queryClient.getQueriesData<RepoGroup[]>({
300Ôćĺ        queryKey: ["workspaces", "by-repo"],
301Ôćĺ      });
302Ôćĺ
303Ôćĺ      // Create optimistic user message
304Ôćĺ      const optimisticId =
305Ôćĺ        typeof crypto !== "undefined" && "randomUUID" in crypto
306Ôćĺ          ? `optimistic-${crypto.randomUUID()}`
307Ôćĺ          : `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
308Ôćĺ
309Ôćĺ      // Content may be plain text or a JSON-stringified content blocks array (when images attached).
310Ôćĺ      let optimisticContentJson: string;
311Ôćĺ      try {
312Ôćĺ        const parsed = JSON.parse(content);
313Ôćĺ        if (Array.isArray(parsed)) {
314Ôćĺ          optimisticContentJson = JSON.stringify(parsed);
315Ôćĺ        } else {
316Ôćĺ          optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
317Ôćĺ        }
318Ôćĺ      } catch {
319Ôćĺ        optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
320Ôćĺ      }
321Ôćĺ
322Ôćĺ      const optimisticMessage: Message = {
323Ôćĺ        id: optimisticId,
324Ôćĺ        session_id: sessionId,
325Ôćĺ        seq: Number.MAX_SAFE_INTEGER,
326Ôćĺ        role: "user",
327Ôćĺ        content: optimisticContentJson,
328Ôćĺ        sent_at: new Date().toISOString(),
329Ôćĺ        model: model ?? null,
330Ôćĺ      };
331Ôćĺ
332Ôćĺ      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
333Ôćĺ        if (!old) return { messages: [optimisticMessage], has_older: false, has_newer: false };
334Ôćĺ        return produce(old, (draft) => {
335Ôćĺ          draft.messages.push(optimisticMessage);
336Ôćĺ        });
337Ôćĺ      });
338Ôćĺ
339Ôćĺ      // Optimistically set workspace status to "working" in sidebar cache.
340Ôćĺ      // Handles the startup race where the first Tauri event arrives before
341Ôćĺ      // the workspace list has loaded (cache empty Ôćĺ event matching fails).
342Ôćĺ      queryClient.setQueriesData<RepoGroup[]>({ queryKey: ["workspaces", "by-repo"] }, (old) => {
343Ôćĺ        if (!old) return old;
344Ôćĺ        return old.map((group) => ({
345Ôćĺ          ...group,
346Ôćĺ          workspaces: group.workspaces.map((ws) =>
347Ôćĺ            ws.current_session_id === sessionId
348Ôćĺ              ? { ...ws, session_status: "working" as SessionStatus }
349Ôćĺ              : ws
350Ôćĺ          ),
351Ôćĺ        }));
352Ôćĺ      });
353Ôćĺ
354Ôćĺ      return { previousMessages, previousWorkspaceByRepo };
355Ôćĺ    },
356Ôćĺ
357Ôćĺ    onError: (_err, variables, context) => {
358Ôćĺ      // Roll back optimistic message
359Ôćĺ      if (context?.previousMessages) {
360Ôćĺ        queryClient.setQueryData(
361Ôćĺ          queryKeys.sessions.messages(variables.sessionId),
362Ôćĺ          context.previousMessages
363Ôćĺ        );
364Ôćĺ      } else {
365Ôćĺ        // No snapshot (first send on empty cache) ÔÇö invalidate to clear the ghost optimistic message
366Ôćĺ        queryClient.invalidateQueries({
367Ôćĺ          queryKey: queryKeys.sessions.messages(variables.sessionId),
368Ôćĺ        });
369Ôćĺ      }
370Ôćĺ      // Roll back optimistic workspace status from snapshot
371Ôćĺ      if (context?.previousWorkspaceByRepo?.length) {
372Ôćĺ        context.previousWorkspaceByRepo.forEach(([key, data]) => {
373Ôćĺ          queryClient.setQueryData(key, data);
374Ôćĺ        });
375Ôćĺ      } else {
376Ôćĺ        queryClient.invalidateQueries({ queryKey: ["workspaces", "by-repo"] });
377Ôćĺ      }
378Ôćĺ    },
379Ôćĺ
380Ôćĺ    onSettled: async (_, error, variables) => {
381Ôćĺ      if (!error) {
382Ôćĺ        const hasImages = (() => {
383Ôćĺ          try {
384Ôćĺ            const parsed = JSON.parse(variables.content);
385Ôćĺ            return (
386Ôćĺ              Array.isArray(parsed) && parsed.some((b: { type?: string }) => b.type === "image")
387Ôćĺ            );
388Ôćĺ          } catch {
389Ôćĺ            return false;
390Ôćĺ          }
391Ôćĺ        })();
392Ôćĺ        const session = queryClient.getQueryData<Session>(
393Ôćĺ          queryKeys.sessions.detail(variables.sessionId)
394Ôćĺ        );
395Ôćĺ        track("session_message_sent", {
396Ôćĺ          session_id: variables.sessionId,
397Ôćĺ          has_images: hasImages,
398Ôćĺ          model: variables.model,
399Ôćĺ          agent_type: session?.agent_type,
400Ôćĺ          message_count: session?.message_count,
401Ôćĺ          context_used_percent: session?.context_used_percent,
402Ôćĺ        });
403Ôćĺ      }
404Ôćĺ      // No incrementalFetchAndMerge needed ÔÇö WS q:delta handles reconciliation.
405Ôćĺ      // The optimistic message stays visible until the delta arrives with the real message.
406Ôćĺ    },
407Ôćĺ  });
408Ôćĺ}
