 73Ôćĺimpl AdapterRuntime {
 74Ôćĺ    pub async fn start(
 75Ôćĺ        launch: LaunchSpec,
 76Ôćĺ        request_timeout: Duration,
 77Ôćĺ    ) -> Result<Self, AdapterError> {
 78Ôćĺ        let spawn_start = Instant::now();
 79Ôćĺ
 80Ôćĺ        let mut command = Command::new(&launch.program);
 81Ôćĺ        command
 82Ôćĺ            .args(&launch.args)
 83Ôćĺ            .stdin(std::process::Stdio::piped())
 84Ôćĺ            .stdout(std::process::Stdio::piped())
 85Ôćĺ            .stderr(std::process::Stdio::piped());
 86Ôćĺ
 87Ôćĺ        for (key, value) in &launch.env {
 88Ôćĺ            command.env(key, value);
 89Ôćĺ        }
 90Ôćĺ
 91Ôćĺ        tracing::info!(
 92Ôćĺ            program = ?launch.program,
 93Ôćĺ            args = ?launch.args,
 94Ôćĺ            "spawning agent process"
 95Ôćĺ        );
 96Ôćĺ
 97Ôćĺ        let mut child = command.spawn().map_err(|err| {
 98Ôćĺ            tracing::error!(
 99Ôćĺ                program = ?launch.program,
100Ôćĺ                error = %err,
101Ôćĺ                "failed to spawn agent process"
102Ôćĺ            );
103Ôćĺ            AdapterError::Spawn(err)
