105Ôćĺ
106Ôćĺ        let pid = child.id().unwrap_or(0);
107Ôćĺ        let spawn_elapsed = spawn_start.elapsed();
108Ôćĺ        tracing::info!(
109Ôćĺ            pid = pid,
110Ôćĺ            elapsed_ms = spawn_elapsed.as_millis() as u64,
111Ôćĺ            "agent process spawned"
