116Ôćĺ        let stderr = child.stderr.take().ok_or(AdapterError::MissingStderr)?;
117Ôćĺ
118Ôćĺ        let (sender, _rx) = broadcast::channel(512);
119Ôćĺ        let runtime = Self {
120Ôćĺ            stdin: Arc::new(Mutex::new(stdin)),
121Ôćĺ            child: Arc::new(Mutex::new(child)),
122Ôćĺ            pending: Arc::new(Mutex::new(HashMap::new())),
123Ôćĺ            sender,
124Ôćĺ            ring: Arc::new(Mutex::new(VecDeque::with_capacity(RING_BUFFER_SIZE))),
125Ôćĺ            sequence: Arc::new(AtomicU64::new(0)),
126Ôćĺ            request_timeout,
127Ôćĺ            shutting_down: AtomicBool::new(false),
128Ôćĺ            spawned_at: spawn_start,
129Ôćĺ            first_stdout: Arc::new(AtomicBool::new(false)),
130Ôćĺ            stderr_tail: Arc::new(Mutex::new(VecDeque::with_capacity(STDERR_TAIL_SIZE))),
131Ôćĺ        };
132Ôćĺ
133Ôćĺ        runtime.spawn_stdout_loop(stdout);
134Ôćĺ        runtime.spawn_stderr_loop(stderr);
135Ôćĺ        runtime.spawn_exit_watcher();
136Ôćĺ
137Ôćĺ        Ok(runtime)
