140Ôćĺ    pub async fn post(&self, payload: Value) -> Result<PostOutcome, AdapterError> {
141Ôćĺ        if !payload.is_object() {
142Ôćĺ            return Err(AdapterError::InvalidEnvelope);
143Ôćĺ        }
144Ôćĺ
145Ôćĺ        let method: String = payload
146Ôćĺ            .get("method")
147Ôćĺ            .and_then(|v| v.as_str())
148Ôćĺ            .unwrap_or("<none>")
149Ôćĺ            .to_string();
150Ôćĺ        let has_method = payload.get("method").is_some();
151Ôćĺ        let id = payload.get("id");
152Ôćĺ
153Ôćĺ        if has_method && id.is_some() {
154Ôćĺ            let id_value = id.expect("checked");
155Ôćĺ            let key = id_key(id_value);
156Ôćĺ            let (tx, rx) = oneshot::channel();
157Ôćĺ
158Ôćĺ            let pending_count = self.pending.lock().await.len();
159Ôćĺ            tracing::info!(
160Ôćĺ                method = %method,
161Ôćĺ                id = %key,
162Ôćĺ                pending_count = pending_count,
163Ôćĺ                "post: request Ôćĺ agent (awaiting response)"
164Ôćĺ            );
165Ôćĺ
166Ôćĺ            self.pending.lock().await.insert(key.clone(), tx);
167Ôćĺ
168Ôćĺ            let write_start = Instant::now();
169Ôćĺ            if let Err(err) = self.send_to_subprocess(&payload).await {
170Ôćĺ                tracing::error!(
171Ôćĺ                    method = %method,
172Ôćĺ                    id = %key,
173Ôćĺ                    error = %err,
174Ôćĺ                    "post: failed to write to agent stdin"
175Ôćĺ                );
176Ôćĺ                self.pending.lock().await.remove(&key);
177Ôćĺ                return Err(err);
178Ôćĺ            }
179Ôćĺ            let write_ms = write_start.elapsed().as_millis() as u64;
180Ôćĺ            tracing::debug!(
181Ôćĺ                method = %method,
182Ôćĺ                id = %key,
183Ôćĺ                write_ms = write_ms,
184Ôćĺ                "post: stdin write complete, waiting for response"
185Ôćĺ            );
186Ôćĺ
187Ôćĺ            let wait_start = Instant::now();
188Ôćĺ            match tokio::time::timeout(self.request_timeout, rx).await {
189Ôćĺ                Ok(Ok(response)) => {
190Ôćĺ                    let wait_ms = wait_start.elapsed().as_millis() as u64;
191Ôćĺ                    tracing::info!(
192Ôćĺ                        method = %method,
193Ôćĺ                        id = %key,
194Ôćĺ                        response_ms = wait_ms,
195Ôćĺ                        total_ms = write_ms + wait_ms,
196Ôćĺ                        "post: got response from agent"
197Ôćĺ                    );
198Ôćĺ                    Ok(PostOutcome::Response(response))
199Ôćĺ                }
200Ôćĺ                Ok(Err(_)) => {
201Ôćĺ                    let wait_ms = wait_start.elapsed().as_millis() as u64;
202Ôćĺ                    tracing::error!(
203Ôćĺ                        method = %method,
204Ôćĺ                        id = %key,
205Ôćĺ                        wait_ms = wait_ms,
206Ôćĺ                        "post: response channel dropped (agent process may have exited)"
207Ôćĺ                    );
208Ôćĺ                    self.pending.lock().await.remove(&key);
209Ôćĺ                    if let Some((exit_code, stderr)) = self.try_process_exit_info().await {
210Ôćĺ                        tracing::error!(
211Ôćĺ                            method = %method,
212Ôćĺ                            id = %key,
213Ôćĺ                            exit_code = ?exit_code,
214Ôćĺ                            stderr = ?stderr,
215Ôćĺ                            "post: agent process exited before response channel completed"
216Ôćĺ                        );
217Ôćĺ                        return Err(AdapterError::Exited { exit_code, stderr });
218Ôćĺ                    }
219Ôćĺ                    Err(AdapterError::Timeout)
220Ôćĺ                }
221Ôćĺ                Err(_) => {
222Ôćĺ                    let pending_keys: Vec<String> =
223Ôćĺ                        self.pending.lock().await.keys().cloned().collect();
224Ôćĺ                    tracing::error!(
225Ôćĺ                        method = %method,
226Ôćĺ                        id = %key,
227Ôćĺ                        timeout_ms = self.request_timeout.as_millis() as u64,
228Ôćĺ                        age_ms = self.spawned_at.elapsed().as_millis() as u64,
229Ôćĺ                        pending_keys = ?pending_keys,
230Ôćĺ                        first_stdout_seen = self.first_stdout.load(Ordering::Relaxed),
231Ôćĺ                        "post: TIMEOUT waiting for agent response"
232Ôćĺ                    );
233Ôćĺ                    self.pending.lock().await.remove(&key);
234Ôćĺ                    if let Some((exit_code, stderr)) = self.try_process_exit_info().await {
235Ôćĺ                        tracing::error!(
236Ôćĺ                            method = %method,
237Ôćĺ                            id = %key,
238Ôćĺ                            exit_code = ?exit_code,
239Ôćĺ                            stderr = ?stderr,
240Ôćĺ                            "post: agent process exited before timeout completed"
241Ôćĺ                        );
242Ôćĺ                        return Err(AdapterError::Exited { exit_code, stderr });
243Ôćĺ                    }
244Ôćĺ                    Err(AdapterError::Timeout)
245Ôćĺ                }
246Ôćĺ            }
247Ôćĺ        } else {
248Ôćĺ            tracing::debug!(
249Ôćĺ                method = %method,
250Ôćĺ                "post: notification Ôćĺ agent (fire-and-forget)"
251Ôćĺ            );
252Ôćĺ            self.send_to_subprocess(&payload).await?;
253Ôćĺ            Ok(PostOutcome::Accepted)
254Ôćĺ        }
255Ôćĺ    }
