257Ôćĺ    async fn subscribe(
258Ôćĺ        &self,
259Ôćĺ        last_event_id: Option<u64>,
260Ôćĺ    ) -> (Vec<(u64, Value)>, broadcast::Receiver<StreamMessage>) {
261Ôćĺ        let replay = {
262Ôćĺ            let ring = self.ring.lock().await;
263Ôćĺ            ring.iter()
264Ôćĺ                .filter(|message| {
265Ôćĺ                    if let Some(last_event_id) = last_event_id {
266Ôćĺ                        message.sequence > last_event_id
267Ôćĺ                    } else {
268Ôćĺ                        true
269Ôćĺ                    }
270Ôćĺ                })
271Ôćĺ                .map(|message| (message.sequence, message.payload.clone()))
272Ôćĺ                .collect::<Vec<_>>()
273Ôćĺ        };
274Ôćĺ        (replay, self.sender.subscribe())
275Ôćĺ    }
