277Ôćĺ    pub async fn sse_stream(
278Ôćĺ        self: Arc<Self>,
279Ôćĺ        last_event_id: Option<u64>,
280Ôćĺ    ) -> impl Stream<Item = Result<Event, Infallible>> + Send + 'static {
281Ôćĺ        let (replay, rx) = self.subscribe(last_event_id).await;
282Ôćĺ        let replay_stream = stream::iter(replay.into_iter().map(|(sequence, payload)| {
283Ôćĺ            let event = Event::default()
284Ôćĺ                .event("message")
285Ôćĺ                .id(sequence.to_string())
286Ôćĺ                .data(payload.to_string());
287Ôćĺ            Ok(event)
288Ôćĺ        }));
289Ôćĺ
290Ôćĺ        let live_stream = BroadcastStream::new(rx).filter_map(|item| async move {
291Ôćĺ            match item {
292Ôćĺ                Ok(message) => {
293Ôćĺ                    let event = Event::default()
294Ôćĺ                        .event("message")
295Ôćĺ                        .id(message.sequence.to_string())
296Ôćĺ                        .data(message.payload.to_string());
297Ôćĺ                    Some(Ok(event))
298Ôćĺ                }
299Ôćĺ                Err(_) => None,
300Ôćĺ            }
301Ôćĺ        });
302Ôćĺ
303Ôćĺ        replay_stream.chain(live_stream)
304Ôćĺ    }
