306Ôćĺ    /// Stream of raw JSON-RPC `Value` payloads (without SSE framing).
307Ôćĺ    /// Useful for consumers that need to inspect the payload contents
308Ôćĺ    /// rather than forward them as SSE events.
309Ôćĺ    pub async fn value_stream(
310Ôćĺ        self: Arc<Self>,
311Ôćĺ        last_event_id: Option<u64>,
312Ôćĺ    ) -> impl Stream<Item = Value> + Send + 'static {
313Ôćĺ        let (replay, rx) = self.subscribe(last_event_id).await;
314Ôćĺ        let replay_stream = stream::iter(replay.into_iter().map(|(_sequence, payload)| payload));
315Ôćĺ        let live_stream = BroadcastStream::new(rx).filter_map(|item| async move {
316Ôćĺ            match item {
317Ôćĺ                Ok(message) => Some(message.payload),
318Ôćĺ                Err(_) => None,
319Ôćĺ            }
320Ôćĺ        });
321Ôćĺ        replay_stream.chain(live_stream)
322Ôćĺ    }
