324Ôćĺ    pub async fn shutdown(&self) {
325Ôćĺ        if self.shutting_down.swap(true, Ordering::SeqCst) {
326Ôćĺ            return;
327Ôćĺ        }
328Ôćĺ
329Ôćĺ        tracing::info!(
330Ôćĺ            age_ms = self.spawned_at.elapsed().as_millis() as u64,
331Ôćĺ            "shutting down agent process"
332Ôćĺ        );
333Ôćĺ
334Ôćĺ        self.pending.lock().await.clear();
335Ôćĺ        let mut child = self.child.lock().await;
336Ôćĺ        match child.try_wait() {
337Ôćĺ            Ok(Some(_)) => {}
338Ôćĺ            Ok(None) => {
339Ôćĺ                let _ = child.kill().await;
340Ôćĺ                let _ = child.wait().await;
341Ôćĺ            }
342Ôćĺ            Err(_) => {
343Ôćĺ                let _ = child.kill().await;
344Ôćĺ            }
345Ôćĺ        }
346Ôćĺ    }
