348Ôćĺ    fn spawn_stdout_loop(&self, stdout: tokio::process::ChildStdout) {
349Ôćĺ        let pending = self.pending.clone();
350Ôćĺ        let sender = self.sender.clone();
351Ôćĺ        let ring = self.ring.clone();
352Ôćĺ        let sequence = self.sequence.clone();
353Ôćĺ        let spawned_at = self.spawned_at;
354Ôćĺ        let first_stdout = self.first_stdout.clone();
355Ôćĺ
356Ôćĺ        tokio::spawn(async move {
357Ôćĺ            let mut lines = BufReader::new(stdout).lines();
358Ôćĺ            let mut line_count: u64 = 0;
359Ôćĺ
360Ôćĺ            while let Ok(Some(line)) = lines.next_line().await {
361Ôćĺ                let trimmed = line.trim();
362Ôćĺ                if trimmed.is_empty() {
363Ôćĺ                    continue;
364Ôćĺ                }
365Ôćĺ
366Ôćĺ                line_count += 1;
367Ôćĺ
368Ôćĺ                if !first_stdout.swap(true, Ordering::Relaxed) {
369Ôćĺ                    tracing::info!(
370Ôćĺ                        first_stdout_ms = spawned_at.elapsed().as_millis() as u64,
371Ôćĺ                        line_bytes = trimmed.len(),
372Ôćĺ                        "agent process: first stdout line received"
373Ôćĺ                    );
374Ôćĺ                }
375Ôćĺ
376Ôćĺ                let payload = match serde_json::from_str::<Value>(trimmed) {
377Ôćĺ                    Ok(payload) => payload,
378Ôćĺ                    Err(err) => {
379Ôćĺ                        tracing::warn!(
380Ôćĺ                            error = %err,
381Ôćĺ                            line_number = line_count,
382Ôćĺ                            raw = %if trimmed.len() > 200 {
383Ôćĺ                                format!("{}...", &trimmed[..200])
384Ôćĺ                            } else {
385Ôćĺ                                trimmed.to_string()
386Ôćĺ                            },
387Ôćĺ                            "agent stdout: invalid JSON"
388Ôćĺ                        );
389Ôćĺ                        json!({
390Ôćĺ                            "jsonrpc": "2.0",
391Ôćĺ                            "method": "_adapter/invalid_stdout",
392Ôćĺ                            "params": {
393Ôćĺ                                "error": err.to_string(),
394Ôćĺ                                "raw": trimmed,
395Ôćĺ                            }
396Ôćĺ                        })
397Ôćĺ                    }
398Ôćĺ                };
399Ôćĺ
400Ôćĺ                let is_response = payload.get("id").is_some() && payload.get("method").is_none();
401Ôćĺ                if is_response {
402Ôćĺ                    let key = id_key(payload.get("id").expect("checked"));
403Ôćĺ                    let has_error = payload.get("error").is_some();
404Ôćĺ                    if let Some(tx) = pending.lock().await.remove(&key) {
405Ôćĺ                        tracing::debug!(
406Ôćĺ                            id = %key,
407Ôćĺ                            has_error = has_error,
408Ôćĺ                            age_ms = spawned_at.elapsed().as_millis() as u64,
409Ôćĺ                            "agent stdout: response matched to pending request"
410Ôćĺ                        );
411Ôćĺ                        let _ = tx.send(payload.clone());
412Ôćĺ                        // Also broadcast the response so SSE/notification subscribers
413Ôćĺ                        // see it in order after preceding notifications. This lets the
414Ôćĺ                        // SSE translation task detect turn completion after all
415Ôćĺ                        // session/update events have been processed.
416Ôćĺ                        let seq = sequence.fetch_add(1, Ordering::SeqCst) + 1;
417Ôćĺ                        let message = StreamMessage {
418Ôćĺ                            sequence: seq,
419Ôćĺ                            payload,
420Ôćĺ                        };
421Ôćĺ                        {
422Ôćĺ                            let mut guard = ring.lock().await;
423Ôćĺ                            guard.push_back(message.clone());
424Ôćĺ                            while guard.len() > RING_BUFFER_SIZE {
425Ôćĺ                                guard.pop_front();
426Ôćĺ                            }
427Ôćĺ                        }
428Ôćĺ                        let _ = sender.send(message);
429Ôćĺ                        continue;
430Ôćĺ                    } else {
431Ôćĺ                        tracing::warn!(
432Ôćĺ                            id = %key,
433Ôćĺ                            has_error = has_error,
434Ôćĺ                            "agent stdout: response has no matching pending request (orphan)"
435Ôćĺ                        );
436Ôćĺ                    }
437Ôćĺ                }
438Ôćĺ
439Ôćĺ                let method = payload
440Ôćĺ                    .get("method")
441Ôćĺ                    .and_then(|v| v.as_str())
442Ôćĺ                    .unwrap_or("<none>");
443Ôćĺ                tracing::debug!(
444Ôćĺ                    method = method,
445Ôćĺ                    line_number = line_count,
446Ôćĺ                    "agent stdout: notification/event Ôćĺ SSE broadcast"
447Ôćĺ                );
448Ôćĺ
449Ôćĺ                let seq = sequence.fetch_add(1, Ordering::SeqCst) + 1;
450Ôćĺ                let message = StreamMessage {
451Ôćĺ                    sequence: seq,
452Ôćĺ                    payload,
453Ôćĺ                };
454Ôćĺ
455Ôćĺ                {
456Ôćĺ                    let mut guard = ring.lock().await;
457Ôćĺ                    guard.push_back(message.clone());
458Ôćĺ                    while guard.len() > RING_BUFFER_SIZE {
459Ôćĺ                        guard.pop_front();
460Ôćĺ                    }
461Ôćĺ                }
462Ôćĺ
463Ôćĺ                let _ = sender.send(message);
464Ôćĺ            }
465Ôćĺ
466Ôćĺ            tracing::info!(
467Ôćĺ                total_lines = line_count,
468Ôćĺ                age_ms = spawned_at.elapsed().as_millis() as u64,
469Ôćĺ                "agent stdout: stream ended"
470Ôćĺ            );
471Ôćĺ        });
472Ôćĺ    }
