507Ôćĺ    fn spawn_exit_watcher(&self) {
508Ôćĺ        let child = self.child.clone();
509Ôćĺ        let sender = self.sender.clone();
510Ôćĺ        let ring = self.ring.clone();
511Ôćĺ        let sequence = self.sequence.clone();
512Ôćĺ        let spawned_at = self.spawned_at;
513Ôćĺ        let pending = self.pending.clone();
514Ôćĺ
515Ôćĺ        tokio::spawn(async move {
516Ôćĺ            let status = {
