519Ôćĺ            };
520Ôćĺ
521Ôćĺ            let age_ms = spawned_at.elapsed().as_millis() as u64;
522Ôćĺ            let pending_count = pending.lock().await.len();
523Ôćĺ
524Ôćĺ            if let Some(status) = status {
525Ôćĺ                tracing::warn!(
526Ôćĺ                    success = status.success(),
527Ôćĺ                    code = status.code(),
528Ôćĺ                    age_ms = age_ms,
529Ôćĺ                    pending_requests = pending_count,
530Ôćĺ                    "agent process exited"
531Ôćĺ                );
532Ôćĺ
533Ôćĺ                let payload = json!({
534Ôćĺ                    "jsonrpc": "2.0",
535Ôćĺ                    "method": "_adapter/agent_exited",
536Ôćĺ                    "params": {
537Ôćĺ                        "success": status.success(),
538Ôćĺ                        "code": status.code(),
539Ôćĺ                    }
540Ôćĺ                });
541Ôćĺ
542Ôćĺ                let seq = sequence.fetch_add(1, Ordering::SeqCst) + 1;
543Ôćĺ                let message = StreamMessage {
544Ôćĺ                    sequence: seq,
545Ôćĺ                    payload,
546Ôćĺ                };
547Ôćĺ
548Ôćĺ                {
549Ôćĺ                    let mut guard = ring.lock().await;
550Ôćĺ                    guard.push_back(message.clone());
551Ôćĺ                    while guard.len() > RING_BUFFER_SIZE {
552Ôćĺ                        guard.pop_front();
553Ôćĺ                    }
554Ôćĺ                }
555Ôćĺ
556Ôćĺ                let _ = sender.send(message);
557Ôćĺ            } else {
558Ôćĺ                tracing::error!(
559Ôćĺ                    age_ms = age_ms,
560Ôćĺ                    pending_requests = pending_count,
561Ôćĺ                    "agent process: failed to get exit status"
562Ôćĺ                );
563Ôćĺ            }
564Ôćĺ        });
565Ôćĺ    }
