567Ôćĺ    async fn send_to_subprocess(&self, payload: &Value) -> Result<(), AdapterError> {
568Ôćĺ        let method = payload
569Ôćĺ            .get("method")
570Ôćĺ            .and_then(|v| v.as_str())
571Ôćĺ            .unwrap_or("<none>");
572Ôćĺ        let id = payload.get("id").map(|v| v.to_string()).unwrap_or_default();
573Ôćĺ
574Ôćĺ        tracing::debug!(
575Ôćĺ            method = method,
576Ôćĺ            id = %id,
577Ôćĺ            bytes = serde_json::to_vec(payload).map(|b| b.len()).unwrap_or(0),
578Ôćĺ            "stdin: writing message to agent"
579Ôćĺ        );
580Ôćĺ
581Ôćĺ        let mut stdin = self.stdin.lock().await;
582Ôćĺ        let bytes = serde_json::to_vec(payload).map_err(AdapterError::Serialize)?;
583Ôćĺ        stdin.write_all(&bytes).await.map_err(|err| {
584Ôćĺ            tracing::error!(method = method, id = %id, error = %err, "stdin: write_all failed");
585Ôćĺ            AdapterError::Write(err)
586Ôćĺ        })?;
587Ôćĺ        stdin.write_all(b"\n").await.map_err(|err| {
588Ôćĺ            tracing::error!(method = method, id = %id, error = %err, "stdin: newline write failed");
589Ôćĺ            AdapterError::Write(err)
590Ôćĺ        })?;
591Ôćĺ        stdin.flush().await.map_err(|err| {
592Ôćĺ            tracing::error!(method = method, id = %id, error = %err, "stdin: flush failed");
593Ôćĺ            AdapterError::Write(err)
594Ôćĺ        })?;
