600Ôćĺ    async fn try_process_exit_info(&self) -> Option<(Option<i32>, Option<String>)> {
601Ôćĺ        let mut child = self.child.lock().await;
602Ôćĺ        match child.try_wait() {
603Ôćĺ            Ok(Some(status)) => {
604Ôćĺ                let exit_code = status.code();
605Ôćĺ                drop(child);
606Ôćĺ                let stderr = self.stderr_tail_summary().await;
607Ôćĺ                Some((exit_code, stderr))
608Ôćĺ            }
609Ôćĺ            Ok(None) => None,
610Ôćĺ            Err(_) => None,
611Ôćĺ        }
612Ôćĺ    }
613Ôćĺ
614Ôćĺ    async fn stderr_tail_summary(&self) -> Option<String> {
615Ôćĺ        let tail = self.stderr_tail.lock().await;
616Ôćĺ        if tail.is_empty() {
617Ôćĺ            return None;
618Ôćĺ        }
619Ôćĺ        Some(tail.iter().cloned().collect::<Vec<_>>().join("\n"))
620Ôćĺ    }
621Ôćĺ}
