141Ôćĺexport interface InMemorySessionPersistDriverOptions {
142Ôćĺ  maxSessions?: number;
143Ôćĺ  maxEventsPerSession?: number;
144Ôćĺ}
145Ôćĺ
146Ôćĺconst DEFAULT_MAX_SESSIONS = 1024;
147Ôćĺconst DEFAULT_MAX_EVENTS_PER_SESSION = 500;
148Ôćĺconst DEFAULT_LIST_LIMIT = 100;
149Ôćĺ
150Ôćĺexport class InMemorySessionPersistDriver implements SessionPersistDriver {
151Ôćĺ  private readonly maxSessions: number;
152Ôćĺ  private readonly maxEventsPerSession: number;
153Ôćĺ  private readonly sessions = new Map<string, SessionRecord>();
154Ôćĺ  private readonly eventsBySession = new Map<string, SessionEvent[]>();
155Ôćĺ
156Ôćĺ  constructor(options: InMemorySessionPersistDriverOptions = {}) {
157Ôćĺ    this.maxSessions = normalizeCap(options.maxSessions, DEFAULT_MAX_SESSIONS);
158Ôćĺ    this.maxEventsPerSession = normalizeCap(options.maxEventsPerSession, DEFAULT_MAX_EVENTS_PER_SESSION);
159Ôćĺ  }
160Ôćĺ
161Ôćĺ  async getSession(id: string): Promise<SessionRecord | null> {
162Ôćĺ    const session = this.sessions.get(id);
163Ôćĺ    return session ? cloneSessionRecord(session) : null;
164Ôćĺ  }
165Ôćĺ
166Ôćĺ  async listSessions(request: ListPageRequest = {}): Promise<ListPage<SessionRecord>> {
167Ôćĺ    const sorted = [...this.sessions.values()].sort((a, b) => {
168Ôćĺ      if (a.createdAt !== b.createdAt) {
169Ôćĺ        return a.createdAt - b.createdAt;
170Ôćĺ      }
171Ôćĺ      return a.id.localeCompare(b.id);
172Ôćĺ    });
173Ôćĺ    const page = paginate(sorted, request);
174Ôćĺ    return {
175Ôćĺ      items: page.items.map(cloneSessionRecord),
176Ôćĺ      nextCursor: page.nextCursor,
177Ôćĺ    };
178Ôćĺ  }
179Ôćĺ
180Ôćĺ  async updateSession(session: SessionRecord): Promise<void> {
181Ôćĺ    this.sessions.set(session.id, { ...session });
182Ôćĺ
183Ôćĺ    if (!this.eventsBySession.has(session.id)) {
184Ôćĺ      this.eventsBySession.set(session.id, []);
185Ôćĺ    }
186Ôćĺ
187Ôćĺ    if (this.sessions.size <= this.maxSessions) {
188Ôćĺ      return;
189Ôćĺ    }
190Ôćĺ
191Ôćĺ    const overflow = this.sessions.size - this.maxSessions;
192Ôćĺ    const removable = [...this.sessions.values()]
193Ôćĺ      .sort((a, b) => {
194Ôćĺ        if (a.createdAt !== b.createdAt) {
195Ôćĺ          return a.createdAt - b.createdAt;
196Ôćĺ        }
197Ôćĺ        return a.id.localeCompare(b.id);
198Ôćĺ      })
199Ôćĺ      .slice(0, overflow)
200Ôćĺ      .map((sessionToRemove) => sessionToRemove.id);
201Ôćĺ
202Ôćĺ    for (const sessionId of removable) {
203Ôćĺ      this.sessions.delete(sessionId);
204Ôćĺ      this.eventsBySession.delete(sessionId);
205Ôćĺ    }
206Ôćĺ  }
207Ôćĺ
208Ôćĺ  async listEvents(request: ListEventsRequest): Promise<ListPage<SessionEvent>> {
209Ôćĺ    const all = [...(this.eventsBySession.get(request.sessionId) ?? [])].sort((a, b) => {
210Ôćĺ      if (a.eventIndex !== b.eventIndex) {
211Ôćĺ        return a.eventIndex - b.eventIndex;
212Ôćĺ      }
213Ôćĺ      return a.id.localeCompare(b.id);
214Ôćĺ    });
215Ôćĺ    const page = paginate(all, request);
216Ôćĺ    return {
217Ôćĺ      items: page.items.map(cloneSessionEvent),
218Ôćĺ      nextCursor: page.nextCursor,
219Ôćĺ    };
220Ôćĺ  }
221Ôćĺ
222Ôćĺ  async insertEvent(event: SessionEvent): Promise<void> {
223Ôćĺ    const events = this.eventsBySession.get(event.sessionId) ?? [];
224Ôćĺ    events.push(cloneSessionEvent(event));
225Ôćĺ
226Ôćĺ    if (events.length > this.maxEventsPerSession) {
227Ôćĺ      events.splice(0, events.length - this.maxEventsPerSession);
228Ôćĺ    }
229Ôćĺ
230Ôćĺ    this.eventsBySession.set(event.sessionId, events);
231Ôćĺ  }
232Ôćĺ}
233Ôćĺ
234Ôćĺfunction cloneSessionRecord(session: SessionRecord): SessionRecord {
235Ôćĺ  return {
236Ôćĺ    ...session,
237Ôćĺ    sessionInit: session.sessionInit ? (JSON.parse(JSON.stringify(session.sessionInit)) as SessionRecord["sessionInit"]) : undefined,
238Ôćĺ    configOptions: session.configOptions ? (JSON.parse(JSON.stringify(session.configOptions)) as SessionRecord["configOptions"]) : undefined,
239Ôćĺ    modes: session.modes ? (JSON.parse(JSON.stringify(session.modes)) as SessionRecord["modes"]) : session.modes,
240Ôćĺ  };
241Ôćĺ}
242Ôćĺ
243Ôćĺfunction cloneSessionEvent(event: SessionEvent): SessionEvent {
244Ôćĺ  return {
245Ôćĺ    ...event,
246Ôćĺ    payload: JSON.parse(JSON.stringify(event.payload)) as AnyMessage,
247Ôćĺ  };
248Ôćĺ}
