250Ôćĺtype ResponsesOf<T> = T extends { responses: infer R } ? R : never;
251Ôćĺtype JsonResponse<T, StatusCode extends keyof ResponsesOf<T>> = ResponsesOf<T>[StatusCode] extends {
252Ôćĺ  content: { "application/json": infer B };
253Ôćĺ}
254Ôćĺ  ? B
255Ôćĺ  : never;
256Ôćĺ
257Ôćĺtype JsonRequestBody<T> = T extends {
258Ôćĺ  requestBody: { content: { "application/json": infer B } };
259Ôćĺ}
260Ôćĺ  ? B
261Ôćĺ  : never;
262Ôćĺ
263Ôćĺtype QueryParams<T> = T extends { parameters: { query: infer Q } } ? Q : T extends { parameters: { query?: infer Q } } ? Q : never;
264Ôćĺ
265Ôćĺfunction normalizeCap(value: number | undefined, fallback: number): number {
266Ôćĺ  if (!Number.isFinite(value) || (value ?? 0) < 1) {
267Ôćĺ    return fallback;
268Ôćĺ  }
269Ôćĺ  return Math.floor(value as number);
270Ôćĺ}
271Ôćĺ
272Ôćĺfunction paginate<T>(items: T[], request: ListPageRequest): ListPage<T> {
273Ôćĺ  const offset = parseCursor(request.cursor);
274Ôćĺ  const limit = normalizeCap(request.limit, DEFAULT_LIST_LIMIT);
275Ôćĺ  const slice = items.slice(offset, offset + limit);
276Ôćĺ  const nextOffset = offset + slice.length;
277Ôćĺ  return {
278Ôćĺ    items: slice,
279Ôćĺ    nextCursor: nextOffset < items.length ? String(nextOffset) : undefined,
280Ôćĺ  };
281Ôćĺ}
282Ôćĺ
283Ôćĺfunction parseCursor(cursor: string | undefined): number {
284Ôćĺ  if (!cursor) {
285Ôćĺ    return 0;
286Ôćĺ  }
287Ôćĺ  const parsed = Number.parseInt(cursor, 10);
288Ôćĺ  if (!Number.isFinite(parsed) || parsed < 0) {
289Ôćĺ    return 0;
290Ôćĺ  }
291Ôćĺ  return parsed;
292Ôćĺ}
