 41Ôćĺ    return apiClient.get<Session>(ENDPOINTS.SESSION_BY_ID(id));
 42Ôćĺ  },
 43Ôćĺ
 44Ôćĺ  /**
 45Ôćĺ   * Fetch messages for a session with optional cursor-based pagination.
