109Ôćĺ    })
110Ôćĺ    .with({ type: "message.tool_result" }, (e) => {
111Ôćĺ      console.log(`[AgentEvent] message.tool_result: session=${e.sessionId} msgId=${e.message.id}`);
112Ôćĺ      const result = persistToolResultMessage(e);
113Ôćĺ      if (result.ok) {
114Ôćĺ        invalidate(
115Ôćĺ          ["messages", "session"] satisfies QueryResource[],
116Ôćĺ          { sessionIds: [e.sessionId] }
117Ôćĺ        );
118Ôćĺ      }
119Ôćĺ    })
120Ôćĺ    .with({ type: "message.result" }, (e) => {
121Ôćĺ      console.log(`[AgentEvent] message.result: session=${e.sessionId} subtype=${e.subtype}`);
122Ôćĺ      // No DB write ÔÇö informational only. Session status handled by session.idle/error.
123Ôćĺ      persistMessageResult(e);
124Ôćĺ    })
125Ôćĺ    .with({ type: "message.cancelled" }, (e) => {
126Ôćĺ      console.log(`[AgentEvent] message.cancelled: session=${e.sessionId}`);
127Ôćĺ      const result = persistMessageCancelled(e);
128Ôćĺ      if (result.ok) {
129Ôćĺ        invalidate(
130Ôćĺ          ["messages", "sessions", "session", "stats"],
131Ôćĺ          { sessionIds: [e.sessionId] }
132Ôćĺ        );
133Ôćĺ      }
134Ôćĺ    })
135Ôćĺ
136Ôćĺ    // ÔöÇÔöÇ Interaction requests ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
137Ôćĺ    .with({ type: "request.opened" }, (e) => {
138Ôćĺ      console.log(`[AgentEvent] request.opened: session=${e.sessionId} requestId=${e.requestId} type=${e.requestType}`);
139Ôćĺ      // No DB write ÔÇö relay to frontend via WS push (future: dedicated event channel)
140Ôćĺ    })
141Ôćĺ    .with({ type: "request.resolved" }, (e) => {
142Ôćĺ      console.log(`[AgentEvent] request.resolved: session=${e.sessionId} requestId=${e.requestId}`);
143Ôćĺ      // No DB write ÔÇö informational
144Ôćĺ    })
145Ôćĺ
146Ôćĺ    // ÔöÇÔöÇ Tool relay ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
147Ôćĺ    .with({ type: "tool.request" }, (e) => {
148Ôćĺ      console.log(`[AgentEvent] tool.request: session=${e.sessionId} method=${e.method} requestId=${e.requestId}`);
149Ôćĺ      // Fire-and-forget: relay to frontend, then send response back to agent-server.
150Ôćĺ      // Errors are logged but don't crash the event handler.
151Ôćĺ      void relayToolRequest(e);
152Ôćĺ    })
153Ôćĺ
154Ôćĺ    // ÔöÇÔöÇ Metadata ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
155Ôćĺ    .with({ type: "agent.session_id" }, (e) => {
156Ôćĺ      console.log(`[AgentEvent] agent.session_id: session=${e.sessionId} agentSessionId=${e.agentSessionId}`);
157Ôćĺ      persistAgentSessionId(e);
158Ôćĺ      // No invalidation needed ÔÇö agent_session_id is not exposed in any query
159Ôćĺ    })
160Ôćĺ
161Ôćĺ    .exhaustive();
162Ôćĺ}
