164Ôćĺ// ---- Tool relay internal ----
165Ôćĺ
166Ôćĺ/**
167Ôćĺ * Relay a tool request to the frontend and send the result back to the agent-server.
168Ôćĺ *
169Ôćĺ * This is async (fire-and-forget from handleAgentEvent). The relay() promise
170Ôćĺ * resolves when the frontend sends q:tool_response, then we forward the result
171Ôćĺ * to the agent via turn/respond.
172Ôćĺ */
173Ôćĺasync function relayToolRequest(event: AgentEvent & { type: "tool.request" }): Promise<void> {
174Ôćĺ  const { sessionId, requestId, method } = event;
175Ôćĺ
176Ôćĺ  if (!respondToAgent) {
177Ôćĺ    console.error(`[AgentEvent] tool.request: no respondToAgent callback registered (requestId=${requestId})`);
178Ôćĺ    return;
179Ôćĺ  }
180Ôćĺ
181Ôćĺ  try {
182Ôćĺ    const result = await relay(event);
183Ôćĺ
184Ôćĺ    // Send the frontend's result back to the agent-server
185Ôćĺ    await respondToAgent({ sessionId, requestId, result });
186Ôćĺ    console.log(`[AgentEvent] tool.request resolved: requestId=${requestId} method=${method}`);
187Ôćĺ  } catch (err) {
188Ôćĺ    console.error(`[AgentEvent] tool.request failed: requestId=${requestId} method=${method}`, err);
189Ôćĺ    // Send an error result back so the agent doesn't hang waiting
190Ôćĺ    try {
191Ôćĺ      await respondToAgent({
192Ôćĺ        sessionId,
193Ôćĺ        requestId,
194Ôćĺ        result: { error: err instanceof Error ? err.message : "Tool relay failed" },
195Ôćĺ      });
196Ôćĺ    } catch (respondErr) {
197Ôćĺ      console.error(`[AgentEvent] Failed to send error response to agent: requestId=${requestId}`, respondErr);
198Ôćĺ    }
199Ôćĺ  }
200Ôćĺ}
