 1Ôćĺ/**
 2Ôćĺ * Parse message content from the database into typed content blocks.
 3Ôćĺ *
 4Ôćĺ * The DB stores content in exactly 3 formats:
 5Ôćĺ *   1. Plain text string (user messages from backend POST)
 6Ôćĺ *   2. JSON.stringify(ContentBlock[]) ÔÇö assistant messages, tool results
 7Ôćĺ *   3. JSON.stringify({ message: { stop_reason }, blocks: ContentBlock[] }) ÔÇö cancelled envelope
 8Ôćĺ *
 9Ôćĺ * Legacy rows may have envelope format for any stop_reason (not just "cancelled").
10Ôćĺ */
11Ôćĺ
12Ôćĺimport type { ContentBlock } from "../types";
13Ôćĺ
14Ôćĺ/**
15Ôćĺ * Parse a raw `content` column value into typed content blocks.
16Ôćĺ *
17Ôćĺ * Returns ContentBlock[] for JSON array or envelope formats,
18Ôćĺ * wraps plain text in [{ type: "text", text }] on parse failure.
19Ôćĺ */
20Ôćĺexport function parseContentBlocks(content: string): (ContentBlock | string)[] | string {
21Ôćĺ  try {
22Ôćĺ    const parsed = JSON.parse(content);
23Ôćĺ
24Ôćĺ    // Format 2: ContentBlock[] (most common ÔÇö assistant messages, tool results)
25Ôćĺ    if (Array.isArray(parsed)) {
26Ôćĺ      return parsed as (ContentBlock | string)[];
27Ôćĺ    }
28Ôćĺ
29Ôćĺ    // Format 3: Envelope ÔÇö { message: { stop_reason }, blocks: [...] }
30Ôćĺ    // Written for cancelled messages; legacy rows may have other stop_reasons.
31Ôćĺ    if (
32Ôćĺ      parsed !== null &&
33Ôćĺ      typeof parsed === "object" &&
34Ôćĺ      "message" in parsed &&
35Ôćĺ      "blocks" in parsed &&
36Ôćĺ      Array.isArray(parsed.blocks)
37Ôćĺ    ) {
38Ôćĺ      return parsed.blocks as (ContentBlock | string)[];
39Ôćĺ    }
40Ôćĺ
41Ôćĺ    // JSON-encoded string (e.g. JSON.stringify("hello") Ôćĺ '"hello"')
42Ôćĺ    if (typeof parsed === "string") {
43Ôćĺ      return parsed;
44Ôćĺ    }
45Ôćĺ
46Ôćĺ    // Unexpected shape ÔÇö wrap as text so it renders safely
47Ôćĺ    return [{ type: "text" as const, text: JSON.stringify(parsed) }];
48Ôćĺ  } catch {
49Ôćĺ    // Format 1: Plain text (not valid JSON) ÔÇö wrap in TextBlock
50Ôćĺ    return [{ type: "text" as const, text: content }];
51Ôćĺ  }
52Ôćĺ}
53Ôćĺ
54Ôćĺ/**
55Ôćĺ * Check if a raw message content string represents a cancelled response.
56Ôćĺ *
57Ôćĺ * The sidecar writes cancelled messages with envelope:
58Ôćĺ *   { message: { stop_reason: "cancelled" }, blocks: [...] }
59Ôćĺ */
60Ôćĺexport function isCancelledMessage(content: string): boolean {
61Ôćĺ  try {
62Ôćĺ    const parsed = JSON.parse(content);
63Ôćĺ    return (
64Ôćĺ      parsed !== null &&
65Ôćĺ      typeof parsed === "object" &&
66Ôćĺ      !Array.isArray(parsed) &&
67Ôćĺ      Array.isArray(parsed.blocks) &&
68Ôćĺ      parsed.message?.stop_reason === "cancelled"
69Ôćĺ    );
70Ôćĺ  } catch {
71Ôćĺ    return false;
72Ôćĺ  }
73Ôćĺ}
