26Ôćĺ}
27Ôćĺ
28Ôćĺ/**
29Ôćĺ * Memoized: block is a parsed JSON object (stable ref), index/role/isStreaming
30Ôćĺ * are primitives. Prevents re-renders of sibling blocks when new content streams in.
31Ôćĺ */
32Ôćĺexport const BlockRenderer = memo(function BlockRenderer({
33Ôćĺ  block,
34Ôćĺ  index,
35Ôćĺ  role,
36Ôćĺ  isStreaming,
37Ôćĺ}: BlockRendererProps) {
38Ôćĺ  const { toolResultMap } = useSession();
39Ôćĺ  // Handle null/undefined blocks gracefully
40Ôćĺ  if (!block) {
41Ôćĺ    if (import.meta.env.DEV) {
42Ôćĺ      console.warn("[BlockRenderer] Received null/undefined block at index:", index);
43Ôćĺ    }
44Ôćĺ    return null;
45Ôćĺ  }
46Ôćĺ
