48Ôćĺ  const weight = isStreaming ? "muted" : "normal";
49Ôćĺ
50Ôćĺ  // Handle string blocks (convert to text block)
51Ôćĺ  if (typeof block === "string") {
52Ôćĺ    return <TextBlock block={{ type: "text", text: block }} role={role} weight={weight} />;
53Ôćĺ  }
54Ôćĺ
55Ôćĺ  // Dispatch based on block type
56Ôćĺ  return match(block)
57Ôćĺ    .with({ type: "text" }, (b) => <TextBlock block={b} role={role} weight={weight} />)
58Ôćĺ    .with({ type: "image" }, (b) => {
59Ôćĺ      // Display-only image in chat (no remove button)
60Ôćĺ      // User: compact 80├Ś80 thumbnails; Assistant: larger inline display
61Ôćĺ      const isUser = role === "user";
62Ôćĺ      return (
63Ôćĺ        <div
64Ôćĺ          className={cn(
65Ôćĺ            "border-border/60 overflow-hidden rounded-lg border",
66Ôćĺ            isUser && "h-[80px] w-[80px] shrink-0"
67Ôćĺ          )}
68Ôćĺ        >
69Ôćĺ          <img
70Ôćĺ            src={`data:${b.source.media_type};base64,${b.source.data}`}
71Ôćĺ            alt="Pasted image"
72Ôćĺ            className={isUser ? "h-full w-full object-cover" : "max-h-64 max-w-full object-contain"}
73Ôćĺ          />
74Ôćĺ        </div>
75Ôćĺ      );
76Ôćĺ    })
77Ôćĺ    .with({ type: "tool_use" }, (b) => (
78Ôćĺ      <ToolUseBlock block={b} toolResult={toolResultMap.get(b.id)} />
79Ôćĺ    ))
80Ôćĺ    .with({ type: "tool_result" }, () => null)
81Ôćĺ    .with({ type: "thinking" }, (b) => <ThinkingBlock block={b} />)
82Ôćĺ    .otherwise((b) => {
83Ôćĺ      if (import.meta.env.DEV) {
84Ôćĺ        console.warn("[BlockRenderer] Unknown block type:", (b as { type?: string }).type, b);
85Ôćĺ      }
86Ôćĺ      return null;
87Ôćĺ    });
88Ôćĺ});
