 13Ôćĺexport async function extractPiSchema(): Promise<NormalizedSchema> {
 14Ôćĺ  console.log("Extracting Pi schema from pi-mono sources...");
 15Ôćĺ
 16Ôćĺ  const tempDir = mkdtempSync(join(tmpdir(), "pi-schema-"));
 17Ôćĺ  try {
 18Ôćĺ    const archivePath = join(tempDir, "pi-mono.tar.gz");
 19Ôćĺ    await downloadToFile(PI_SOURCE_URL, archivePath);
 20Ôćĺ
 21Ôćĺ    execSync(`tar -xzf "${archivePath}" -C "${tempDir}"`, {
 22Ôćĺ      stdio: ["ignore", "ignore", "ignore"],
 23Ôćĺ    });
 24Ôćĺ
 25Ôćĺ    const repoRoot = findRepoRoot(tempDir);
 26Ôćĺ    const rpcTypesPath = join(repoRoot, RPC_TYPES_PATH);
 27Ôćĺ    if (!existsSync(rpcTypesPath)) {
 28Ôćĺ      throw new Error(`rpc-types.ts not found at ${rpcTypesPath}`);
 29Ôćĺ    }
 30Ôćĺ
 31Ôćĺ    const tsconfig = resolveTsconfig(repoRoot);
 32Ôćĺ    const definitions = generateDefinitions(rpcTypesPath, tsconfig);
 33Ôćĺ    if (Object.keys(definitions).length === 0) {
 34Ôćĺ      console.log("  [warn] No schemas extracted from source, using fallback");
 35Ôćĺ      return createFallbackSchema();
 36Ôćĺ    }
 37Ôćĺ
 38Ôćĺ    console.log(`  [ok] Extracted ${Object.keys(definitions).length} types from source`);
 39Ôćĺ    return createNormalizedSchema("pi", "Pi RPC Schema", definitions);
 40Ôćĺ  } catch (error) {
 41Ôćĺ    const errorMessage = error instanceof Error ? error.message : String(error);
 42Ôćĺ    console.log(`  [warn] Pi schema extraction failed: ${errorMessage}`);
 43Ôćĺ    console.log("  [fallback] Using embedded schema definitions");
 44Ôćĺ    return createFallbackSchema();
 45Ôćĺ  } finally {
 46Ôćĺ    rmSync(tempDir, { recursive: true, force: true });
 47Ôćĺ  }
 48Ôćĺ}
