 50Ôćĺasync function downloadToFile(url: string, filePath: string): Promise<void> {
 51Ôćĺ  const response = await fetch(url);
 52Ôćĺ  if (!response.ok) {
 53Ôćĺ    throw new Error(`HTTP ${response.status}: ${response.statusText}`);
 54Ôćĺ  }
 55Ôćĺ  const buffer = Buffer.from(await response.arrayBuffer());
 56Ôćĺ  writeFileSync(filePath, buffer);
 57Ôćĺ}
 58Ôćĺ
 59Ôćĺfunction findRepoRoot(root: string): string {
 60Ôćĺ  const entries = readdirSync(root, { withFileTypes: true }).filter((entry) => entry.isDirectory());
 61Ôćĺ  const repoDir = entries.find((entry) => entry.name.startsWith("pi-mono"));
 62Ôćĺ  if (!repoDir) {
 63Ôćĺ    throw new Error("pi-mono source directory not found after extraction");
 64Ôćĺ  }
 65Ôćĺ  return join(root, repoDir.name);
 66Ôćĺ}
