 68Ôćĺfunction resolveTsconfig(root: string): string | undefined {
 69Ôćĺ  const candidates = [join(root, "tsconfig.json"), join(root, "tsconfig.base.json"), join(root, "packages", "coding-agent", "tsconfig.json")];
 70Ôćĺ  return candidates.find((path) => existsSync(path));
 71Ôćĺ}
