 73Ôćĺfunction generateDefinitions(rpcTypesPath: string, tsconfigPath?: string): Record<string, JSONSchema7> {
 74Ôćĺ  const definitions: Record<string, JSONSchema7> = {};
 75Ôćĺ
 76Ôćĺ  for (const typeName of TARGET_TYPES) {
 77Ôćĺ    const config: Config = {
 78Ôćĺ      path: rpcTypesPath,
 79Ôćĺ      type: typeName,
 80Ôćĺ      expose: "all",
 81Ôćĺ      skipTypeCheck: false,
 82Ôćĺ      topRef: false,
 83Ôćĺ      ...(tsconfigPath ? { tsconfig: tsconfigPath } : {}),
 84Ôćĺ    };
 85Ôćĺ    const schema = createGenerator(config).createSchema(typeName) as JSONSchema7;
 86Ôćĺ    mergeDefinitions(definitions, schema, typeName);
 87Ôćĺ  }
 88Ôćĺ
 89Ôćĺ  return definitions;
 90Ôćĺ}
