 92Ôćĺfunction mergeDefinitions(target: Record<string, JSONSchema7>, schema: JSONSchema7, typeName: string): void {
 93Ôćĺ  if (schema.definitions) {
 94Ôćĺ    for (const [name, def] of Object.entries(schema.definitions)) {
 95Ôćĺ      target[name] = def as JSONSchema7;
 96Ôćĺ    }
 97Ôćĺ  } else if (schema.$defs) {
 98Ôćĺ    for (const [name, def] of Object.entries(schema.$defs)) {
 99Ôćĺ      target[name] = def as JSONSchema7;
100Ôćĺ    }
101Ôćĺ  } else {
102Ôćĺ    target[typeName] = schema;
103Ôćĺ  }
104Ôćĺ
105Ôćĺ  if (!target[typeName]) {
106Ôćĺ    target[typeName] = schema;
107Ôćĺ  }
108Ôćĺ}
