117Ôćĺtype ToolInput = AgentInput | BashInput | FileEditInput | FileReadInput | 
118Ôćĺ                 FileWriteInput | GlobInput | GrepInput | WebFetchInput | 
119Ôćĺ                 WebSearchInput | /* ... 10+ more */;
120Ôćĺ
121Ôćĺinterface BashInput {
122Ôćĺ  command: string;
